                          record.loaiNhanXet === 'Cần cố gắng' ? 'bg-rose-100 text-rose-700' :
                          'text-slate-400 italic'
                        }`}>
                          {record.loaiNhanXet || 'Chờ tạo...'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm font-mono text-slate-400">
                        {record.maNhanXet || 'N/A'}
