                      <td className="px-6 py-4">
                        <textarea 
                          className={`w-full bg-transparent border border-transparent hover:border-slate-200 focus:border-indigo-500 focus:bg-white rounded p-2 text-sm text-slate-600 outline-none transition-all resize-none min-h-[60px] leading-relaxed ${!record.noiDung && 'italic text-slate-300'}`}
                          value={record.noiDung}
                          onChange={(e) => {
                            const newRecords = [...records];
                            newRecords[index].noiDung = e.target.value;
                            setRecords(newRecords);
                          }}
