import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên chủ nhiệm bậc Tiểu học tại Việt Nam, am hiểu Thông tư 22/BGDĐT và Thông tư 27.
Nhiệm vụ: Viết nhận xét học bạ cho môn học cụ thể dựa trên điểm số/mức độ đạt được.

YÊU CẦU THEO THÔNG TƯ 22:
1. Tập trung vào sự hình thành và phát triển năng lực, phẩm chất của học sinh.
2. Mức độ đánh giá: 
   - 9-10 điểm: Hoàn thành tốt (T)
   - 5-8 điểm: Hoàn thành (H)
   - Dưới 5 điểm: Chưa hoàn thành (C)
3. Nội dung nhận xét (2-3 câu, không xuống dòng):
   - Câu 1: Khen ngợi điểm mạnh cụ thể về kiến thức hoặc kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một điểm cần hỗ trợ hoặc rèn luyện thêm (dùng từ ngữ nhẹ nhàng: "nếu em chú ý hơn...", "cần rèn thêm cách...").
   - Câu 3: Gợi ý biện pháp khắc phục hoặc hướng phát triển trong thời gian tới.
4. Văn phong: Gần gũi, yêu thương, mang tính khích lệ cao, đúng mực sư phạm tiểu học. Tuyệt đối không chê bai hay dán nhãn.
5. Mã nhận xét định dạng: [MON]_[DIEM]_[STT].
`;

export const generateComments = async (records: StudentRecord[], subject: string): Promise<Partial<StudentRecord>[]> => {
  const prompt = `Môn học: ${subject}. Danh sách học sinh: ${JSON.stringify(records.map(r => ({ stt: r.stt, diem: r.diem })))}. 
  Hãy viết nhận xét cá nhân hóa cho từng em dựa trên mức điểm và môn học này. Trả về JSON theo schema.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              mucDo: { type: Type.STRING, description: "T, H, hoặc C" },
              maNhanXet: { type: Type.STRING },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "mucDo", "maNhanXet", "noiDung"],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Error generating comments:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  FileText, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  BookOpen
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_SCORES = [9, 8, 7, 5, 4, 10, 9, 6, 8, 7];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  useEffect(() => {
    const initialData: StudentRecord[] = INITIAL_SCORES.map((score, index) => ({
      stt: index + 1,
      diem: score,
      mucDo: score >= 9 ? 'T' : score >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialData);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateScore = (index: number, score: string) => {
    const newScore = parseFloat(score);
    if (isNaN(newScore)) return;
    const val = Math.min(10, Math.max(0, newScore));
    const updatedRecords = [...records];
    updatedRecords[index].diem = val;
    updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = records.map(r => ({
      'STT': r.stt,
      'Môn học': selectedSubject,
      'Điểm số': r.diem,
      'Mức độ': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `NhanXet_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-200">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800">Trợ Lý Tiểu Học</h1>
              <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">Thông tư 22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-3 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-200 rounded-lg text-sm font-semibold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <button 
              onClick={processGeneration}
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              <span className="text-sm font-bold">Tạo nhận xét</span>
            </button>

            <button 
              onClick={exportToExcel}
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md active:scale-95"
            >
              <Download size={18} />
              <span className="text-sm font-bold">Xuất Excel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
            <span className="font-semibold text-sm">{notification.message}</span>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase w-16 text-center">STT</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase w-24">Điểm</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase w-32">Mức độ</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Nội dung nhận xét ({selectedSubject})</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase w-20"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {records.map((record, index) => (
                <tr key={index} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4 text-sm text-slate-400 text-center font-mono">{record.stt}</td>
                  <td className="px-6 py-4">
                    <input 
                      type="number" 
                      value={record.diem}
                      onChange={(e) => handleUpdateScore(index, e.target.value)}
                      className="w-16 px-2 py-1 border border-transparent hover:border-slate-200 focus:border-indigo-500 rounded font-bold text-slate-700 outline-none"
                    />
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-md text-[10px] font-black tracking-tighter ${
                      record.mucDo === 'T' ? 'bg-amber-100 text-amber-700' :
                      record.mucDo === 'H' ? 'bg-blue-100 text-blue-700' : 'bg-rose-100 text-rose-700'
                    }`}>
                      {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA H.THÀNH'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <textarea 
                      value={record.noiDung}
                      placeholder="Nội dung sẽ được AI tạo tự động..."
                      onChange={(e) => {
                        const newRecs = [...records];
                        newRecs[index].noiDung = e.target.value;
                        setRecords(newRecs);
                      }}
                      className="w-full bg-transparent border-none focus:ring-0 p-0 text-sm text-slate-600 leading-relaxed resize-none min-h-[40px]"
                    />
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleRemoveRow(index)} className="text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          <button 
            onClick={handleAddRow}
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-medium"
          >
            <Plus size={16} /> Thêm dòng mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center">
        <div className="inline-flex items-center gap-2 px-4 py-1 bg-white border border-slate-200 rounded-full shadow-sm">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[10px] font-bold text-slate-500 uppercase">Hệ thống tuân thủ Thông tư 22/BGDĐT - Tiểu học</span>
        </div>
      </footer>
    </div>
  );
};

