Bạn là giáo viên chủ nhiệm bậc Tiểu học tại Việt Nam, am hiểu Thông tư 22/BGDĐT và Thông tư 27.
Nhiệm vụ: Viết nhận xét học bạ cho môn học cụ thể dựa trên điểm số/mức độ đạt được.

YÊU CẦU THEO THÔNG TƯ 22:
1. Tập trung vào sự hình thành và phát triển năng lực, phẩm chất của học sinh.
2. Mức độ đánh giá: 
   - 9-10 điểm: Hoàn thành tốt (T)
   - 5-8 điểm: Hoàn thành (H)
   - Dưới 5 điểm: Chưa hoàn thành (C)
3. Nội dung nhận xét (2-3 câu, không xuống dòng):
   - Câu 1: Khen ngợi điểm mạnh cụ thể về kiến thức hoặc kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một điểm cần hỗ trợ hoặc rèn luyện thêm (dùng từ ngữ nhẹ nhàng, không dán nhãn tiêu cực).
   - Câu 3: Gợi ý một hành động cụ thể để tiến bộ hơn.
4. Văn phong: Gần gũi, yêu thương, mang tính khích lệ cao, đúng mực sư phạm tiểu học Việt Nam.
5. Mã nhận xét: Bạn chỉ cần trả về nội dung nhận xét và mức độ (T/H/C), hệ thống sẽ tự tính toán mã số nhảy.
`;

export const generateComments = async (records: StudentRecord[], subject: string): Promise<Partial<StudentRecord>[]> => {
  const prompt = `Môn học: ${subject}. Danh sách học sinh có điểm: ${JSON.stringify(records.map(r => ({ stt: r.stt, diem: r.diem })))}. 
  Hãy viết nhận xét cá nhân hóa cho từng em. Trả về JSON theo schema.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              mucDo: { type: Type.STRING, description: "T, H, hoặc C" },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "mucDo", "noiDung"],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Error generating comments:", error);
    throw error;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  FileText, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  BookOpen
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_SCORES = [9, 8, 7, 5, 4, 10, 9, 6, 8, 7];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  // Helper to calculate codes for all records
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialData: StudentRecord[] = INITIAL_SCORES.map((score, index) => ({
      stt: index + 1,
      diem: score,
      mucDo: score >= 9 ? 'T' : score >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialData);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateScore = (index: number, score: string) => {
    const newScore = parseFloat(score);
    if (isNaN(newScore)) return;
    const val = Math.min(10, Math.max(0, newScore));
    const updatedRecords = [...records];
    updatedRecords[index].diem = val;
    updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Môn học': selectedSubject,
      'Điểm số': r.diem,
      'Mức độ': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `NhanXet_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-200">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase">Trợ Lý Tiểu Học</h1>
              <p className="text-xs text-slate-900 font-medium uppercase tracking-wider">Thông tư 22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-3 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <button 
              onClick={processGeneration}
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              <span className="text-sm font-bold">Tạo nhận xét</span>
            </button>

            <button 
              onClick={exportToExcel}
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md active:scale-95"
            >
              <Download size={18} />
              <span className="text-sm font-bold">Xuất Excel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2 border ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-black uppercase w-16 text-center">STT</th>
                <th className="px-6 py-4 text-xs font-black text-black uppercase w-24">Điểm</th>
                <th className="px-6 py-4 text-xs font-black text-black uppercase w-32">Mức độ</th>
                <th className="px-6 py-4 text-xs font-black text-black uppercase w-32">Mã nhận xét</th>
                <th className="px-6 py-4 text-xs font-black text-black uppercase">Nội dung nhận xét ({selectedSubject})</th>
                <th className="px-6 py-4 text-xs font-black text-black uppercase w-16 text-center"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {calculatedRecords.map((record, index) => (
                <tr key={index} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4 text-sm text-black text-center font-bold">{record.stt}</td>
                  <td className="px-6 py-4">
                    <input 
                      type="number" 
                      value={record.diem}
                      onChange={(e) => handleUpdateScore(index, e.target.value)}
                      className="w-16 px-2 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black outline-none bg-transparent focus:bg-white"
                    />
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-md text-[11px] font-black tracking-tighter inline-block text-center w-full ${
                      record.mucDo === 'T' ? 'bg-amber-100 text-amber-900' :
                      record.mucDo === 'H' ? 'bg-blue-100 text-blue-900' : 'bg-rose-100 text-rose-900'
                    }`}>
                      {record.mucDo === 'T' ? 'H.THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA H.THÀNH'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-xs font-black font-mono px-2 py-1 bg-slate-100 rounded text-black">
                      {record.maNhanXet}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <textarea 
                      value={record.noiDung}
                      placeholder="Nội dung sẽ được AI tạo tự động..."
                      onChange={(e) => {
                        const newRecs = [...records];
                        newRecs[index].noiDung = e.target.value;
                        setRecords(newRecs);
                      }}
                      className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded-md p-2 text-sm text-black font-medium leading-relaxed resize-none min-h-[50px] placeholder:text-slate-300"
                    />
                  </td>
                  <td className="px-6 py-4 text-center">
                    <button onClick={() => handleRemoveRow(index)} className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1">
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          <button 
            onClick={handleAddRow}
            className="w-full py-5 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm dòng mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-10">
        <div className="inline-flex items-center gap-3 px-6 py-2 bg-white border border-slate-200 rounded-full shadow-sm">
          <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-sm shadow-emerald-200"></div>
          <span className="text-[11px] font-black text-black uppercase tracking-wider">Thông tư 22/BGDĐT - Dữ liệu bảng được bảo lưu</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface StudentRecord {
  stt: number;
  hoTen: string;
  diem: number;
  mucDo: string; // T: Hoàn thành tốt, H: Hoàn thành, C: Chưa hoàn thành
  maNhanXet: string;
  noiDung: string;
  isProcessing?: boolean;
}

export const MON_HOC_TIEU_HOC = [
  "Tiếng Việt",
  "Toán",
  "Tiếng Anh",
  "Đạo đức",
  "Tự nhiên và Xã hội",
  "Lịch sử và Địa lý",
  "Khoa học",
  "Tin học",
  "Công nghệ",
  "Giáo dục thể chất",
  "Nghệ thuật (Âm nhạc)",
  "Nghệ thuật (Mỹ thuật)",
  "Hoạt động trải nghiệm"
];

export const getSubjectAbbr = (subject: string): string => {
  const mapping: Record<string, string> = {
    "Tiếng Việt": "TV",
    "Toán": "T",
    "Tiếng Anh": "TA",
    "Đạo đức": "DD",
    "Tự nhiên và Xã hội": "TNXH",
    "Lịch sử và Địa lý": "LSDL",
    "Khoa học": "KH",
    "Tin học": "TH",
    "Công nghệ": "CN",
    "Giáo dục thể chất": "GDTC",
    "Nghệ thuật (Âm nhạc)": "AN",
    "Nghệ thuật (Mỹ thuật)": "MT",
    "Hoạt động trải nghiệm": "HDTN"
  };
  return mapping[subject] || "MH";
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  FileText, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  BookOpen,
  User
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to calculate codes for all records based on level sequence
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      stt: item.stt,
      hoTen: item.hoTen,
      diem: item.diem,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

      // Assuming columns: STT, HoTen, Diem (Index 0, 1, 2)
      // We skip the first row (header)
      const newRecords: StudentRecord[] = data.slice(1)
        .filter(row => row.length >= 2) // Basic validation
        .map((row, idx) => {
          const score = parseFloat(row[2]) || 0;
          return {
            stt: parseInt(row[0]) || idx + 1,
            hoTen: row[1]?.toString() || "Chưa có tên",
            diem: score,
            mucDo: score >= 9 ? 'T' : score >= 5 ? 'H' : 'C',
            maNhanXet: '',
            noiDung: '',
          };
        });

      if (newRecords.length > 0) {
        setRecords(newRecords);
        setNotification({ type: 'success', message: `Đã tải lên ${newRecords.length} học sinh!` });
      }
    };
    reader.readAsBinaryString(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Môn học': selectedSubject,
      'Điểm số': r.diem,
      'Mức độ': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `NhanXet_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-200">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học</h1>
              <p className="text-[10px] text-slate-900 font-black uppercase tracking-widest">Circular 22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
