};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  FileText, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  BookOpen,
  User
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to calculate codes for all records based on level sequence
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      stt: item.stt,
      hoTen: item.hoTen,
      diem: item.diem,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to array of arrays to find headers
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        // Identification keywords
        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'diem so', 'grade']
        };

        let sttIdx = -1, nameIdx = -1, scoreIdx = -1;
        let headerRowIdx = 0;

        // Scan first 10 rows to find header
        for (let i = 0; i < Math.min(data.length, 10); i++) {
          const row = data[i];
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
            if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
            if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
          });
          if (nameIdx !== -1 || scoreIdx !== -1) {
            headerRowIdx = i;
            break;
          }
        }

        // Fallback if not found by keywords
        if (nameIdx === -1) nameIdx = sttIdx === 0 ? 1 : 0;
        if (scoreIdx === -1) scoreIdx = Math.max(nameIdx, sttIdx) + 1;

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined)
          .map((row, idx) => {
            const scoreVal = row[scoreIdx];
            const score = typeof scoreVal === 'number' ? scoreVal : parseFloat(String(scoreVal || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh mới").trim(),
              diem: validScore,
              mucDo: validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C',
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Đã tự động nhận diện và tải lên ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh trong file.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi khi đọc file Excel. Hãy kiểm tra lại định dạng.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Môn học': selectedSubject,
      'Điểm số': r.diem,
      'Mức độ': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `NhanXet_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-200">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học</h1>
              <p className="text-[10px] text-slate-900 font-black uppercase tracking-widest">Circular 22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
            />

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm active:scale-95 text-sm font-bold"
              title="Tải file Excel (Tự động nhận diện cột Tên và Điểm)"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>

            <button 
              onClick={processGeneration}
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>

            <button 
              onClick={exportToExcel}
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md active:scale-95 text-sm font-bold"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2 border ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto text-slate-400 p-1 hover:text-black">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-12 text-center">STT</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase min-w-[200px]">Họ và tên</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-20 text-center">Điểm</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-32 text-center">Mức độ</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-24 text-center">Mã NX</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase">Nội dung nhận xét ({selectedSubject})</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-12"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={7} className="px-6 py-12 text-center text-slate-400 italic text-sm">
                      Chưa có dữ liệu. Hãy thêm dòng mới hoặc tải file Excel.
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-4 py-4 text-sm text-black text-center font-bold">{record.stt}</td>
                      <td className="px-4 py-4">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.hoTen}
                            onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)}
                            placeholder="Nhập tên học sinh..."
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-sm font-bold text-black outline-none placeholder:text-slate-200 placeholder:font-normal"
                          />
                        </div>
                      </td>
                      <td className="px-4 py-4">
                        <input 
                          type="number" 
                          step="0.1"
                          value={record.diem}
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)}
                          className="w-16 px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent focus:bg-white transition-all"
                        />
                      </td>
                      <td className="px-4 py-4">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black tracking-tighter inline-block text-center w-full shadow-sm ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-900 border border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-900 border border-blue-200' : 'bg-rose-100 text-rose-900 border border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'H.THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA H.THÀNH'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-black font-mono px-1.5 py-0.5 bg-slate-100 border border-slate-200 rounded text-slate-600">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-4 py-4">
                        <textarea 
                          value={record.noiDung}
                          placeholder="Nội dung sẽ được AI tạo..."
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)}
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded-md p-1.5 text-sm text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
