  FileText, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  BookOpen,
  User
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to calculate codes for all records based on level sequence
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      stt: item.stt,
      hoTen: item.hoTen,
      diem: item.diem,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to array of arrays to find headers
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        // Identification keywords
        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'diem so', 'grade', 'điểm ktđk', 'ktđk']
        };

        let sttIdx = -1, nameIdx = -1, scoreIdx = -1;
        let headerRowIdx = -1;

        // Scan rows to find the most likely header row
        for (let i = 0; i < Math.min(data.length, 20); i++) {
          const row = data[i];
          let foundCount = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) { sttIdx = idx; foundCount++; }
            if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) { nameIdx = idx; foundCount++; }
            if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) { scoreIdx = idx; foundCount++; }
          });
          if (foundCount >= 2) {
            headerRowIdx = i;
            break;
          }
        }

        // Fallback if not found by keywords
        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = sttIdx === 0 ? 1 : 0;
        if (scoreIdx === -1) scoreIdx = Math.max(nameIdx, sttIdx) + 1;

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreVal = row[scoreIdx];
            const score = typeof scoreVal === 'number' ? scoreVal : parseFloat(String(scoreVal || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              diem: validScore,
              mucDo: validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C',
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Đã tự động nhận diện và tải lên ${newRecords.length} học sinh với dữ liệu chính xác!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ trong file.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi khi đọc file Excel. Hãy kiểm tra lại định dạng.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Môn học': selectedSubject,
      'Điểm KTĐK': r.diem,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `HocBa_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-200">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học</h1>
              <p className="text-[10px] text-slate-900 font-black uppercase tracking-widest">Circular 22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
            />

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm active:scale-95 text-sm font-bold"
              title="Tải file Excel (Tự động nhận diện cột Tên và Điểm)"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>

            <button 
              onClick={processGeneration}
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>

            <button 
              onClick={exportToExcel}
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md active:scale-95 text-sm font-bold"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
