                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-12 text-center">STT</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase min-w-[200px]">Họ và tên</th>
                  <th className="px-4 py-4 text-[10px] font-black text-slate-500 uppercase w-24 text-center">Điểm KTĐK</th>
