                        <span className="text-[10px] font-black font-mono px-1.5 py-0.5 bg-slate-100 border border-slate-200 rounded text-slate-600">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-4 py-4">
                        <textarea 
                          value={record.noiDung}
                          placeholder="Nội dung sẽ được AI tạo..."
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)}
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded-md p-1.5 text-sm text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200"
