            const val = String(cell || '').toLowerCase().trim();
            if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) { sttIdx = idx; foundInRow++; }
            if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) { nameIdx = idx; foundInRow++; }
            if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) { scoreIdx = idx; foundInRow++; }
            if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) { levelIdx = idx; foundInRow++; }
          });
          if (foundInRow >= 2) {
            headerRowIdx = i;
            break;
          }
        }

        // Default indices if not detected
        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = sttIdx === 0 ? 1 : 0;
        if (scoreIdx === -1) scoreIdx = Math.max(nameIdx, sttIdx) + 1;

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't') return 'T';
          if (v.includes('chưa') || v === 'c') return 'C';
          if (v.includes('hoàn thành') || v === 'h') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreVal = row[scoreIdx];
            const score = typeof scoreVal === 'number' ? scoreVal : parseFloat(String(scoreVal || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            // Try to get level from file, if not calculate it
            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) {
              mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';
            }

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Đã tự động nhận diện và tải lên ${newRecords.length} học sinh với dữ liệu chính xác 100%!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ trong file.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi khi đọc file Excel. Vui lòng kiểm tra lại cấu trúc file.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Môn học': selectedSubject,
      'Điểm KTĐK': r.diem,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `HocBa_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg shadow-indigo-200">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học</h1>
              <p className="text-[10px] text-slate-900 font-black uppercase tracking-widest">Circular 22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
            />

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm active:scale-95 text-sm font-bold"
              title="Tải file Excel (Tự động nhận diện Tên, Điểm, Mức đạt được)"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>

            <button 
              onClick={processGeneration}
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>

            <button 
              onClick={exportToExcel}
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md active:scale-95 text-sm font-bold"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2 border ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto text-slate-400 p-1 hover:text-black font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-200 text-black font-bold">
                <tr>
                  <th className="px-4 py-4 text-[10px] uppercase w-12 text-center">STT</th>
                  <th className="px-4 py-4 text-[10px] uppercase min-w-[200px]">Họ và tên</th>
                  <th className="px-4 py-4 text-[10px] uppercase w-28 text-center">Điểm KTĐK</th>
                  <th className="px-4 py-4 text-[10px] uppercase w-36 text-center">Mức đạt được</th>
                  <th className="px-4 py-4 text-[10px] uppercase w-24 text-center">Mã NX</th>
                  <th className="px-4 py-4 text-[10px] uppercase">Nội dung nhận xét ({selectedSubject})</th>
                  <th className="px-4 py-4 text-[10px] uppercase w-12 text-center"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 text-black">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={7} className="px-6 py-12 text-center text-slate-500 italic text-sm">
                      Chưa có dữ liệu. Hãy thêm mới hoặc tải file Excel.
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-4 py-4 text-sm text-center font-bold">{record.stt}</td>
                      <td className="px-4 py-4">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-400 shrink-0" />
                          <input 
                            type="text" 
                            value={record.hoTen}
                            onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)}
                            placeholder="Nhập tên học sinh..."
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-sm font-bold text-black outline-none placeholder:text-slate-300 placeholder:font-normal"
                          />
                        </div>
                      </td>
                      <td className="px-4 py-4">
                        <input 
                          type="number" 
                          step="0.1"
                          value={record.diem}
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)}
                          className="w-full px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent focus:bg-white transition-all"
                        />
                      </td>
                      <td className="px-4 py-4">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black tracking-tighter inline-block text-center w-full shadow-sm border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-black font-mono px-1.5 py-0.5 bg-slate-100 border border-slate-200 rounded text-slate-700">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-4 py-4">
                        <textarea 
                          value={record.noiDung}
                          placeholder="Nội dung sẽ được AI tạo..."
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)}
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded-md p-1.5 text-sm text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-300"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button onClick={() => handleRemoveRow(index)} className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1">
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          <button 
            onClick={handleAddRow}
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-10">
        <div className="inline-flex items-center gap-3 px-6 py-2 bg-white border border-slate-200 rounded-full shadow-sm">
          <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-sm shadow-emerald-200"></div>
          <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest leading-none">Tuân thủ Thông tư 22/BGDĐT - Tự động nhận diện Họ tên, Điểm KTĐK, Mức đạt được</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface StudentRecord {
  stt: number;
  hoTen: string;
  ngaySinh: string;
  diem: number;
  mucDo: string; // T: Hoàn thành tốt, H: Hoàn thành, C: Chưa hoàn thành
  maNhanXet: string;
  noiDung: string;
  isProcessing?: boolean;
}

export const MON_HOC_TIEU_HOC = [
  "Tiếng Việt",
  "Toán",
  "Tiếng Anh",
  "Đạo đức",
  "Tự nhiên và Xã hội",
  "Lịch sử và Địa lý",
  "Khoa học",
  "Tin học",
  "Công nghệ",
  "Giáo dục thể chất",
  "Nghệ thuật (Âm nhạc)",
  "Nghệ thuật (Mỹ thuật)",
  "Hoạt động trải nghiệm"
];

export const getSubjectAbbr = (subject: string): string => {
  const mapping: Record<string, string> = {
    "Tiếng Việt": "TV",
    "Toán": "T",
    "Tiếng Anh": "TA",
    "Đạo đức": "DD",
    "Tự nhiên và Xã hội": "TNXH",
    "Lịch sử và Địa lý": "LSDL",
    "Khoa học": "KH",
    "Tin học": "TH",
    "Công nghệ": "CN",
    "Giáo dục thể chất": "GDTC",
    "Nghệ thuật (Âm nhạc)": "AN",
    "Nghệ thuật (Mỹ thuật)": "MT",
    "Hoạt động trải nghiệm": "HDTN"
  };
  return mapping[subject] || "MH";
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'name', 'họ và tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 25); i++) {
          const row = data[i];
          let foundInRow = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) { sttIdx = idx; foundInRow++; }
            if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) { nameIdx = idx; foundInRow++; }
            if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) { birthIdx = idx; foundInRow++; }
            if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) { scoreIdx = idx; foundInRow++; }
            if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) { levelIdx = idx; foundInRow++; }
          });
          if (foundInRow >= 2) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = 4;

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't') return 'T';
          if (v.includes('chưa') || v === 'c') return 'C';
          if (v.includes('hoàn thành') || v === 'h') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreVal = row[scoreIdx];
            const score = typeof scoreVal === 'number' ? scoreVal : parseFloat(String(scoreVal || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: birthIdx !== -1 ? String(row[birthIdx] || '') : '',
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Tải lên thành công ${newRecords.length} học sinh!` });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi khi đọc file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã tạo nhận xét cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "NhanXet");
    XLSX.writeFile(workbook, `BangDanhGia_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học - Nấm Dẩn</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight"> Circular 22/BGDĐT - Học bạ điện tử</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold">
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button onClick={processGeneration} disabled={isGenerating || records.length === 0} className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold">
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button onClick={exportToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold">
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex justify-between items-end">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight">ĐÁNH GIÁ ĐỊNH KỲ MÔN {selectedSubject.toUpperCase()}</h2>
            <p className="text-sm font-bold">LỚP: - NĂM HỌC: 2025-2026</p>
          </div>
          <div className="text-right">
             <div className="text-[10px] font-bold text-slate-500 uppercase">Trường PTDTBT Tiểu học Nấm Dẩn</div>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse border border-slate-300">
              <thead className="bg-slate-50 text-black font-bold uppercase text-[10px] text-center">
                <tr>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-12">STT</th>
                  <th rowSpan={2} className="px-4 py-3 border border-slate-300 min-w-[180px]">Họ và tên</th>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-28">Ngày sinh</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-24">Mức đạt được</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-20">Điểm KTĐK</th>
                  <th colSpan={2} className="px-4 py-2 border border-slate-300 bg-slate-100">Nhận xét điểm mạnh và các mặt</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-12"></th>
                </tr>
                <tr className="bg-slate-50">
                  <th className="px-3 py-2 border border-slate-300 w-20">Mã nhận xét</th>
                  <th className="px-4 py-2 border border-slate-300">Nội dung</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-slate-400 italic text-sm">Trống. Vui lòng thêm học sinh hoặc tải file.</td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-2 py-3 text-sm text-center font-bold border-x border-slate-200">{record.stt}</td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-300 shrink-0" />
                          <input type="text" value={record.hoTen} onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)} placeholder="Tên học sinh" className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm font-bold text-black outline-none" />
                        </div>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <Calendar size={12} className="text-slate-300 shrink-0" />
                          <input type="text" value={record.ngaySinh} onChange={(e) => handleUpdateField(index, 'ngaySinh', e.target.value)} placeholder="dd/mm/yyyy" className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm text-black outline-none text-center" />
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black inline-block text-center w-full shadow-sm border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <input type="number" step="0.1" value={record.diem} onChange={(e) => handleUpdateField(index, 'diem', e.target.value)} className="w-full px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent" />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <span className="text-[10px] font-bold font-mono px-1.5 py-1 bg-slate-100 rounded text-slate-700">{record.maNhanXet}</span>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <textarea value={record.noiDung} placeholder="AI sẽ viết..." onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px]" />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <button onClick={() => handleRemoveRow(index)} className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button onClick={handleAddRow} className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"><Plus size={18} /> Thêm học sinh</button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-10">
        <div className="flex flex-col items-center gap-2">
           <div className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Người lập biểu</div>
           <div className="italic text-[10px] text-slate-400">(Ký và ghi rõ họ tên)</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        // Load with cellDates true to handle Excel date objects
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to 2D array for precise header analysis
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        // Smart scan to find the actual header row (look for most matches)
        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            // Map exact indices for this row
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        // Final fallback heuristics if keyword search failed
        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            // Format level
            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            // Format Date (Handle strings or Excel date formats)
            let rawBirth = row[birthIdx] || '';
            let formattedBirth = String(rawBirth);

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth.trim(),
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Dữ liệu được xác định và tải lên chính xác: ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không thể xác định dữ liệu học sinh trong file.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel. Hãy đảm bảo file có tiêu đề rõ ràng.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét tự động cho môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học - Nấm Dẩn</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Circular 22/BGDĐT - Chế độ bảo toàn dữ liệu</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
                <Plus size={14} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95"
              title="Tải lên file Excel có tiêu đề Họ tên, Ngày sinh, Điểm..."
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button 
              onClick={exportToExcel} 
