3. Nội dung nhận xét (2-3 câu, không xuống dòng, gộp thành 1 đoạn văn):
   - Câu 1: Khen ngợi điểm mạnh cụ thể về kiến thức hoặc kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một điểm cần hỗ trợ hoặc rèn luyện thêm.
   - Câu 3: Gợi ý một hành động cụ thể để tiến bộ hơn.
4. Văn phong: Gần gũi, yêu thương, mang tính khích lệ cao, đúng mực sư phạm tiểu học Việt Nam.
5. Cấm tuyệt đối: 
   - Không dùng từ dán nhãn tiêu cực (lười, hư, chậm chạp, vô ý thức, yếu, kém).
   - Không phán xét tính cách.
   - Thay bằng: "cần cố gắng hơn", "nên tập trung hơn", "phát huy khả năng", "rèn luyện thêm".
6. Phù hợp lứa tuổi: Ngôn từ phải phù hợp với KHỐI LỚP đã chọn (ví dụ Khối 1 dùng từ đơn giản, Khối 5 dùng từ ngữ chuẩn mực hơn).
`;

export const generateComments = async (records: StudentRecord[], subject: string, gradeLevel: string): Promise<Partial<StudentRecord>[]> => {
  const prompt = `Khối lớp: ${gradeLevel}. 
  Môn học: ${subject}. 
  Danh sách học sinh có điểm: ${JSON.stringify(records.map(r => ({ stt: r.stt, hoTen: r.hoTen, diem: r.diem })))}. 
  Hãy viết nhận xét cá nhân hóa, tích cực cho từng em. Trả về JSON theo schema.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              mucDo: { type: Type.STRING, description: "T, H, hoặc C" },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "mucDo", "noiDung"],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Error generating comments:", error);
    throw error;
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            let formattedBirth = String(row[birthIdx] || '').trim();

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth,
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét cho ${selectedGrade} - Môn ${selectedSubject}!` });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
