    );
  }

  // Màn hình Chào mừng và yêu cầu API Key
  if (isKeySelected === false) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-xl w-full bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="bg-indigo-600 p-8 text-white text-center">
            <div className="inline-flex p-4 bg-white/20 rounded-2xl mb-4 backdrop-blur-sm">
