                        <textarea 
                          value={record.noiDung} 
                          placeholder="AI sẽ tự động viết nhận xét tích cực..." 
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <button 
                          onClick={() => handleRemoveRow(index)} 
                          className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">Người lập biểu</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Ký và ghi rõ họ tên)</div>
        </div>
      </footer>
    </div>
  );
};

