import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap,
  Key,
  ChevronRight,
  ShieldCheck,
  Heart
} from 'lucide-react';
import * as XLSX from 'xlsx';

// Define the AIStudio interface to match the environment's expected type
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    readonly aistudio: AIStudio;
  }
}

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Kiểm tra trạng thái API Key khi khởi chạy
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } else {
        // Fallback nếu chạy ngoài môi trường AI Studio (có thể cho phép pass nếu dùng env có sẵn)
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Theo yêu cầu: Phải giả định việc chọn key thành công và tiếp tục vào app để tránh race condition
      setIsKeySelected(true);
    }
  };

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            let formattedBirth = String(row[birthIdx] || '').trim();

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth,
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét cho ${selectedGrade} - Môn ${selectedSubject}!` });
    } catch (error: any) {
      if (error.message && error.message.includes("Requested entity was not found")) {
        setNotification({ type: 'error', message: 'Lỗi API Key. Vui lòng thiết lập lại API Key.' });
        setIsKeySelected(false); // Reset để quay về màn hình chào
      } else {
        setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_${selectedGrade.replace(/\s/g, '_')}_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  // Màn hình chờ kiểm tra API Key ban đầu
  if (isKeySelected === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
      </div>
    );
  }

  // Màn hình Chào mừng và yêu cầu API Key
  if (isKeySelected === false) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-xl w-full bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="bg-indigo-600 p-8 text-white text-center">
            <div className="inline-flex p-4 bg-white/20 rounded-2xl mb-4 backdrop-blur-sm">
              <BookOpen size={48} />
            </div>
            <h1 className="text-3xl font-black mb-2 uppercase tracking-tight">Trợ Lý Giáo Viên</h1>
            <p className="text-indigo-100 font-medium">Hệ thống hỗ trợ viết nhận xét học bạ thông minh</p>
          </div>

          <div className="p-10 space-y-8">
            <div className="space-y-4">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <ShieldCheck className="text-emerald-500" /> Thiết lập API Key
              </h2>
              <p className="text-slate-600 leading-relaxed text-sm">
                Để ứng dụng có thể sử dụng trí tuệ nhân tạo (Gemini AI) tạo nhận xét, bạn cần cung cấp một API Key hợp lệ từ <strong>Google AI Studio</strong>. 
                Vui lòng sử dụng API Key từ một dự án có trả phí (Paid GCP Project).
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-start gap-3">
                  <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600 mt-1">
                    <Sparkles size={18} />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-sm">Cá nhân hóa</h3>
                    <p className="text-[11px] text-slate-500">Nhận xét tích cực cho từng học sinh</p>
                  </div>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-start gap-3">
                  <div className="p-2 bg-emerald-100 rounded-lg text-emerald-600 mt-1">
                    <Heart size={18} />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-sm">Sư phạm</h3>
                    <p className="text-[11px] text-slate-500">Tuân thủ Thông tư 22/BGDĐT</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-4">
              <button 
                onClick={handleSelectKey}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-3"
              >
                <Key size={24} />
                BẮT ĐẦU THIẾT LẬP
                <ChevronRight size={24} />
              </button>

              <a 
                href="https://ai.google.dev/gemini-api/docs/billing" 
                target="_blank" 
                rel="noopener noreferrer"
                className="text-center text-xs text-indigo-500 font-bold hover:underline"
              >
                Tìm hiểu về Billing & API Key
              </a>
            </div>
          </div>

          <div className="bg-slate-50 border-t p-4 text-center">
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Dữ liệu của bạn được bảo mật tuyệt đối</p>
          </div>
        </div>
      </div>
    );
  }

  // Màn hình chính của App
  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black animate-in fade-in duration-700">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý Tiểu Học - Nấm Dẩn</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Circular 22/BGDĐT - Ngôn từ tích cực</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* Grade Selection */}
            <div className="relative group">
              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-600">
                <GraduationCap size={16} />
              </div>
              <select 
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
                className="pl-9 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[120px]"
              >
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            {/* Subject Selection */}
            <div className="relative group">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
              title="AI sẽ viết nhận xét phù hợp với khối lớp và môn học đã chọn"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight">ĐÁNH GIÁ ĐỊNH KỲ MÔN {selectedSubject.toUpperCase()}</h2>
            <p className="text-sm font-bold uppercase">{selectedGrade} - NĂM HỌC: 2025-2026</p>
          </div>
          <div className="text-right hidden md:block">
             <div className="text-[10px] font-bold text-slate-500 uppercase">Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <button 
                onClick={handleSelectKey}
                className="text-[10px] font-bold text-indigo-600 uppercase hover:underline flex items-center gap-1 justify-end mt-1"
             >
               <Key size={10} /> Đổi API Key
             </button>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse border border-slate-300">
              <thead className="bg-slate-50 text-black font-bold uppercase text-[10px] text-center sticky top-0 z-10">
                <tr>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-12">STT</th>
                  <th rowSpan={2} className="px-4 py-3 border border-slate-300 min-w-[200px]">Họ và tên</th>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-32">Ngày sinh</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-32">Mức đạt được</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-24">Điểm KTĐK</th>
                  <th colSpan={2} className="px-4 py-2 border border-slate-300 bg-slate-100">Nhận xét điểm mạnh và các mặt</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-12 text-center"></th>
                </tr>
                <tr className="bg-slate-50">
                  <th className="px-3 py-2 border border-slate-300 w-24">Mã nhận xét</th>
                  <th className="px-4 py-2 border border-slate-300">Nội dung</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-20 text-center text-slate-400 italic text-sm">
                      <div className="flex flex-col items-center gap-3">
                        <Upload size={40} className="text-slate-200" />
                        <p>Danh sách trống. Hãy tải file Excel hoặc thêm học sinh thủ công.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-indigo-50/30 transition-colors group">
                      <td className="px-2 py-3 text-sm text-center font-bold border-x border-slate-200">{record.stt}</td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.hoTen} 
                            onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)} 
                            placeholder="Nhập họ tên" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm font-bold text-black outline-none placeholder:font-normal placeholder:text-slate-300" 
                          />
                        </div>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <Calendar size={12} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.ngaySinh} 
                            onChange={(e) => handleUpdateField(index, 'ngaySinh', e.target.value)} 
                            placeholder="dd/mm/yyyy" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm text-black outline-none text-center font-medium" 
                          />
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black inline-block text-center w-full shadow-sm border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <input 
                          type="number" 
                          step="0.1" 
                          value={record.diem} 
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)} 
                          className="w-full px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <span className="text-[10px] font-bold font-mono px-1.5 py-1 bg-slate-100 border border-slate-200 rounded text-slate-700 shadow-xs">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <textarea 
                          value={record.noiDung} 
                          placeholder="AI sẽ tự động viết nhận xét tích cực..." 
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <button 
                          onClick={() => handleRemoveRow(index)} 
                          className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">Người lập biểu</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Ký và ghi rõ họ tên)</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap,
  Key,
  ChevronRight,
  ShieldCheck,
  Heart
} from 'lucide-react';
import * as XLSX from 'xlsx';

// Define the AIStudio interface to match the environment's expected type
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    readonly aistudio: AIStudio;
  }
}

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Kiểm tra trạng thái API Key khi khởi chạy
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } else {
        // Fallback nếu chạy ngoài môi trường AI Studio (có thể cho phép pass nếu dùng env có sẵn)
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Theo yêu cầu: Phải giả định việc chọn key thành công và tiếp tục vào app để tránh race condition
      setIsKeySelected(true);
    }
  };

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            let formattedBirth = String(row[birthIdx] || '').trim();

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth,
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét cho ${selectedGrade} - Môn ${selectedSubject}!` });
    } catch (error: any) {
      if (error.message && error.message.includes("Requested entity was not found")) {
        setNotification({ type: 'error', message: 'Lỗi API Key. Vui lòng thiết lập lại API Key.' });
        setIsKeySelected(false); // Reset để quay về màn hình chào
      } else {
        setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_${selectedGrade.replace(/\s/g, '_')}_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  // Màn hình chờ kiểm tra API Key ban đầu
  if (isKeySelected === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
      </div>
    );
  }

  // Màn hình Chào mừng và yêu cầu API Key
  if (isKeySelected === false) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-xl w-full bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="bg-indigo-600 p-8 text-white text-center">
            <div className="inline-flex p-4 bg-white/20 rounded-2xl mb-4 backdrop-blur-sm">
              <BookOpen size={48} />
            </div>
            <h1 className="text-3xl font-black mb-2 uppercase tracking-tight">Trợ Lý Giáo Viên</h1>
            <p className="text-indigo-100 font-medium">Hệ thống hỗ trợ viết nhận xét học bạ thông minh</p>
          </div>

          <div className="p-10 space-y-8">
            <div className="space-y-4">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <ShieldCheck className="text-emerald-500" /> Thiết lập API Key
              </h2>
              <p className="text-slate-600 leading-relaxed text-sm">
                Để ứng dụng có thể sử dụng trí tuệ nhân tạo (Gemini AI) tạo nhận xét, bạn cần cung cấp một API Key hợp lệ. 
                Bạn có thể lấy mã này hoàn toàn miễn phí từ <strong>Google AI Studio</strong>.
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-start gap-3">
                  <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600 mt-1">
                    <Sparkles size={18} />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-sm">Cá nhân hóa</h3>
                    <p className="text-[11px] text-slate-500">Nhận xét tích cực cho từng học sinh</p>
                  </div>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-start gap-3">
                  <div className="p-2 bg-emerald-100 rounded-lg text-emerald-600 mt-1">
                    <Heart size={18} />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-sm">Sư phạm</h3>
                    <p className="text-[11px] text-slate-500">Tuân thủ Thông tư 22/BGDĐT</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-4">
              <button 
                onClick={handleSelectKey}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-3"
              >
                <Key size={24} />
                NHẬP API KEY
                <ChevronRight size={24} />
              </button>

              <a 
                href="https://aistudio.google.com/app/apikey" 
                target="_blank" 
                rel="noopener noreferrer"
                className="text-center text-xs text-indigo-500 font-bold hover:underline"
              >
                Lấy mã API Key miễn phí tại đây
              </a>
            </div>
          </div>

          <div className="bg-slate-50 border-t p-4 text-center">
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Dữ liệu của bạn được bảo mật tuyệt đối</p>
          </div>
        </div>
      </div>
    );
  }

  // Màn hình chính của App
  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black animate-in fade-in duration-700">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý tạo nhận xét Tiểu Học</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Theo TT22/BGDĐT - Ngôn từ tích cực</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* Grade Selection */}
            <div className="relative group">
              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-600">
                <GraduationCap size={16} />
              </div>
              <select 
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
                className="pl-9 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[120px]"
              >
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            {/* Subject Selection */}
            <div className="relative group">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
              title="AI sẽ viết nhận xét phù hợp với khối lớp và môn học đã chọn"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight">ĐÁNH GIÁ ĐỊNH KỲ MÔN {selectedSubject.toUpperCase()}</h2>
            <p className="text-sm font-bold uppercase">{selectedGrade} - NĂM HỌC: 2025-2026</p>
          </div>
          <div className="text-right hidden md:block">
             <div className="text-[10px] font-bold text-slate-500 uppercase">Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <button 
                onClick={handleSelectKey}
                className="text-[10px] font-bold text-indigo-600 uppercase hover:underline flex items-center gap-1 justify-end mt-1"
             >
               <Key size={10} /> Đổi API Key
             </button>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse border border-slate-300">
              <thead className="bg-slate-50 text-black font-bold uppercase text-[10px] text-center sticky top-0 z-10">
                <tr>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-12">STT</th>
                  <th rowSpan={2} className="px-4 py-3 border border-slate-300 min-w-[200px]">Họ và tên</th>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-32">Ngày sinh</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-32">Mức đạt được</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-24">Điểm KTĐK</th>
                  <th colSpan={2} className="px-4 py-2 border border-slate-300 bg-slate-100">Nhận xét điểm mạnh và các mặt</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-12 text-center"></th>
                </tr>
                <tr className="bg-slate-50">
                  <th className="px-3 py-2 border border-slate-300 w-24">Mã nhận xét</th>
                  <th className="px-4 py-2 border border-slate-300">Nội dung</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-20 text-center text-slate-400 italic text-sm">
                      <div className="flex flex-col items-center gap-3">
                        <Upload size={40} className="text-slate-200" />
                        <p>Danh sách trống. Hãy tải file Excel hoặc thêm học sinh thủ công.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-indigo-50/30 transition-colors group">
                      <td className="px-2 py-3 text-sm text-center font-bold border-x border-slate-200">{record.stt}</td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.hoTen} 
                            onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)} 
                            placeholder="Nhập họ tên" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm font-bold text-black outline-none placeholder:font-normal placeholder:text-slate-300" 
                          />
                        </div>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <Calendar size={12} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.ngaySinh} 
                            onChange={(e) => handleUpdateField(index, 'ngaySinh', e.target.value)} 
                            placeholder="dd/mm/yyyy" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm text-black outline-none text-center font-medium" 
                          />
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black inline-block text-center w-full shadow-sm border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <input 
                          type="number" 
                          step="0.1" 
                          value={record.diem} 
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)} 
                          className="w-full px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <span className="text-[10px] font-bold font-mono px-1.5 py-1 bg-slate-100 border border-slate-200 rounded text-slate-700 shadow-xs">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <textarea 
                          value={record.noiDung} 
                          placeholder="AI sẽ tự động viết nhận xét tích cực..." 
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <button 
                          onClick={() => handleRemoveRow(index)} 
                          className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">người tạo app</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Hùng Nguyễn)</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap,
  Key,
  ChevronRight,
  ShieldCheck,
  Heart
} from 'lucide-react';
import * as XLSX from 'xlsx';

// Define the AIStudio interface to match the environment's expected type
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    // Fix: Remove readonly as it must have identical modifiers across all declarations of 'aistudio'
    aistudio: AIStudio;
  }
}

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Kiểm tra trạng thái API Key khi khởi chạy
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } else {
        // Fallback nếu chạy ngoài môi trường AI Studio (có thể cho phép pass nếu dùng env có sẵn)
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Theo yêu cầu: Phải giả định việc chọn key thành công và tiếp tục vào app để tránh race condition
      setIsKeySelected(true);
    }
  };

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            let formattedBirth = String(row[birthIdx] || '').trim();

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth,
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét cho ${selectedGrade} - Môn ${selectedSubject}!` });
    } catch (error: any) {
      if (error.message && error.message.includes("Requested entity was not found")) {
        setNotification({ type: 'error', message: 'Lỗi API Key. Vui lòng thiết lập lại API Key.' });
        setIsKeySelected(false); // Reset để quay về màn hình chào
      } else {
        setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_${selectedGrade.replace(/\s/g, '_')}_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  // Màn hình chờ kiểm tra API Key ban đầu
  if (isKeySelected === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
      </div>
    );
  }

  // Màn hình Chào mừng và yêu cầu API Key
  if (isKeySelected === false) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-xl w-full bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="bg-indigo-600 p-8 text-white text-center">
            <div className="inline-flex p-4 bg-white/20 rounded-2xl mb-4 backdrop-blur-sm">
              <BookOpen size={48} />
            </div>
            <h1 className="text-3xl font-black mb-2 uppercase tracking-tight">Trợ Lý Giáo Viên</h1>
            <p className="text-indigo-100 font-medium">Hệ thống hỗ trợ viết nhận xét học bạ thông minh</p>
          </div>

          <div className="p-10 space-y-8">
            <div className="space-y-4">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <ShieldCheck className="text-emerald-500" /> Thiết lập API Key
              </h2>
              <p className="text-slate-600 leading-relaxed text-sm">
                Để ứng dụng có thể sử dụng trí tuệ nhân tạo (Gemini AI) tạo nhận xét, bạn cần cung cấp một API Key hợp lệ. 
                Bạn có thể lấy mã này hoàn toàn miễn phí từ <strong>Google AI Studio</strong>.
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-start gap-3">
                  <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600 mt-1">
                    <Sparkles size={18} />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-sm">Cá nhân hóa</h3>
                    <p className="text-[11px] text-slate-500">Nhận xét tích cực cho từng học sinh</p>
                  </div>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-start gap-3">
                  <div className="p-2 bg-emerald-100 rounded-lg text-emerald-600 mt-1">
                    <Heart size={18} />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-sm">Sư phạm</h3>
                    <p className="text-[11px] text-slate-500">Tuân thủ Thông tư 22/BGDĐT</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-4">
              <button 
                onClick={handleSelectKey}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-3"
              >
                <Key size={24} />
                NHẬP API KEY
                <ChevronRight size={24} />
              </button>

              <a 
                href="https://aistudio.google.com/app/apikey" 
                target="_blank" 
                rel="noopener noreferrer"
                className="text-center text-xs text-indigo-500 font-bold hover:underline"
              >
                Lấy mã API Key miễn phí tại đây
              </a>
            </div>
          </div>

          <div className="bg-slate-50 border-t p-4 text-center">
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Dữ liệu của bạn được bảo mật tuyệt đối</p>
          </div>
        </div>
      </div>
    );
  }

  // Màn hình chính của App
  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black animate-in fade-in duration-700">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý tạo nhận xét Tiểu Học</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Theo TT22/BGDĐT - Ngôn từ tích cực</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* Grade Selection */}
            <div className="relative group">
              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-600">
                <GraduationCap size={16} />
              </div>
              <select 
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
                className="pl-9 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[120px]"
              >
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            {/* Subject Selection */}
            <div className="relative group">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
              title="AI sẽ viết nhận xét phù hợp với khối lớp và môn học đã chọn"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight">ĐÁNH GIÁ ĐỊNH KỲ MÔN {selectedSubject.toUpperCase()}</h2>
            <p className="text-sm font-bold uppercase">{selectedGrade} - NĂM HỌC: 2025-2026</p>
          </div>
          <div className="text-right hidden md:block">
             <div className="text-[10px] font-bold text-slate-500 uppercase">Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <button 
                onClick={handleSelectKey}
                className="text-[10px] font-bold text-indigo-600 uppercase hover:underline flex items-center gap-1 justify-end mt-1"
             >
               <Key size={10} /> Đổi API Key
             </button>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse border border-slate-300">
              <thead className="bg-slate-50 text-black font-bold uppercase text-[10px] text-center sticky top-0 z-10">
                <tr>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-12">STT</th>
                  <th rowSpan={2} className="px-4 py-3 border border-slate-300 min-w-[200px]">Họ và tên</th>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-32">Ngày sinh</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-32">Mức đạt được</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-24">Điểm KTĐK</th>
                  <th colSpan={2} className="px-4 py-2 border border-slate-300 bg-slate-100">Nhận xét điểm mạnh và các mặt</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-12 text-center"></th>
                </tr>
                <tr className="bg-slate-50">
                  <th className="px-3 py-2 border border-slate-300 w-24">Mã nhận xét</th>
                  <th className="px-4 py-2 border border-slate-300">Nội dung</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-20 text-center text-slate-400 italic text-sm">
                      <div className="flex flex-col items-center gap-3">
                        <Upload size={40} className="text-slate-200" />
                        <p>Danh sách trống. Hãy tải file Excel hoặc thêm học sinh thủ công.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-indigo-50/30 transition-colors group">
                      <td className="px-2 py-3 text-sm text-center font-bold border-x border-slate-200">{record.stt}</td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.hoTen} 
                            onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)} 
                            placeholder="Nhập họ tên" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm font-bold text-black outline-none placeholder:font-normal placeholder:text-slate-300" 
                          />
                        </div>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <Calendar size={12} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.ngaySinh} 
                            onChange={(e) => handleUpdateField(index, 'ngaySinh', e.target.value)} 
                            placeholder="dd/mm/yyyy" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm text-black outline-none text-center font-medium" 
                          />
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black inline-block text-center w-full shadow-sm border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <input 
                          type="number" 
                          step="0.1" 
                          value={record.diem} 
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)} 
                          className="w-full px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <span className="text-[10px] font-bold font-mono px-1.5 py-1 bg-slate-100 border border-slate-200 rounded text-slate-700 shadow-xs">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <textarea 
                          value={record.noiDung} 
                          placeholder="AI sẽ tự động viết nhận xét tích cực..." 
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <button 
                          onClick={() => handleRemoveRow(index)} 
                          className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">người tạo app</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Hùng Nguyễn)</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            let formattedBirth = String(row[birthIdx] || '').trim();

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth,
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found };
        return original;
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét cho ${selectedGrade} - Môn ${selectedSubject}!` });
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_${selectedGrade.replace(/\s/g, '_')}_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black animate-in fade-in duration-700">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý tạo nhận xét Tiểu Học</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Theo TT22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* Grade Selection */}
            <div className="relative group">
              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-600">
                <GraduationCap size={16} />
              </div>
              <select 
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
                className="pl-9 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[120px]"
              >
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            {/* Subject Selection */}
            <div className="relative group">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
              title="AI sẽ viết nhận xét phù hợp với khối lớp và môn học đã chọn"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight">ĐÁNH GIÁ ĐỊNH KỲ MÔN {selectedSubject.toUpperCase()}</h2>
            <p className="text-sm font-bold uppercase">{selectedGrade} - NĂM HỌC: 2025-2026</p>
          </div>
          <div className="text-right hidden md:block">
             <div className="text-[10px] font-bold text-slate-500 uppercase">Trường PTDTBT Tiểu học Nấm Dẩn</div>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse border border-slate-300">
              <thead className="bg-slate-50 text-black font-bold uppercase text-[10px] text-center sticky top-0 z-10">
                <tr>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-12">STT</th>
                  <th rowSpan={2} className="px-4 py-3 border border-slate-300 min-w-[200px]">Họ và tên</th>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-32">Ngày sinh</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-32">Mức đạt được</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-24">Điểm KTĐK</th>
                  <th colSpan={2} className="px-4 py-2 border border-slate-300 bg-slate-100">Nhận xét điểm mạnh và các mặt</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-12 text-center"></th>
                </tr>
                <tr className="bg-slate-50">
                  <th className="px-3 py-2 border border-slate-300 w-24">Mã nhận xét</th>
                  <th className="px-4 py-2 border border-slate-300">Nội dung</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-6 py-20 text-center text-slate-400 italic text-sm">
                      <div className="flex flex-col items-center gap-3">
                        <Upload size={40} className="text-slate-200" />
                        <p>Danh sách trống. Hãy tải file Excel hoặc thêm học sinh thủ công.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className="hover:bg-indigo-50/30 transition-colors group">
                      <td className="px-2 py-3 text-sm text-center font-bold border-x border-slate-200">{record.stt}</td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <User size={14} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.hoTen} 
                            onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)} 
                            placeholder="Nhập họ tên" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm font-bold text-black outline-none placeholder:font-normal placeholder:text-slate-300" 
                          />
                        </div>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <div className="flex items-center gap-2">
                          <Calendar size={12} className="text-slate-300 shrink-0" />
                          <input 
                            type="text" 
                            value={record.ngaySinh} 
                            onChange={(e) => handleUpdateField(index, 'ngaySinh', e.target.value)} 
                            placeholder="dd/mm/yyyy" 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded text-sm text-black outline-none text-center font-medium" 
                          />
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black inline-block text-center w-full shadow-sm border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <input 
                          type="number" 
                          step="0.1" 
                          value={record.diem} 
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)} 
                          className="w-full px-1 py-1 border border-slate-100 hover:border-slate-300 focus:border-indigo-500 rounded font-black text-black text-center outline-none bg-transparent" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <span className="text-[10px] font-bold font-mono px-1.5 py-1 bg-slate-100 border border-slate-200 rounded text-slate-700 shadow-xs">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <textarea 
                          value={record.noiDung} 
                          placeholder="AI sẽ tự động viết nhận xét tích cực..." 
                          onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                          className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <button 
                          onClick={() => handleRemoveRow(index)} 
                          className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">người tạo app</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Hùng Nguyễn)</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap,
  RefreshCw
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const generateSingleComment = async (index: number) => {
    const record = records[index];
    if (record.isProcessing) return;

    const updatedProcessing = [...records];
    updatedProcessing[index].isProcessing = true;
    setRecords(updatedProcessing);

    try {
      const results = await generateComments([record], selectedSubject, selectedGrade);
      if (results.length > 0) {
        const updated = [...records];
        updated[index] = { ...updated[index], ...results[0], isProcessing: false };
        setRecords(updated);
      }
    } catch (error) {
      setNotification({ type: 'error', message: `Lỗi khi tạo nhận xét cho ${record.hoTen}` });
      const resetProcessing = [...records];
      resetProcessing[index].isProcessing = false;
      setRecords(resetProcessing);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            let formattedBirth = String(row[birthIdx] || '').trim();

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: formattedBirth,
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
              isProcessing: false,
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      // Đánh dấu tất cả là đang xử lý
      setRecords(prev => prev.map(r => 
        targetRecords.some(tr => tr.stt === r.stt) ? { ...r, isProcessing: true } : r
      ));

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      const updatedRecords = records.map(original => {
        const found = results.find(r => r?.stt === original.stt);
        if (found) return { ...original, ...found, isProcessing: false };
        return { ...original, isProcessing: false };
      });

      setRecords(updatedRecords);
      setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét cho ${selectedGrade} - Môn ${selectedSubject}!` });
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
      setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_${selectedGrade.replace(/\s/g, '_')}_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black animate-in fade-in duration-700">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý tạo nhận xét Tiểu Học</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Theo TT22/BGDĐT</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* Grade Selection */}
            <div className="relative group">
              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-600">
                <GraduationCap size={16} />
              </div>
              <select 
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
                className="pl-9 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[120px]"
              >
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            {/* Subject Selection */}
            <div className="relative group">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <Plus size={12} className="rotate-45" />
              </div>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>
            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
              title="AI sẽ viết nhận xét phù hợp với khối lớp và môn học đã chọn"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>
            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight">ĐÁNH GIÁ ĐỊNH KỲ MÔN {selectedSubject.toUpperCase()}</h2>
            <p className="text-sm font-bold uppercase">{selectedGrade} - NĂM HỌC: 2025-2026</p>
          </div>
          <div className="text-right hidden md:block">
             <div className="text-[10px] font-bold text-slate-500 uppercase">Trường PTDTBT Tiểu học Nấm Dẩn</div>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
