                      </td>
                      <td className="px-3 py-3 border-x border-slate-200 relative">
                        <div className="flex items-start gap-2">
                          <textarea 
                            disabled={record.isProcessing}
                            value={record.noiDung} 
                            placeholder="AI sẽ tự động viết nhận xét tích cực..." 
                            onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px] placeholder:text-slate-200 disabled:opacity-50" 
                          />
                          {record.isProcessing && (
                            <div className="absolute inset-0 bg-white/40 flex items-center justify-center backdrop-blur-[1px]">
                              <Loader2 size={16} className="text-indigo-600 animate-spin" />
                            </div>
                          )}
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <div className="flex items-center justify-center gap-1">
                          <button 
                            onClick={() => generateSingleComment(index)} 
                            disabled={record.isProcessing || !record.hoTen}
                            title="Tạo lại nhận xét cho học sinh này"
                            className="text-indigo-400 hover:text-indigo-700 p-1 rounded-md hover:bg-indigo-50 transition-all disabled:opacity-30"
