                            <RefreshCw size={14} className={record.isProcessing ? 'animate-spin' : ''} />
                          </button>
                          <button 
                            onClick={() => handleRemoveRow(index)} 
                            disabled={record.isProcessing}
                            className="text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all p-1 disabled:opacity-0"
                          >
                            <Trash2 size={14} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            disabled={isGenerating}
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold disabled:opacity-50"
          >
            <Plus size={18} /> Thêm học sinh mới
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">người tạo app</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Hùng Nguyễn)</div>
        </div>
      </footer>
    </div>
  );
};

