import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên chủ nhiệm bậc Tiểu học tại Việt Nam, am hiểu Thông tư 22/BGDĐT và Thông tư 27.
Nhiệm vụ: Viết nhận xét học bạ cho môn học cụ thể dựa trên điểm số/mức độ đạt được.

YÊU CẦU THEO THÔNG TƯ 22:
1. Tập trung vào sự hình thành và phát triển năng lực, phẩm chất của học sinh.
2. Mức độ đánh giá: 
   - 9-10 điểm: Hoàn thành tốt (T)
   - 5-8 điểm: Hoàn thành (H)
   - Dưới 5 điểm: Chưa hoàn thành (C)
3. Nội dung nhận xét (2-3 câu, không xuống dòng, gộp thành 1 đoạn văn):
   - Câu 1: Khen ngợi điểm mạnh cụ thể về kiến thức hoặc kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một điểm cần hỗ trợ hoặc rèn luyện thêm.
   - Câu 3: Gợi ý một hành động cụ thể để tiến bộ hơn.
4. Văn phong: Gần gũi, yêu thương, mang tính khích lệ cao, đúng mực sư phạm tiểu học Việt Nam.
5. Cấm tuyệt đối: 
   - Không dùng từ dán nhãn tiêu cực (lười, hư, chậm chạp, vô ý thức, yếu, kém).
   - Không phán xét tính cách.
   - Thay bằng: "cần cố gắng hơn", "nên tập trung hơn", "phát huy khả năng", "rèn luyện thêm".
6. Phù hợp lứa tuổi: Ngôn từ phải phù hợp với KHỐI LỚP đã chọn (ví dụ Khối 1 dùng từ đơn giản, Khối 5 dùng từ ngữ chuẩn mực hơn).
`;

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string,
  signal?: AbortSignal
): Promise<Partial<StudentRecord>[]> => {
  // Luôn khởi tạo instance mới ngay trước khi gọi API để lấy API Key mới nhất
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Khối lớp: ${gradeLevel}. 
  Môn học: ${subject}. 
  Danh sách học sinh có điểm: ${JSON.stringify(records.map(r => ({ stt: r.stt, hoTen: r.hoTen, diem: r.diem })))}. 
  Hãy viết nhận xét cá nhân hóa, tích cực cho từng em. Trả về JSON theo schema.`;

  try {
    // Fix: ai.models.generateContent only accepts one argument. AbortSignal cannot be passed as a second argument.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              mucDo: { type: Type.STRING, description: "T, H, hoặc C" },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "mucDo", "noiDung"],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text.trim());
  } catch (error: any) {
    if (error.name === 'AbortError') {
      console.log('Generation aborted');
      return [];
    }
    console.error("Error generating comments:", error);
    throw error;
  }
};

