import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap,
  RefreshCw,
  XCircle
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });
  }, [records, selectedSubject]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }]);
  };

  const handleUpdateField = (index: number, field: keyof StudentRecord, value: any) => {
    const updatedRecords = [...records];
    if (field === 'diem') {
      const newScore = parseFloat(value);
      if (isNaN(newScore)) return;
      const val = Math.min(10, Math.max(0, newScore));
      updatedRecords[index].diem = val;
      updatedRecords[index].mucDo = val >= 9 ? 'T' : val >= 5 ? 'H' : 'C';
    } else {
      (updatedRecords[index] as any)[field] = value;
    }
    setRecords(updatedRecords);
  };

  const handleRemoveRow = (index: number) => {
    setRecords(records.filter((_, i) => i !== index));
  };

  const stopGeneration = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setIsGenerating(false);
    setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
    setNotification({ type: 'error', message: 'Đã dừng quá trình tạo nhận xét.' });
  };

  const generateSingleComment = async (index: number) => {
    const record = records[index];
    if (record.isProcessing) return;

    const updatedProcessing = [...records];
    updatedProcessing[index].isProcessing = true;
    setRecords(updatedProcessing);

    try {
      const results = await generateComments([record], selectedSubject, selectedGrade);
      if (results.length > 0) {
        const updated = [...records];
        updated[index] = { ...updated[index], ...results[0], isProcessing: false };
        setRecords(updated);
      } else {
        const updated = [...records];
        updated[index].isProcessing = false;
        setRecords(updated);
      }
    } catch (error) {
      setNotification({ type: 'error', message: `Lỗi khi tạo nhận xét cho ${record.hoTen}` });
      const resetProcessing = [...records];
      resetProcessing[index].isProcessing = false;
      setRecords(resetProcessing);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        const data = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false }) as any[][];
        if (data.length === 0) throw new Error("File trống");

        const keywords = {
          stt: ['stt', 'số thứ tự', 'id', 'no', 'st', 'só tt'],
          hoTen: ['họ và tên', 'họ tên', 'tên', 'ho ten', 'ho va ten', 'full name', 'fullname', 'name', 'họ và tên học sinh', 'tên học sinh'],
          ngaySinh: ['ngày sinh', 'ngay sinh', 'birth', 'dob', 'date of birth', 'ns', 'n.sinh'],
          diem: ['điểm', 'diem', 'score', 'điểm số', 'grade', 'điểm ktđk', 'ktđk', 'thi', 'điểm thi', 'mark'],
          mucDo: ['mức đạt được', 'mức', 'xếp loại', 'muc dat duoc', 'level', 'đánh giá', 'kết quả', 'đánh giá định kỳ']
        };

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i];
          let matches = 0;
          row.forEach((cell, idx) => {
            const val = String(cell || '').toLowerCase().trim();
            if (keywords.stt.some(k => val === k || val.includes(k))) matches++;
            if (keywords.hoTen.some(k => val === k || val.includes(k))) matches++;
            if (keywords.ngaySinh.some(k => val === k || val.includes(k))) matches++;
            if (keywords.diem.some(k => val === k || val.includes(k))) matches++;
            if (keywords.mucDo.some(k => val === k || val.includes(k))) matches++;
          });

          if (matches >= 2) {
            headerRowIdx = i;
            row.forEach((cell, idx) => {
              const val = String(cell || '').toLowerCase().trim();
              if (sttIdx === -1 && keywords.stt.some(k => val === k || val.includes(k))) sttIdx = idx;
              if (nameIdx === -1 && keywords.hoTen.some(k => val === k || val.includes(k))) nameIdx = idx;
              if (birthIdx === -1 && keywords.ngaySinh.some(k => val === k || val.includes(k))) birthIdx = idx;
              if (scoreIdx === -1 && keywords.diem.some(k => val === k || val.includes(k))) scoreIdx = idx;
              if (levelIdx === -1 && keywords.mucDo.some(k => val === k || val.includes(k))) levelIdx = idx;
            });
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = Math.min(data[headerRowIdx].length - 1, 4);

        const parseMucDo = (val: string): string => {
          const v = val.toLowerCase().trim();
          if (v.includes('tốt') || v === 't' || v.includes('htt')) return 'T';
          if (v.includes('chưa') || v === 'c' || v.includes('cht')) return 'C';
          if (v.includes('hoàn thành') || v === 'h' || v === 'ht') return 'H';
          return '';
        };

        const newRecords: StudentRecord[] = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] !== undefined && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const scoreRaw = row[scoreIdx];
            const score = typeof scoreRaw === 'number' ? scoreRaw : parseFloat(String(scoreRaw || 0));
            const validScore = isNaN(score) ? 0 : Math.min(10, Math.max(0, score));

            let mucDo = levelIdx !== -1 ? parseMucDo(String(row[levelIdx] || '')) : '';
            if (!mucDo) mucDo = validScore >= 9 ? 'T' : validScore >= 5 ? 'H' : 'C';

            return {
              stt: parseInt(row[sttIdx]) || idx + 1,
              hoTen: String(row[nameIdx] || "Học sinh").trim(),
              ngaySinh: String(row[birthIdx] || '').trim(),
              diem: validScore,
              mucDo: mucDo,
              maNhanXet: '',
              noiDung: '',
              isProcessing: false,
            };
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Xác định thành công ${newRecords.length} học sinh!` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh.' });
        }
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    try {
      const emptyRecords = records.filter(r => !r.noiDung);
      const targetRecords = emptyRecords.length > 0 ? emptyRecords : records;

      if (emptyRecords.length === 0) {
        if (!window.confirm("Tất cả đã có nhận xét. Bạn muốn tạo mới lại cho toàn bộ không?")) {
          setIsGenerating(false);
          return;
        }
      }

      setRecords(prev => prev.map(r => 
        targetRecords.some(tr => tr.stt === r.stt) ? { ...r, isProcessing: true } : r
      ));

      const results = await generateComments(targetRecords, selectedSubject, selectedGrade);

      if (results.length > 0) {
        const updatedRecords = records.map(original => {
          const found = results.find(r => r?.stt === original.stt);
          if (found) return { ...original, ...found, isProcessing: false };
          return { ...original, isProcessing: false };
        });

        setRecords(updatedRecords);
        setNotification({ type: 'success', message: `Đã hoàn tất tạo nhận xét theo TT 27!` });
      } else {
        setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
      }
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI. Vui lòng thử lại.' });
      setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Ngày sinh': r.ngaySinh,
      'Mức đạt được': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm KTĐK': r.diem,
      'Mã nhận xét': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "DanhGia");
    XLSX.writeFile(workbook, `BangDiem_TT27_${selectedSubject.replace(/\s/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-100 pb-20 text-black animate-in fade-in duration-700">
      <header className="bg-white border-b sticky top-0 z-30 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-black uppercase tracking-tight">Trợ Lý nhận xét TT 27/2020</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Nguyễn Đức Hùng - Trường PTDTBT TH Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="relative group">
              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-600">
                <GraduationCap size={16} />
              </div>
              <select 
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
                className="pl-9 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[120px]"
              >
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
            </div>

            <div className="relative group">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="pl-3 pr-8 py-2 bg-white border border-slate-300 rounded-lg text-sm font-bold text-black outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer shadow-sm min-w-[160px]"
              >
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>

            <input type="file" accept=".xlsx, .xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()} 
              disabled={isGenerating}
              className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-black rounded-lg hover:bg-slate-50 transition-all shadow-sm text-sm font-bold active:scale-95 disabled:opacity-50"
            >
              <Upload size={18} className="text-indigo-600" />
              Tải Excel
            </button>

            {isGenerating ? (
              <button 
                onClick={stopGeneration} 
                className="inline-flex items-center gap-2 px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 transition-all shadow-md active:scale-95 text-sm font-bold animate-pulse"
              >
                <XCircle size={18} />
                Dừng lại
              </button>
            ) : (
              <button 
                onClick={processGeneration} 
                disabled={records.length === 0} 
                className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
              >
                <Sparkles size={18} />
                Tạo nhận xét
              </button>
            )}

            <button 
              onClick={exportToExcel} 
              disabled={isGenerating}
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95 disabled:opacity-50"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
          <div className="text-slate-600">
            <h2 className="text-2xl font-black text-slate-900 leading-tight uppercase">Đánh giá định kỳ môn {selectedSubject}</h2>
            <p className="text-sm font-bold uppercase">Theo Thông tư 27/2020/TT-BGDĐT</p>
          </div>
          <div className="text-right hidden md:block">
             <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Trường PTDTBT Tiểu học Nấm Dẩn</div>
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse border border-slate-300">
              <thead className="bg-slate-50 text-black font-bold uppercase text-[10px] text-center sticky top-0 z-10">
                <tr>
                  <th rowSpan={2} className="px-3 py-3 border border-slate-300 w-12">STT</th>
                  <th rowSpan={2} className="px-4 py-3 border border-slate-300 min-w-[200px]">Họ và tên</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-32">Mức đạt được</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-24">Điểm</th>
                  <th colSpan={2} className="px-4 py-2 border border-slate-300 bg-slate-100">Nội dung nhận xét (Không xưng "em", không tên)</th>
                  <th rowSpan={2} className="px-2 py-3 border border-slate-300 w-16 text-center"></th>
                </tr>
                <tr className="bg-slate-50">
                  <th className="px-3 py-2 border border-slate-300 w-24 text-[9px]">Mã NX</th>
                  <th className="px-4 py-2 border border-slate-300">Nội dung (Đúng 2 câu)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {calculatedRecords.length === 0 ? (
                  <tr>
                    <td colSpan={7} className="px-6 py-20 text-center text-slate-400 italic text-sm">
                      <div className="flex flex-col items-center gap-3">
                        <Upload size={40} className="text-slate-200" />
                        <p>Danh sách trống. Hãy tải file Excel.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  calculatedRecords.map((record, index) => (
                    <tr key={index} className={`hover:bg-indigo-50/30 transition-colors group ${record.isProcessing ? 'opacity-60 bg-indigo-50/20' : ''}`}>
                      <td className="px-2 py-3 text-sm text-center font-bold border-x border-slate-200">{record.stt}</td>
                      <td className="px-3 py-3 border-x border-slate-200">
                        <input 
                          type="text" 
                          disabled={record.isProcessing}
                          value={record.hoTen} 
                          onChange={(e) => handleUpdateField(index, 'hoTen', e.target.value)} 
                          className="w-full bg-transparent border-none text-sm font-bold text-black outline-none" 
                        />
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black inline-block text-center w-full border ${
                          record.mucDo === 'T' ? 'bg-amber-100 text-amber-950 border-amber-200' :
                          record.mucDo === 'H' ? 'bg-blue-100 text-blue-950 border-blue-200' : 'bg-rose-100 text-rose-950 border-rose-200'
                        }`}>
                          {record.mucDo === 'T' ? 'HOÀN THÀNH TỐT' : record.mucDo === 'H' ? 'HOÀN THÀNH' : 'CHƯA HOÀN THÀNH'}
                        </span>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <input 
                          type="number" 
                          disabled={record.isProcessing}
                          step="0.1" 
                          value={record.diem} 
                          onChange={(e) => handleUpdateField(index, 'diem', e.target.value)} 
                          className="w-full px-1 py-1 font-black text-black text-center outline-none bg-transparent" 
                        />
                      </td>
                      <td className="px-2 py-3 text-center border-x border-slate-200">
                        <span className="text-[10px] font-bold font-mono px-1.5 py-1 bg-slate-100 border border-slate-200 rounded text-slate-700">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-3 py-3 border-x border-slate-200 relative">
                        <div className="flex items-start gap-2">
                          <textarea 
                            disabled={record.isProcessing}
                            value={record.noiDung} 
                            placeholder="..." 
                            onChange={(e) => handleUpdateField(index, 'noiDung', e.target.value)} 
                            className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-100 rounded p-1 text-xs text-black font-medium leading-relaxed resize-none min-h-[44px]" 
                          />
                          {record.isProcessing && (
                            <div className="absolute inset-0 bg-white/40 flex items-center justify-center backdrop-blur-[1px]">
                              <Loader2 size={16} className="text-indigo-600 animate-spin" />
                            </div>
                          )}
                        </div>
                      </td>
                      <td className="px-2 py-3 border-x border-slate-200">
                        <div className="flex items-center justify-center gap-1">
                          <button 
                            onClick={() => generateSingleComment(index)} 
                            disabled={record.isProcessing || !record.hoTen}
                            className="text-indigo-400 hover:text-indigo-700 p-1"
                          >
                            <RefreshCw size={14} className={record.isProcessing ? 'animate-spin' : ''} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
          <button 
            onClick={handleAddRow} 
            disabled={isGenerating}
            className="w-full py-4 border-t border-dashed border-slate-200 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/30 transition-all flex items-center justify-center gap-2 text-sm font-bold"
          >
            <Plus size={18} /> Thêm học sinh
          </button>
        </div>
      </main>

      <footer className="mt-12 text-center pb-20">
        <div className="inline-flex flex-col items-center gap-3 bg-white px-10 py-6 rounded-2xl shadow-sm border border-slate-200">
           <div className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">Sản phẩm hỗ trợ giáo dục</div>
           <div className="w-32 h-px bg-slate-100"></div>
           <div className="italic text-[10px] text-slate-400 font-medium">(Nguyễn Đức Hùng)</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  User,
  Calendar,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  GraduationCap,
  RefreshCw,
  XCircle,
  Table as TableIcon,
  AlignLeft,
  Search
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>('table');
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    let filtered = records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });

    if (searchTerm) {
      filtered = filtered.filter(r => 
        r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.noiDung.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    return filtered;
  }, [records, selectedSubject, searchTerm]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }));
    setRecords(initialRecords);
  }, []);

  const handleAddRow = () => {
    const newStt = records.length > 0 ? Math.max(...records.map(r => r.stt)) + 1 : 1;
    setRecords([...records, {
      stt: newStt,
      hoTen: '',
      ngaySinh: '',
      diem: 10,
      mucDo: 'T',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }]);
  };

  const handleUpdateField = (stt: number, field: keyof StudentRecord, value: any) => {
    setRecords(prev => prev.map(r => {
      if (r.stt === stt) {
        if (field === 'diem') {
          const val = Math.min(10, Math.max(0, parseFloat(value) || 0));
          return { ...r, diem: val, mucDo: val >= 9 ? 'T' : val >= 5 ? 'H' : 'C' };
        }
        return { ...r, [field]: value };
      }
      return r;
    }));
  };

  const handleRemoveRow = (stt: number) => {
    setRecords(records.filter(r => r.stt !== stt));
  };

  const stopGeneration = () => {
    setIsGenerating(false);
    setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
    setNotification({ type: 'error', message: 'Đã dừng quá trình tạo nhận xét.' });
  };

  const generateSingleComment = async (stt: number) => {
    const record = records.find(r => r.stt === stt);
    if (!record || record.isProcessing) return;

    setRecords(prev => prev.map(r => r.stt === stt ? { ...r, isProcessing: true } : r));

    try {
      const results = await generateComments([record], selectedSubject, selectedGrade);
      if (results.length > 0) {
        setRecords(prev => prev.map(r => r.stt === stt ? { ...r, ...results[0], isProcessing: false } : r));
      } else {
        setRecords(prev => prev.map(r => r.stt === stt ? { ...r, isProcessing: false } : r));
      }
    } catch (error) {
      setNotification({ type: 'error', message: `Lỗi khi tạo nhận xét cho ${record.hoTen}` });
      setRecords(prev => prev.map(r => r.stt === stt ? { ...r, isProcessing: false } : r));
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        // Simple logic to find headers and parse
        const newRecords = data.slice(1).map((row, idx) => ({
          stt: idx + 1,
          hoTen: String(row[1] || "Học sinh"),
          ngaySinh: String(row[2] || ""),
          diem: parseFloat(row[3]) || 0,
          mucDo: (parseFloat(row[3]) || 0) >= 9 ? 'T' : (parseFloat(row[3]) || 0) >= 5 ? 'H' : 'C',
          maNhanXet: '',
          noiDung: '',
          isProcessing: false,
        }));
        setRecords(newRecords);
        setNotification({ type: 'success', message: 'Đã tải dữ liệu thành công!' });
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi định dạng file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    const targetRecords = records.filter(r => !r.noiDung);
    const toProcess = targetRecords.length > 0 ? targetRecords : records;

    setRecords(prev => prev.map(r => toProcess.some(tp => tp.stt === r.stt) ? { ...r, isProcessing: true } : r));

    try {
      const results = await generateComments(toProcess, selectedSubject, selectedGrade);
      setRecords(prev => prev.map(original => {
        const found = results.find(r => r.stt === original.stt);
        return found ? { ...original, ...found, isProcessing: false } : { ...original, isProcessing: false };
      }));
      setNotification({ type: 'success', message: 'Hoàn tất tạo nhận xét theo TT 27!' });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI.' });
      setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Mức đạt': r.mucDo,
      'Điểm': r.diem,
      'Mã NX': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedSubject}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-indigo-200 shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">N.Đ.Hùng - Tiểu học Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
              onChange={(e) => setSelectedGrade(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>

            <select 
              value={selectedSubject}
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              {isGenerating ? 'Đang tạo...' : 'Tạo nhận xét'}
            </button>

            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất File
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {/* Tab Selection Navigation */}
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex w-full sm:w-auto">
            <button 
              onClick={() => setViewMode('table')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <TableIcon size={18} />
              Bảng nhận xét
            </button>
            <button 
              onClick={() => setViewMode('content')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <AlignLeft size={18} />
              Nội dung nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm học sinh..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm"
            />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in slide-in-from-top-4 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto p-1 hover:bg-black/10 rounded-full">&times;</button>
          </div>
        )}

        {viewMode === 'table' ? (
          /* Chế độ Bảng Tổng Hợp */
          <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider text-center border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-4 w-12">STT</th>
                    <th className="px-6 py-4 text-left">Họ và tên học sinh</th>
                    <th className="px-4 py-4 w-32">Mức đạt</th>
                    <th className="px-4 py-4 w-24">Điểm</th>
                    <th className="px-4 py-4 w-24">Mã NX</th>
                    <th className="px-6 py-4 text-left">Nội dung nhận xét (TT 27)</th>
                    <th className="px-4 py-4 w-16"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {calculatedRecords.map((record, index) => (
                    <tr key={record.stt} className={`group hover:bg-slate-50 transition-colors ${record.isProcessing ? 'bg-indigo-50/30' : ''}`}>
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-400">{record.stt}</td>
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={record.hoTen} 
                          onChange={(e) => handleUpdateField(record.stt, 'hoTen', e.target.value)}
                          className="w-full bg-transparent border-none text-sm font-bold outline-none focus:text-indigo-600"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border ${
                          record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                          record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'
                        }`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center">
                        <input 
                          type="number" 
                          value={record.diem}
                          onChange={(e) => handleUpdateField(record.stt, 'diem', e.target.value)}
                          className="w-12 text-center text-sm font-bold bg-slate-100 rounded py-1 outline-none focus:ring-1 focus:ring-indigo-300"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-6 py-4 relative">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => handleUpdateField(record.stt, 'noiDung', e.target.value)}
                          placeholder="Chưa có nội dung..."
                          className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[40px] leading-relaxed outline-none focus:ring-0"
                        />
                        {record.isProcessing && (
                          <div className="absolute inset-0 bg-white/60 flex items-center justify-center backdrop-blur-[1px]">
                            <Loader2 size={16} className="text-indigo-600 animate-spin" />
                          </div>
                        )}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button 
                          onClick={() => generateSingleComment(record.stt)}
                          className="p-1.5 text-slate-300 hover:text-indigo-600 transition-colors"
                        >
                          <RefreshCw size={14} className={record.isProcessing ? 'animate-spin' : ''} />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <button 
              onClick={handleAddRow}
              className="w-full py-4 bg-slate-50 text-slate-500 hover:text-indigo-600 hover:bg-white transition-all text-sm font-bold flex items-center justify-center gap-2 border-t border-slate-100"
            >
              <Plus size={18} /> Thêm học sinh
            </button>
          </div>
        ) : (
          /* Chế độ Nội Dung Nhận Xét (Xem tập trung) */
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {calculatedRecords.map((record) => (
              <div 
                key={record.stt} 
                className={`bg-white p-6 rounded-2xl shadow-sm border border-slate-200 transition-all hover:shadow-md hover:border-indigo-200 relative group ${
                  record.isProcessing ? 'ring-2 ring-indigo-500 ring-opacity-20 bg-indigo-50/10' : ''
                }`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-3">
                    <span className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-xs font-black text-slate-500">
                      {record.stt}
                    </span>
                    <div>
                      <h3 className="text-sm font-black text-slate-900 group-hover:text-indigo-600 transition-colors">{record.hoTen}</h3>
                      <div className="flex items-center gap-2 mt-1">
                        <span className={`text-[9px] font-black px-1.5 py-0.5 rounded border ${
                          record.mucDo === 'T' ? 'bg-amber-50 border-amber-100 text-amber-600' :
                          record.mucDo === 'H' ? 'bg-blue-50 border-blue-100 text-blue-600' : 'bg-rose-50 border-rose-100 text-rose-600'
                        }`}>
                          {record.mucDo === 'T' ? 'Hoàn thành tốt' : record.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành'}
                        </span>
                        <span className="text-[9px] font-bold text-slate-400">Điểm: {record.diem}</span>
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={() => generateSingleComment(record.stt)}
                    className="p-2 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                  >
                    <RefreshCw size={16} className={record.isProcessing ? 'animate-spin' : ''} />
                  </button>
                </div>

                <div className="relative">
                  <textarea 
                    value={record.noiDung}
                    onChange={(e) => handleUpdateField(record.stt, 'noiDung', e.target.value)}
                    placeholder="Đang chờ tạo nội dung..."
                    className="w-full bg-slate-50 border-none rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[100px] resize-none focus:ring-2 focus:ring-indigo-100 outline-none transition-all"
                  />
                  {record.isProcessing && (
                    <div className="absolute inset-0 bg-white/40 flex flex-col items-center justify-center rounded-xl backdrop-blur-[2px]">
                      <Loader2 size={24} className="text-indigo-600 animate-spin mb-2" />
                      <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Đang tạo...</span>
                    </div>
                  )}
                </div>

                <div className="mt-3 flex justify-end">
                  <span className="text-[10px] font-black text-slate-300 uppercase">Mã: {record.maNhanXet}</span>
                </div>
              </div>
            ))}

            <button 
              onClick={handleAddRow}
              className="border-2 border-dashed border-slate-200 rounded-2xl p-6 flex flex-col items-center justify-center gap-2 text-slate-400 hover:border-indigo-300 hover:text-indigo-500 hover:bg-indigo-50/50 transition-all group"
            >
              <div className="p-3 bg-white rounded-full shadow-sm group-hover:shadow-md transition-all">
                <Plus size={24} />
              </div>
              <span className="text-sm font-bold uppercase tracking-wide">Thêm học sinh mới</span>
            </button>
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center">
        <div className="max-w-7xl mx-auto px-6">
          <div className="inline-flex flex-col items-center gap-4 bg-white px-12 py-8 rounded-3xl shadow-sm border border-slate-100">
            <div className="text-[10px] font-black text-slate-900 uppercase tracking-[0.3em]">Hệ thống hỗ trợ sư phạm chuyên dụng</div>
            <div className="flex items-center gap-6">
               <div className="w-12 h-px bg-slate-200"></div>
               <div className="text-sm font-black italic text-indigo-600">Nguyễn Đức Hùng</div>
               <div className="w-12 h-px bg-slate-200"></div>
            </div>
            <p className="text-[10px] text-slate-400 font-bold uppercase">Trường PTDTBT Tiểu học Nấm Dẩn - Xín Mần - Hà Giang</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Trash2, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  XCircle,
  Table as TableIcon,
  AlignLeft,
  Search,
  User
} from 'lucide-react';
import * as XLSX from 'xlsx';

const INITIAL_DATA = [
  { stt: 1, hoTen: "Nguyễn Văn A", ngaySinh: "10/05/2015", diem: 9 },
  { stt: 2, hoTen: "Trần Thị B", ngaySinh: "12/08/2015", diem: 8 },
  { stt: 3, hoTen: "Lê Văn C", ngaySinh: "20/01/2015", diem: 7 },
  { stt: 4, hoTen: "Phạm Minh D", ngaySinh: "15/03/2015", diem: 5 },
  { stt: 5, hoTen: "Hoàng Anh E", ngaySinh: "05/12/2015", diem: 4 }
];

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>('table');
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    let processed = records.map(record => {
      const level = record.mucDo || (record.diem >= 9 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;
      const code = `${abbr}${counters[level]}${level}`;
      return { ...record, maNhanXet: code };
    });

    if (searchTerm) {
      processed = processed.filter(r => 
        r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.noiDung.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    return processed;
  }, [records, selectedSubject, searchTerm]);

  useEffect(() => {
    const initialRecords: StudentRecord[] = INITIAL_DATA.map((item) => ({
      ...item,
      mucDo: item.diem >= 9 ? 'T' : item.diem >= 5 ? 'H' : 'C',
      maNhanXet: '',
      noiDung: '',
      isProcessing: false,
    }));
    setRecords(initialRecords);
  }, []);

  const handleUpdateField = (stt: number, field: keyof StudentRecord, value: any) => {
    setRecords(prev => prev.map(r => {
      if (r.stt === stt) {
        if (field === 'diem') {
          const val = Math.min(10, Math.max(0, parseFloat(value) || 0));
          return { ...r, diem: val, mucDo: val >= 9 ? 'T' : val >= 5 ? 'H' : 'C' };
        }
        return { ...r, [field]: value };
      }
      return r;
    }));
  };

  const generateSingleComment = async (stt: number) => {
    const record = records.find(r => r.stt === stt);
    if (!record || record.isProcessing) return;

    setRecords(prev => prev.map(r => r.stt === stt ? { ...r, isProcessing: true } : r));

    try {
      const results = await generateComments([record], selectedSubject, selectedGrade);
      if (results.length > 0) {
        setRecords(prev => prev.map(r => r.stt === stt ? { ...r, ...results[0], isProcessing: false } : r));
      } else {
        setRecords(prev => prev.map(r => r.stt === stt ? { ...r, isProcessing: false } : r));
      }
    } catch (error) {
      setNotification({ type: 'error', message: `Lỗi khi tạo nhận xét cho STT ${stt}` });
      setRecords(prev => prev.map(r => r.stt === stt ? { ...r, isProcessing: false } : r));
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        const newRecords = data.slice(1).map((row, idx) => ({
          stt: idx + 1,
          hoTen: String(row[1] || "Học sinh"),
          ngaySinh: String(row[2] || ""),
          diem: parseFloat(row[3]) || 0,
          mucDo: (parseFloat(row[3]) || 0) >= 9 ? 'T' : (parseFloat(row[3]) || 0) >= 5 ? 'H' : 'C',
          maNhanXet: '',
          noiDung: '',
          isProcessing: false,
        }));
        setRecords(newRecords);
        setNotification({ type: 'success', message: 'Tải file và tự động phân loại mức đạt thành công!' });
      } catch (err) {
        setNotification({ type: 'error', message: 'Lỗi đọc file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const processGeneration = async () => {
    if (isGenerating) return;
    setIsGenerating(true);
    setNotification(null);

    const targetRecords = records.filter(r => !r.noiDung);
    const toProcess = targetRecords.length > 0 ? targetRecords : records;

    setRecords(prev => prev.map(r => toProcess.some(tp => tp.stt === r.stt) ? { ...r, isProcessing: true } : r));

    try {
      const results = await generateComments(toProcess, selectedSubject, selectedGrade);
      setRecords(prev => prev.map(original => {
        const found = results.find(r => r.stt === original.stt);
        return found ? { ...original, ...found, isProcessing: false } : { ...original, isProcessing: false };
      }));
      setNotification({ type: 'success', message: 'Hoàn tất cập nhật nội dung nhận xét mới!' });
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi kết nối AI.' });
      setRecords(prev => prev.map(r => ({ ...r, isProcessing: false })));
    } finally {
      setIsGenerating(false);
    }
  };

  const exportToExcel = () => {
    const dataToExport = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Họ và tên': r.hoTen,
      'Mức đạt': r.mucDo,
      'Điểm': r.diem,
      'Mã NX': r.maNhanXet,
      'Nội dung nhận xét': r.noiDung
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NhanXet");
    XLSX.writeFile(wb, `PhieuNhanXet_${selectedSubject}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">N.Đ.Hùng - Tiểu học Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
              onChange={(e) => setSelectedGrade(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none"
            >
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>

            <select 
              value={selectedSubject}
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none"
            >
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold"
            >
              <Upload size={18} />
              Tải điểm
            </button>

            <button 
              onClick={processGeneration} 
              disabled={isGenerating || records.length === 0}
              className="inline-flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md active:scale-95 disabled:opacity-50 text-sm font-bold"
            >
              {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              Tạo nhận xét
            </button>

            <button 
              onClick={exportToExcel} 
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất File
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex w-full sm:w-auto">
            <button 
              onClick={() => setViewMode('table')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <TableIcon size={18} />
              Bảng nhận xét
            </button>
            <button 
              onClick={() => setViewMode('content')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <AlignLeft size={18} />
              Nội dung nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm kiếm..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm"
            />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto font-bold">&times;</button>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
          {viewMode === 'table' ? (
            /* BẢNG NHẬN XÉT ĐẦY ĐỦ */
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider text-center border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-4 w-12">STT</th>
                    <th className="px-6 py-4 text-left">Học sinh</th>
                    <th className="px-4 py-4 w-28">Mức đạt</th>
                    <th className="px-4 py-4 w-20">Điểm</th>
                    <th className="px-4 py-4 w-24">Mã NX</th>
                    <th className="px-6 py-4 text-left">Nhận xét tóm lược</th>
                    <th className="px-4 py-4 w-16"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {calculatedRecords.map((record) => (
                    <tr key={record.stt} className={`hover:bg-slate-50 transition-colors ${record.isProcessing ? 'bg-indigo-50/30' : ''}`}>
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-400">{record.stt}</td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-bold">{record.hoTen}</div>
                        <div className="text-[10px] text-slate-400">{record.ngaySinh}</div>
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border ${
                          record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                          record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'
                        }`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center">
                        <input 
                          type="number" 
                          value={record.diem}
                          onChange={(e) => handleUpdateField(record.stt, 'diem', e.target.value)}
                          className="w-12 text-center text-sm font-bold bg-slate-100 rounded py-1 outline-none"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600">
                          {record.maNhanXet}
                        </span>
                      </td>
                      <td className="px-6 py-4 relative">
                        <p className="text-xs text-slate-600 line-clamp-2 italic">
                          {record.noiDung || "Đang chờ dữ liệu..."}
                        </p>
                        {record.isProcessing && (
                          <div className="absolute inset-0 bg-white/60 flex items-center justify-center">
                            <Loader2 size={16} className="text-indigo-600 animate-spin" />
                          </div>
                        )}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button 
                          onClick={() => generateSingleComment(record.stt)}
                          className="p-1.5 text-slate-300 hover:text-indigo-600"
                        >
                          <RefreshCw size={14} className={record.isProcessing ? 'animate-spin' : ''} />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            /* BẢNG NỘI DUNG NHẬN XÉT (CHỈ MÃ VÀ NỘI DUNG) */
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider border-b border-slate-200">
                  <tr>
                    <th className="px-6 py-5 w-32 text-center">Mã nhận xét</th>
                    <th className="px-6 py-5">Nội dung nhận xét (Theo TT 27)</th>
                    <th className="px-6 py-5 w-20 text-center">Thao tác</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {calculatedRecords.map((record) => (
                    <tr key={record.stt} className={`group hover:bg-indigo-50/10 transition-colors ${record.isProcessing ? 'bg-indigo-50/30' : ''}`}>
                      <td className="px-6 py-6 text-center align-top">
                        <div className="flex flex-col items-center gap-2">
                          <span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg">
                            {record.maNhanXet}
                          </span>
                          <span className="text-[9px] text-slate-400 font-bold uppercase truncate max-w-[80px]">
                             {record.hoTen}
                          </span>
                        </div>
                      </td>
                      <td className="px-6 py-6 relative">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => handleUpdateField(record.stt, 'noiDung', e.target.value)}
                          placeholder="Chưa có nội dung. Hãy nhấn 'Tạo nhận xét' hoặc tải file điểm."
                          className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] focus:ring-2 focus:ring-indigo-100 outline-none transition-all resize-none shadow-sm"
                        />
                        {record.isProcessing && (
                          <div className="absolute inset-0 bg-white/40 flex items-center justify-center rounded-xl backdrop-blur-[1px]">
                            <div className="flex items-center gap-2 px-4 py-2 bg-white rounded-full shadow-lg border border-indigo-50">
                              <Loader2 size={16} className="text-indigo-600 animate-spin" />
                              <span className="text-[10px] font-black text-indigo-600 uppercase">Đang soạn thảo...</span>
                            </div>
                          </div>
                        )}
                      </td>
                      <td className="px-6 py-6 text-center align-top">
                        <button 
                          onClick={() => generateSingleComment(record.stt)}
                          title="Tạo lại nhận xét này"
                          className="p-3 text-slate-300 hover:text-indigo-600 hover:bg-white rounded-xl shadow-sm transition-all"
                        >
                          <RefreshCw size={18} className={record.isProcessing ? 'animate-spin' : ''} />
                        </button>
                      </td>
                    </tr>
                  ))}
                  {calculatedRecords.length === 0 && (
                    <tr>
                      <td colSpan={3} className="px-6 py-20 text-center">
                        <div className="flex flex-col items-center gap-4 text-slate-300">
                          <TableIcon size={48} strokeWidth={1} />
                          <p className="text-sm font-bold uppercase tracking-widest">Không có dữ liệu hiển thị</p>
                        </div>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          )}
          <button 
            onClick={() => setRecords([...records, {
              stt: records.length + 1,
