                    <th className="px-4 py-4 w-12">STT</th>
                    <th className="px-6 py-4 text-left">Học sinh</th>
                    <th className="px-4 py-4 w-28">Mức đạt</th>
                    <th className="px-4 py-4 w-20">Điểm</th>
                    <th className="px-4 py-4 w-24">Mã NX</th>
                    <th className="px-6 py-4 text-left">Nội dung (Tự động từ ngân hàng)</th>
