          <div className="inline-flex flex-col items-center gap-4 bg-white px-12 py-8 rounded-3xl border border-slate-100 shadow-sm">
            <div className="text-[10px] font-black text-slate-900 uppercase tracking-[0.3em]">Hệ thống hỗ trợ sư phạm chuyên dụng</div>
            <div className="flex items-center gap-6">
               <div className="w-12 h-px bg-slate-200"></div>
               <div className="text-sm font-black italic text-indigo-600">Nguyễn Đức Hùng</div>
               <div className="w-12 h-px bg-slate-200"></div>
            </div>
            <p className="text-[10px] text-slate-400 font-bold uppercase">Trường PTDTBT Tiểu học Nấm Dẩn - Xín Mần - Hà Giang</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

