import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên chuyên nghiệp bậc Tiểu học tại Việt Nam, am hiểu sâu sắc Thông tư 27/2020/TT-BGDĐT.
Nhiệm vụ: Viết nhận xét học bạ định kỳ cho môn học.

YÊU CẦU NGHIÊM NGẶT VỀ NỘI DUNG (THEO TT 27):
1. Độ dài: Đúng 2 câu văn, gộp thành một đoạn văn duy nhất.
2. Cấu trúc 2 câu:
   - Câu 1: Đánh giá cụ thể về sự tiến bộ hoặc điểm mạnh trong kiến thức, kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một vấn đề về năng lực/phẩm chất cần rèn luyện thêm và đưa ra biện pháp hỗ trợ cụ thể.
3. QUY ĐỊNH CẤM:
   - KHÔNG sử dụng tên riêng của học sinh.
   - KHÔNG sử dụng từ "em" (viết ẩn chủ ngữ).
   - KHÔNG sử dụng từ "nám".
   - Tuyệt đối không dùng từ ngữ tiêu cực (yếu, kém, lười). 
4. VĂN PHONG: Sát thực tế với mức điểm, khích lệ, mẫu mực sư phạm.
`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Hãy tạo chính xác 30 mẫu nhận xét khác nhau cho môn ${subject}, khối ${gradeLevel}. 
  Yêu cầu phân bổ và nội dung sát với điểm số:
  - 10 mẫu mức "Hoàn thành tốt" (T): Nhận xét sát với năng lực của học sinh đạt điểm 8, 9, 10.
  - 10 mẫu mức "Hoàn thành" (H): Nhận xét sát với năng lực của học sinh đạt điểm 5, 6, 7.
  - 10 mẫu mức "Chưa hoàn thành" (C): Nhận xét sát với năng lực của học sinh đạt điểm 1, 2, 3, 4.

  Mỗi mẫu phải đúng 2 câu, không dùng tên học sinh, không dùng từ "em", không dùng từ "nám". 
  Trả về mảng JSON gồm các đối tượng { mucDo: "T"|"H"|"C", noiDung: "chuỗi nhận xét" }.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error) {
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Môn: ${subject}. Khối: ${gradeLevel}. Viết nhận xét 2 câu cho các học sinh có mức độ: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>('table');
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Logic tính toán bảng chính - ưu tiên dữ liệu từ file upload
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      // Xác định mức độ dựa trên điểm số nếu chưa có
      const level = record.mucDo || (record.diem >= 8 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      counters[level]++;

      // Tạo mã NX nếu chưa có
      const generatedCode = `${abbr}${counters[level]}${level}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng nếu chưa có nội dung nhận xét trong file
      const levelGroup = commentBank.filter(b => b.mucDo === level);
      let content = record.noiDung;

      if (!content && levelGroup.length > 0) {
        const bankIndex = (counters[level] - 1) % levelGroup.length;
        content = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: content };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng 30 mã nhận xét (10 mã/loại) sát với điểm số!' });
      }
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi khi kết nối AI tạo ngân hàng mã.' });
    } finally {
      setIsGeneratingBank(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'File Excel không hợp lệ hoặc thiếu dữ liệu.' });
          return;
        }

        // --- Tìm vị trí các cột dựa trên tiêu đề ---
        let sttIdx = -1, nameIdx = -1, levelIdx = -1, scoreIdx = -1, codeIdx = -1, contentIdx = -1;

        // Tìm dòng chứa tiêu đề (thường là dòng 0-3)
        let headerRowIdx = 0;
        for (let i = 0; i < Math.min(data.length, 5); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());
          const hasName = row.some(c => c.includes('họ') || c.includes('tên') || c === 'học sinh');
          const hasScore = row.some(c => c.includes('điểm') || c.includes('ktđk'));

          if (hasName && hasScore) {
            headerRowIdx = i;
            sttIdx = row.findIndex(c => c === 'stt' || c.includes('số tt'));
            nameIdx = row.findIndex(c => c.includes('họ') || c.includes('tên') || c === 'học sinh');
            levelIdx = row.findIndex(c => c.includes('mức đạt') || c.includes('xếp loại'));
            scoreIdx = row.findIndex(c => c.includes('điểm') || c.includes('ktđk'));
            codeIdx = row.findIndex(c => c.includes('mã nx') || c.includes('mã nhận xét'));
            contentIdx = row.findIndex(c => c.includes('nội dung') || c.includes('nhận xét'));
            break;
          }
        }

        // Mặc định nếu không tìm thấy tự động
        if (nameIdx === -1) nameIdx = 1;
        if (scoreIdx === -1) scoreIdx = 3;

        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => row[nameIdx] && String(row[nameIdx]).trim() !== "")
          .map((row, idx) => {
            const rawScore = row[scoreIdx];
            const score = typeof rawScore === 'number' ? rawScore : parseFloat(String(rawScore)) || 0;

            let mucDo = "";
            if (levelIdx !== -1 && row[levelIdx]) {
              const val = String(row[levelIdx]).toUpperCase();
              if (val.includes('TỐT') || val === 'T') mucDo = 'T';
              else if (val.includes('CHƯA') || val === 'C') mucDo = 'C';
              else if (val.includes('HOÀN THÀNH') || val === 'H') mucDo = 'H';
            }
            if (!mucDo) mucDo = score >= 8 ? 'T' : score >= 5 ? 'H' : 'C';

            return {
              stt: sttIdx !== -1 ? parseInt(String(row[sttIdx])) || (idx + 1) : (idx + 1),
              hoTen: String(row[nameIdx]).trim(),
              ngaySinh: "", // Tạm thời để trống
              diem: score,
              mucDo: mucDo,
              maNhanXet: codeIdx !== -1 ? String(row[codeIdx] || "").trim() : "",
              noiDung: contentIdx !== -1 ? String(row[contentIdx] || "").trim() : "",
              isProcessing: false,
            };
          });

        setRecords(newRecords);
        setNotification({ type: 'success', message: `Đã tải ${newRecords.length} học sinh. Các cột STT, Học sinh, Điểm, Mã NX và Nhận xét đã được đồng bộ!` });
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi định dạng file Excel. Vui lòng kiểm tra tiêu đề các cột.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = calculatedRecords.map(r => ({
      'STT': r.stt,
      'Học sinh': r.hoTen,
      'Mức đạt': r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      'Điểm': r.diem,
      'Mã NX': r.maNhanXet,
      'Nội dung nhận xét (Theo mã NX)': r.noiDung
    }));
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangNhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters = { T: 0, H: 0, C: 0 };
    const data = commentBank.map(b => {
      counters[b.mucDo]++;
      return {
        'Mã nhận xét': `${abbr}${counters[b.mucDo]}${b.mucDo}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Phân loại điểm': b.mucDo === 'T' ? '8-10đ' : b.mucDo === 'H' ? '5-7đ' : '1-4đ',
        'Nội dung mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
