  const handleClearData = () => {
    if (window.confirm("Xóa toàn bộ danh sách hiện tại?")) setRecords([]);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">N.Đ.Hùng - Tiểu học Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer">
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>
            <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer">
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>
            <button onClick={handleGenerateBank} disabled={isGeneratingBank} className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-all shadow-md text-sm font-bold disabled:opacity-50">
              {isGeneratingBank ? <Loader2 size={18} className="animate-spin" /> : <Database size={18} />}
