            <button onClick={viewMode === 'table' ? exportTableToExcel : exportBankToExcel} className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold">
