                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border uppercase ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-bold text-slate-600 border-r border-slate-50">{record.diem}</td>
                      <td className="px-4 py-4 text-center border-r border-slate-50">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))}
                          placeholder="Chưa có nội dung..."
                          className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] leading-relaxed outline-none focus:ring-1 focus:ring-indigo-100 rounded"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button 
                          onClick={() => setRecords(records.filter(r => r.stt !== record.stt))}
                          className="p-1.5 text-slate-200 hover:text-rose-500 transition-colors"
                        >
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={8} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                        <Upload size={48} strokeWidth={1.5} />
                        <p className="text-sm font-bold uppercase tracking-widest">Hãy tải file điểm để bắt đầu</p>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex flex-col">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-5 w-32 text-center">Mã nhận xét</th>
                      <th className="px-6 py-5 w-48 text-center">Mức đạt (Điểm)</th>
                      <th className="px-6 py-5">Nội dung mẫu (Đúng 2 câu)</th>
                      <th className="px-4 py-5 w-12"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {commentBank.map((item, index) => {
                      const abbr = getSubjectAbbr(selectedSubject);
                      const sameLevelCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo).length;
                      const displayCode = `${abbr}${sameLevelCount}${item.mucDo}`;
                      return (
                        <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                          <td className="px-6 py-6 text-center align-top">
                            <span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg shadow-sm">
                              {displayCode}
                            </span>
                          </td>
                          <td className="px-6 py-6 text-center align-top">
                            <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${
                              item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                              item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'
                            }`}>
                              {item.mucDo === 'T' ? 'HT Tốt (8-10đ)' : item.mucDo === 'H' ? 'H.Thành (5-7đ)' : 'C.H.Thành (1-4đ)'}
                            </span>
                          </td>
                          <td className="px-6 py-6">
                            <textarea 
                              value={item.noiDung}
                              onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))}
                              className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] outline-none transition-all resize-none shadow-sm"
                            />
                          </td>
                          <td className="px-4 py-6 text-center align-top">
                             <button 
                               onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))}
                               className="p-2 text-slate-200 hover:text-rose-500"
                             >
                               <Trash2 size={16} />
                             </button>
                          </td>
                        </tr>
                      );
                    })}
                    {commentBank.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                          <Database size={48} strokeWidth={1.5} />
                          <p className="text-sm font-bold uppercase tracking-widest">Ngân hàng mã trống. Hãy nhấn "Tạo 30 mã NX"</p>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
              {commentBank.length > 0 && (
                <div className="p-8 flex justify-center bg-slate-50/50">
                  <button onClick={exportBankToExcel} className="inline-flex items-center gap-3 px-8 py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-all shadow-lg active:scale-95 font-black uppercase text-sm tracking-wider">
                    <FileSpreadsheet size={20} /> Tải ngân hàng mã nhận xét (.xlsx)
                  </button>
                </div>
              )}
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-100">
            <button 
              onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 10, mucDo: 'T', maNhanXet: '', noiDung: '', isProcessing: false }])}
              className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
            >
              <Plus size={16} /> Thêm học sinh
            </button>
            {records.length > 0 && (
              <button 
                onClick={handleClearData}
                className="px-4 py-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
              >
                <Trash2 size={16} /> Xóa danh sách
              </button>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        Trường PTDTBT Tiểu học Nấm Dẩn - Xín Mần - Hà Giang
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      // Xác định mức độ (ưu tiên dữ liệu từ file)
      const level = record.mucDo || (record.diem >= 8 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      if (counters[level] !== undefined) {
        counters[level]++;
      }

      // Tạo mã nhận xét tự động nếu chưa có
      const generatedCode = `${abbr}${counters[level]}${level}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu nếu nội dung hiện tại đang trống
      const levelGroup = commentBank.filter(b => b.mucDo === level);
      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[level] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng 30 mã nhận xét (10 mã/loại)!' });
      }
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
    } finally {
      setIsGeneratingBank(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'File không có dữ liệu học sinh.' });
          return;
        }

        // --- NHẬN DIỆN CỘT DỮ LIỆU ---
        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        // Quét tìm dòng tiêu đề chứa các từ khóa chính xác
        for (let i = 0; i < Math.min(data.length, 30); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());

          row.forEach((cell, colIdx) => {
            // Chỉ lấy dữ liệu Giữa kỳ, bỏ qua cột cuối kỳ
            if (!cell.includes('cuối')) {
              if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;
              if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên học sinh')) nameIdx = colIdx;
              if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;
              if (scoreIdx === -1 && (cell.includes('điểm ktđk') || (cell === 'điểm' && !cell.includes('miệng')) || cell.includes('điểm giữa kỳ'))) scoreIdx = colIdx;
              if (levelIdx === -1 && (cell.includes('mức đạt') || cell.includes('đánh giá') || cell.includes('xếp loại'))) levelIdx = colIdx;
            }
          });

          // Tiêu chuẩn tối thiểu: Có Họ tên
          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;

        // --- TRÍCH XUẤT DỮ LIỆU CHÍNH XÁC ---
        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            // Lọc các hàng không phải học sinh (hàng trống, hàng tiêu đề lặp lại, hàng tổng kết)
            return nameVal !== "" && isNaN(parseFloat(nameVal)) && 
                   !nameVal.toLowerCase().includes("họ và tên") &&
                   !nameVal.toLowerCase().includes("danh sách") &&
                   nameVal.length > 2;
          })
          .map((row, idx) => {
            // 1. STT
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }

            // 2. Họ tên
            const hoTen = String(row[nameIdx] || "").trim();

            // 3. Ngày sinh
            let ngaySinh = String(row[birthIdx] || "").trim();
            // Nếu là số serial của Excel, ta cố gắng hiển thị thô (XLSX có thể tự convert nếu dùng cellDates: true nhưng ở đây ta dùng array)

            // 4. Điểm KTĐK (Nhập theo đúng dữ liệu hàng trong file)
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  const strScore = String(rawScore).replace(',', '.');
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }

            // 5. Mức đạt được (Nhập theo đúng dữ liệu hàng trong file)
            let mucDoValue = "";
            if (levelIdx !== -1 && row[levelIdx]) {
              const rawLevel = String(row[levelIdx]).trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT') mucDoValue = 'T';
              else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT') mucDoValue = 'C';
              else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') mucDoValue = 'H';
            }

            // Nếu file không có cột mức đạt, tính từ điểm KTĐK vừa lấy
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 8 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }

            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ 
            type: 'success', 
            message: `Đã nhập dữ liệu cho ${newRecords.length} học sinh. Các cột STT, Họ tên, Ngày sinh, Điểm KTĐK và Mức đạt được đã được copy chính xác từ file!` 
          });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh trong file. Vui lòng kiểm tra lại cột Họ và tên.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel. Vui lòng đảm bảo file không bị khóa hoặc lỗi định dạng.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Giữa học kỳ I", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
