export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      // Xác định mức độ (ưu tiên dữ liệu từ file, nếu không có mới tính toán)
      const level = record.mucDo || (record.diem >= 8 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      if (counters[level] !== undefined) {
        counters[level]++;
      }

      // Tạo mã nhận xét tự động nếu chưa có
      const generatedCode = `${abbr}${counters[level]}${level}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu nếu nội dung hiện tại đang trống
      const levelGroup = commentBank.filter(b => b.mucDo === level);
      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[level] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng 30 mã nhận xét (10 mã/loại)!' });
      }
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
    } finally {
      setIsGeneratingBank(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        // Đọc dữ liệu thô để xử lý chính xác nhất
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'File không có dữ liệu học sinh.' });
          return;
        }

        // --- NHẬN DIỆN CỘT DỮ LIỆU ---
        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        // Quét tìm dòng tiêu đề chứa các từ khóa chính xác nhất
        // Chúng ta quét sâu hơn (đến hàng 40) để tránh các tiêu đề trang trí lớn
        for (let i = 0; i < Math.min(data.length, 40); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());

          row.forEach((cell, colIdx) => {
            // Loại trừ các cột chứa từ "cuối" để ưu tiên lấy dữ liệu Giữa Kỳ
            if (!cell.includes('cuối')) {
              // Nhận diện cột STT
              if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;

              // Nhận diện cột Họ và Tên
              if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên học sinh' || cell === 'tên')) nameIdx = colIdx;

              // Nhận diện cột Ngày sinh
              if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;

              // NHẬN DIỆN CỘT ĐIỂM KTĐK (Rất quan trọng)
              if (scoreIdx === -1 && (
                cell.includes('điểm ktđk') || 
                cell.includes('điểm thi') || 
                cell.includes('điểm giữa') ||
                cell.includes('điểm kt') ||
                (cell === 'điểm' && !cell.includes('miệng') && !cell.includes('thường xuyên'))
              )) scoreIdx = colIdx;

              // Nhận diện cột Mức đạt được
              if (levelIdx === -1 && (cell.includes('mức đạt') || cell.includes('đánh giá') || cell.includes('xếp loại'))) levelIdx = colIdx;
            }
          });

          // Tiêu chuẩn vàng: Phải có ít nhất cột Tên và cột Điểm (hoặc cột Mức đạt)
          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) headerRowIdx = 0;

        // --- SAO CHÉP DỮ LIỆU CHÍNH XÁC 100% ---
        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            // Lọc hàng rác: Phải có tên học sinh, không phải hàng tiêu đề, không phải hàng tổng hợp
            return nameVal !== "" && 
                   isNaN(parseFloat(nameVal)) && 
                   !nameVal.toLowerCase().includes("họ và tên") &&
                   !nameVal.toLowerCase().includes("danh sách") &&
                   !nameVal.toLowerCase().includes("trường") &&
                   nameVal.length > 2;
          })
          .map((row, idx) => {
            // 1. Lấy STT
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }

            // 2. Lấy Họ tên
            const hoTen = String(row[nameIdx] || "").trim();

            // 3. Lấy Ngày sinh
            const ngaySinh = String(row[birthIdx] || "").trim();

            // 4. LẤY ĐIỂM KTĐK (SAO CHÉP CHÍNH XÁC)
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  // Xử lý chuỗi điểm (ví dụ: "8,5" thành 8.5)
                  const strScore = String(rawScore).replace(',', '.').trim();
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }

            // 5. Lấy Mức đạt được (Sao chép và chuẩn hóa)
            let mucDoValue = "";
            if (levelIdx !== -1 && row[levelIdx]) {
              const rawLevel = String(row[levelIdx]).trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT') mucDoValue = 'T';
              else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT') mucDoValue = 'C';
              else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') mucDoValue = 'H';
            }

            // Nếu cột mức đạt trống, tính toán dựa trên điểm KTĐK vừa lấy được
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 8 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }

            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ 
            type: 'success', 
            message: `Hệ thống đã sao chép chính xác 100% Điểm KTĐK cho ${newRecords.length} học sinh từ file của bạn!` 
          });
        } else {
          setNotification({ type: 'error', message: 'Không thể trích xuất dữ liệu. Vui lòng kiểm tra lại cấu trúc file Excel.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel. Hãy đảm bảo bạn đã đóng file trước khi tải lên.' });
      }
    };
    reader.readAsBinaryString(file);
    // Reset file input để có thể tải lên lại cùng một file nếu cần
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Giữa học kỳ I", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
    const headerRow3 = ["", "", "", "", "", "Mã nhận xét", "Nội dung"];

    const dataRows = calculatedRecords.map(r => [
      r.stt,
      r.hoTen,
      r.ngaySinh,
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);

    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);

    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangDiem_NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters = { T: 0, H: 0, C: 0 };
    const data = commentBank.map(b => {
      if (counters[b.mucDo] !== undefined) {
        counters[b.mucDo]++;
      }
      return {
        'Mã nhận xét': `${abbr}${counters[b.mucDo]}${b.mucDo}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.mucDo === 'T' ? '8, 9, 10' : b.mucDo === 'H' ? '5, 6, 7' : '1, 2, 3, 4',
        'Nội dung nhận xét mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => {
    if (window.confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) {
      setRecords([]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">N.Đ.Hùng - Tiểu học Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
              onChange={(e) => setSelectedGrade(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>

            <select 
              value={selectedSubject}
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>

            <button 
              onClick={handleGenerateBank} 
              disabled={isGeneratingBank}
              className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-all shadow-md active:scale-95 text-sm font-bold disabled:opacity-50"
            >
              {isGeneratingBank ? <Loader2 size={18} className="animate-spin" /> : <Database size={18} />}
              Tạo 30 mã NX
            </button>

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold"
            >
              <Upload size={18} />
              Tải file điểm
            </button>

            <button 
              onClick={viewMode === 'table' ? exportTableToExcel : exportBankToExcel} 
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex w-full sm:w-auto">
            <button 
              onClick={() => setViewMode('table')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <TableIcon size={18} /> Bảng nhận xét
            </button>
            <button 
              onClick={() => setViewMode('content')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <FileJson size={18} /> Mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm nhanh..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm"
            />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in duration-300 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto font-bold p-1">&times;</button>
          </div>
        )}

        {viewMode === 'table' && (
          <div className="mb-6 p-6 bg-white rounded-2xl border border-slate-100 shadow-sm text-center">
             <div className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-1">UBND Xã Nấm Dẩn - Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">
               ĐÁNH GIÁ ĐỊNH KỲ MÔN HỌC {selectedSubject.toUpperCase()}
             </h2>
             <div className="text-sm font-bold text-slate-600 mt-1 uppercase">
               LỚP: {selectedGrade.replace('Khối ', '')}B - NĂM HỌC: 2025-2026
             </div>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center border-b border-slate-200">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12 border-r border-slate-200">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64 border-r border-slate-200">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32 border-r border-slate-200">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 border-b border-slate-200 bg-slate-100/50">Giữa học kỳ I</th>
                    <th rowSpan={3} className="px-4 py-3 w-16"></th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-36 border-r border-slate-200">Mức đạt được</th>
                    <th rowSpan={2} className="px-4 py-2 w-24 border-r border-slate-200">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nhận xét điểm mạnh và các mặt cần rèn luyện</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-32 border-r border-slate-200 border-t border-slate-200">Mã nhận xét</th>
                    <th className="px-6 py-2 border-t border-slate-200 text-left">Nội dung</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-400 border-r border-slate-50">{record.stt}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-900 border-r border-slate-50">{record.hoTen}</td>
                      <td className="px-4 py-4 text-sm text-slate-500 border-r border-slate-50">{record.ngaySinh}</td>
                      <td className="px-4 py-4 text-center border-r border-slate-50">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border uppercase ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-bold text-slate-600 border-r border-slate-50">
                        {record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)}
                      </td>
                      <td className="px-4 py-4 text-center border-r border-slate-50">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))}
                          placeholder="Chưa có nội dung..."
                          className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] leading-relaxed outline-none focus:ring-1 focus:ring-indigo-100 rounded"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button 
                          onClick={() => setRecords(records.filter(r => r.stt !== record.stt))}
                          className="p-1.5 text-slate-200 hover:text-rose-500 transition-colors"
                        >
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={8} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                        <Upload size={48} strokeWidth={1.5} />
                        <p className="text-sm font-bold uppercase tracking-widest">Hãy tải file điểm để bắt đầu</p>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex flex-col">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-5 w-32 text-center">Mã nhận xét</th>
                      <th className="px-6 py-5 w-48 text-center">Mức đạt (Điểm)</th>
                      <th className="px-6 py-5">Nội dung mẫu (Đúng 2 câu)</th>
                      <th className="px-4 py-5 w-12"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {commentBank.map((item, index) => {
                      const abbr = getSubjectAbbr(selectedSubject);
                      const sameLevelCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo).length;
                      const displayCode = `${abbr}${sameLevelCount}${item.mucDo}`;
                      return (
                        <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                          <td className="px-6 py-6 text-center align-top">
                            <span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg shadow-sm">
                              {displayCode}
                            </span>
                          </td>
                          <td className="px-6 py-6 text-center align-top">
                            <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${
                              item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                              item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'
                            }`}>
                              {item.mucDo === 'T' ? 'HT Tốt (8-10đ)' : item.mucDo === 'H' ? 'H.Thành (5-7đ)' : 'C.H.Thành (1-4đ)'}
                            </span>
                          </td>
                          <td className="px-6 py-6">
                            <textarea 
                              value={item.noiDung}
                              onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))}
                              className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] outline-none transition-all resize-none shadow-sm"
                            />
                          </td>
                          <td className="px-4 py-6 text-center align-top">
                             <button 
                               onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))}
                               className="p-2 text-slate-200 hover:text-rose-500"
                             >
                               <Trash2 size={16} />
                             </button>
                          </td>
                        </tr>
                      );
                    })}
                    {commentBank.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                          <Database size={48} strokeWidth={1.5} />
                          <p className="text-sm font-bold uppercase tracking-widest">Ngân hàng mã trống. Hãy nhấn "Tạo 30 mã NX"</p>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
              {commentBank.length > 0 && (
                <div className="p-8 flex justify-center bg-slate-50/50">
                  <button onClick={exportBankToExcel} className="inline-flex items-center gap-3 px-8 py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-all shadow-lg active:scale-95 font-black uppercase text-sm tracking-wider">
                    <FileSpreadsheet size={20} /> Tải ngân hàng mã nhận xét (.xlsx)
                  </button>
                </div>
              )}
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-100">
            <button 
              onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 10, mucDo: 'T', maNhanXet: '', noiDung: '', isProcessing: false }])}
              className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
            >
              <Plus size={16} /> Thêm học sinh
            </button>
            {records.length > 0 && (
              <button 
                onClick={handleClearData}
                className="px-4 py-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
              >
                <Trash2 size={16} /> Xóa danh sách
              </button>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        Trường PTDTBT Tiểu học Nấm Dẩn - Xín Mần - Hà Giang
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      // Xác định mức độ (ưu tiên dữ liệu từ file, nếu không có mới tính toán)
      const level = record.mucDo || (record.diem >= 8 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      if (counters[level] !== undefined) {
        counters[level]++;
      }

      // Tạo mã nhận xét tự động nếu chưa có
      const generatedCode = `${abbr}${counters[level]}${level}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu nếu nội dung hiện tại đang trống
      const levelGroup = commentBank.filter(b => b.mucDo === level);
      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[level] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng 30 mã nhận xét (10 mã/loại)!' });
      }
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
    } finally {
      setIsGeneratingBank(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        // Sử dụng cellText: false để lấy giá trị số thô nếu có thể
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'File không có dữ liệu học sinh.' });
          return;
        }

        // --- NHẬN DIỆN CỘT DỮ LIỆU ---
        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        // Quét tìm dòng tiêu đề chứa các từ khóa chính xác nhất
        for (let i = 0; i < Math.min(data.length, 50); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());

          row.forEach((cell, colIdx) => {
            // Loại bỏ các cột chứa chữ "Cuối" để tránh lấy nhầm cột điểm Cuối học kỳ
            if (!cell.includes('cuối')) {
              // Cột STT
              if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;

              // Cột Họ tên
              if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên học sinh' || cell === 'tên')) nameIdx = colIdx;

              // Cột Ngày sinh
              if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;

              // Cột ĐIỂM KTĐK (Quan trọng nhất)
              // Kiểm tra nhiều biến thể tiêu đề phổ biến trong file Excel giáo viên
              if (scoreIdx === -1 && (
                cell === 'điểm' || 
                cell === 'điểm ktđk' || 
                cell === 'điểm thi' ||
                cell.includes('điểm kiểm tra định kỳ') ||
                cell.includes('điểm ktđk') ||
                cell.includes('điểm giữa') ||
                cell.includes('điểm thi giữa') ||
                (cell.includes('ktđk') && !cell.includes('nhận xét'))
              )) {
                scoreIdx = colIdx;
              }

              // Cột Mức đạt được
              if (levelIdx === -1 && (cell.includes('mức đạt') || cell.includes('đánh giá') || cell.includes('xếp loại'))) levelIdx = colIdx;
            }
          });

          // Nếu tìm thấy cột tên và cột điểm thì dừng lại
          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) {
            setNotification({ type: 'error', message: 'Không tìm thấy tiêu đề cột "Họ tên" hoặc "Điểm" trong file.' });
            return;
        }

        // --- SAO CHÉP DỮ LIỆU ---
        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            // Loại bỏ hàng trống hoặc hàng tiêu đề lặp lại
            return nameVal !== "" && 
                   isNaN(parseFloat(nameVal)) && 
                   nameVal.length > 2 &&
                   !nameVal.toLowerCase().includes("họ và tên");
          })
          .map((row, idx) => {
            // 1. STT
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }

            // 2. Họ tên
            const hoTen = String(row[nameIdx] || "").trim();

            // 3. Ngày sinh
            const ngaySinhVal = row[birthIdx];
            let ngaySinh = "";
            if (ngaySinhVal instanceof Date) {
              ngaySinh = ngaySinhVal.toLocaleDateString('vi-VN');
            } else {
              ngaySinh = String(ngaySinhVal || "").trim();
            }

            // 4. SAO CHÉP CHÍNH XÁC ĐIỂM KTĐK
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  // Xử lý chuỗi (ví dụ giáo viên nhập "8.5" hoặc "8,5")
                  const strScore = String(rawScore).replace(',', '.').trim();
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }

            // 5. Mức đạt được
            let mucDoValue = "";
            if (levelIdx !== -1 && row[levelIdx]) {
              const rawLevel = String(row[levelIdx]).trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT') mucDoValue = 'T';
              else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT') mucDoValue = 'C';
              else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') mucDoValue = 'H';
            }

            // Nếu file không có cột mức đạt, tự động tính từ điểm KTĐK vừa copy
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 8 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }

            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ 
            type: 'success', 
            message: `Thành công! Đã sao chép chính xác 100% Điểm KTĐK cho ${newRecords.length} học sinh.` 
          });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ sau hàng tiêu đề.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi đọc file Excel. Vui lòng kiểm tra định dạng file (.xlsx hoặc .xls).' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Giữa học kỳ I", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
    const headerRow3 = ["", "", "", "", "", "Mã nhận xét", "Nội dung"];

    const dataRows = calculatedRecords.map(r => [
      r.stt,
      r.hoTen,
      r.ngaySinh,
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);

    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);

    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangDiem_NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters = { T: 0, H: 0, C: 0 };
    const data = commentBank.map(b => {
      if (counters[b.mucDo] !== undefined) {
        counters[b.mucDo]++;
      }
      return {
        'Mã nhận xét': `${abbr}${counters[b.mucDo]}${b.mucDo}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.mucDo === 'T' ? '8, 9, 10' : b.mucDo === 'H' ? '5, 6, 7' : '1, 2, 3, 4',
        'Nội dung nhận xét mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => {
    if (window.confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) {
      setRecords([]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">N.Đ.Hùng - Tiểu học Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
              onChange={(e) => setSelectedGrade(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>

            <select 
              value={selectedSubject}
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>

            <button 
              onClick={handleGenerateBank} 
              disabled={isGeneratingBank}
              className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-all shadow-md active:scale-95 text-sm font-bold disabled:opacity-50"
            >
              {isGeneratingBank ? <Loader2 size={18} className="animate-spin" /> : <Database size={18} />}
              Tạo 30 mã NX
            </button>

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold"
            >
              <Upload size={18} />
              Tải file điểm
            </button>

            <button 
              onClick={viewMode === 'table' ? exportTableToExcel : exportBankToExcel} 
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex w-full sm:w-auto">
            <button 
              onClick={() => setViewMode('table')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <TableIcon size={18} /> Bảng nhận xét
            </button>
            <button 
              onClick={() => setViewMode('content')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <FileJson size={18} /> Mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm nhanh..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm"
            />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in duration-300 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto font-bold p-1">&times;</button>
          </div>
        )}

        {viewMode === 'table' && (
          <div className="mb-6 p-6 bg-white rounded-2xl border border-slate-100 shadow-sm text-center">
             <div className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-1">UBND Xã Nấm Dẩn - Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">
               ĐÁNH GIÁ ĐỊNH KỲ MÔN HỌC {selectedSubject.toUpperCase()}
             </h2>
             <div className="text-sm font-bold text-slate-600 mt-1 uppercase">
               LỚP: {selectedGrade.replace('Khối ', '')}B - NĂM HỌC: 2025-2026
             </div>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center border-b border-slate-200">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12 border-r border-slate-200">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64 border-r border-slate-200">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32 border-r border-slate-200">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 border-b border-slate-200 bg-slate-100/50">Giữa học kỳ I</th>
                    <th rowSpan={3} className="px-4 py-3 w-16"></th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-36 border-r border-slate-200">Mức đạt được</th>
                    <th rowSpan={2} className="px-4 py-2 w-24 border-r border-slate-200">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nhận xét điểm mạnh và các mặt cần rèn luyện</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-32 border-r border-slate-200 border-t border-slate-200">Mã nhận xét</th>
                    <th className="px-6 py-2 border-t border-slate-200 text-left">Nội dung</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-400 border-r border-slate-50">{record.stt}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-900 border-r border-slate-50">{record.hoTen}</td>
                      <td className="px-4 py-4 text-sm text-slate-500 border-r border-slate-50">{record.ngaySinh}</td>
                      <td className="px-4 py-4 text-center border-r border-slate-50">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border uppercase ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-bold text-slate-600 border-r border-slate-50">
                        {record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)}
                      </td>
                      <td className="px-4 py-4 text-center border-r border-slate-50">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))}
                          placeholder="Chưa có nội dung..."
                          className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] leading-relaxed outline-none focus:ring-1 focus:ring-indigo-100 rounded"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button 
                          onClick={() => setRecords(records.filter(r => r.stt !== record.stt))}
                          className="p-1.5 text-slate-200 hover:text-rose-500 transition-colors"
                        >
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={8} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                        <Upload size={48} strokeWidth={1.5} />
                        <p className="text-sm font-bold uppercase tracking-widest">Hãy tải file điểm để bắt đầu</p>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex flex-col">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-5 w-32 text-center">Mã nhận xét</th>
                      <th className="px-6 py-5 w-48 text-center">Mức đạt (Điểm)</th>
                      <th className="px-6 py-5">Nội dung mẫu (Đúng 2 câu)</th>
                      <th className="px-4 py-5 w-12"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {commentBank.map((item, index) => {
                      const abbr = getSubjectAbbr(selectedSubject);
                      const sameLevelCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo).length;
                      const displayCode = `${abbr}${sameLevelCount}${item.mucDo}`;
                      return (
                        <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                          <td className="px-6 py-6 text-center align-top">
                            <span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg shadow-sm">
                              {displayCode}
                            </span>
                          </td>
                          <td className="px-6 py-6 text-center align-top">
                            <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${
                              item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                              item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'
                            }`}>
                              {item.mucDo === 'T' ? 'HT Tốt (8-10đ)' : item.mucDo === 'H' ? 'H.Thành (5-7đ)' : 'C.H.Thành (1-4đ)'}
                            </span>
                          </td>
                          <td className="px-6 py-6">
                            <textarea 
                              value={item.noiDung}
                              onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))}
                              className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] outline-none transition-all resize-none shadow-sm"
                            />
                          </td>
                          <td className="px-4 py-6 text-center align-top">
                             <button 
                               onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))}
                               className="p-2 text-slate-200 hover:text-rose-500"
                             >
                               <Trash2 size={16} />
                             </button>
                          </td>
                        </tr>
                      );
                    })}
                    {commentBank.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                          <Database size={48} strokeWidth={1.5} />
                          <p className="text-sm font-bold uppercase tracking-widest">Ngân hàng mã trống. Hãy nhấn "Tạo 30 mã NX"</p>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
              {commentBank.length > 0 && (
                <div className="p-8 flex justify-center bg-slate-50/50">
                  <button onClick={exportBankToExcel} className="inline-flex items-center gap-3 px-8 py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-all shadow-lg active:scale-95 font-black uppercase text-sm tracking-wider">
                    <FileSpreadsheet size={20} /> Tải ngân hàng mã nhận xét (.xlsx)
                  </button>
                </div>
              )}
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-100">
            <button 
              onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 10, mucDo: 'T', maNhanXet: '', noiDung: '', isProcessing: false }])}
              className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
            >
              <Plus size={16} /> Thêm học sinh
            </button>
            {records.length > 0 && (
              <button 
                onClick={handleClearData}
                className="px-4 py-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
              >
                <Trash2 size={16} /> Xóa danh sách
              </button>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        Trường PTDTBT Tiểu học Nấm Dẩn - Xín Mần - Hà Giang
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Lấy số khối từ chuỗi "Khối X"
  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = { T: 0, H: 0, C: 0 };

    return records.map(record => {
      // Xác định mức độ (ưu tiên dữ liệu từ file, nếu không có mới tính toán)
      const level = record.mucDo || (record.diem >= 8 ? 'T' : record.diem >= 5 ? 'H' : 'C');
      if (counters[level] !== undefined) {
        counters[level]++;
      }

      // Tạo mã nhận xét tự động theo định dạng mới: [Môn][Khối][Mức][STT] -> Ví dụ TV2T1
      const generatedCode = `${abbr}${gradeNumber}${level}${counters[level]}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu nếu nội dung hiện tại đang trống
      const levelGroup = commentBank.filter(b => b.mucDo === level);
      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[level] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng 30 mã nhận xét (10 mã/loại)!' });
      }
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
    } finally {
      setIsGeneratingBank(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'File không có dữ liệu học sinh.' });
          return;
        }

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 50); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());
          row.forEach((cell, colIdx) => {
            if (!cell.includes('cuối')) {
              if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;
              if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên học sinh' || cell === 'tên')) nameIdx = colIdx;
              if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;
              if (scoreIdx === -1 && (
                cell === 'điểm' || 
                cell === 'điểm ktđk' || 
                cell === 'điểm thi' ||
                cell.includes('điểm kiểm tra định kỳ') ||
                cell.includes('điểm ktđk') ||
                cell.includes('điểm giữa') ||
                cell.includes('điểm thi giữa') ||
                (cell.includes('ktđk') && !cell.includes('nhận xét'))
              )) {
                scoreIdx = colIdx;
              }
              if (levelIdx === -1 && (cell.includes('mức đạt') || cell.includes('đánh giá') || cell.includes('xếp loại'))) levelIdx = colIdx;
            }
          });
          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) {
            setNotification({ type: 'error', message: 'Không tìm thấy tiêu đề cột "Họ tên" hoặc "Điểm" trong file.' });
            return;
        }

        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            return nameVal !== "" && isNaN(parseFloat(nameVal)) && nameVal.length > 2 && !nameVal.toLowerCase().includes("họ và tên");
          })
          .map((row, idx) => {
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }
            const hoTen = String(row[nameIdx] || "").trim();
            const ngaySinhVal = row[birthIdx];
            let ngaySinh = "";
            if (ngaySinhVal instanceof Date) {
              ngaySinh = ngaySinhVal.toLocaleDateString('vi-VN');
            } else {
              ngaySinh = String(ngaySinhVal || "").trim();
            }
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  const strScore = String(rawScore).replace(',', '.').trim();
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }
            let mucDoValue = "";
            if (levelIdx !== -1 && row[levelIdx]) {
              const rawLevel = String(row[levelIdx]).trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT') mucDoValue = 'T';
              else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT') mucDoValue = 'C';
              else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') mucDoValue = 'H';
            }
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 8 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }
            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ type: 'success', message: `Thành công! Đã sao chép chính xác 100% Điểm KTĐK cho ${newRecords.length} học sinh.` });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ sau hàng tiêu đề.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi đọc file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Giữa học kỳ I", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
    const headerRow3 = ["", "", "", "", "", "Mã nhận xét", "Nội dung"];
    const dataRows = calculatedRecords.map(r => [
      r.stt,
      r.hoTen,
      r.ngaySinh,
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);
    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangDiem_NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters = { T: 0, H: 0, C: 0 };
    const data = commentBank.map(b => {
      if (counters[b.mucDo] !== undefined) {
        counters[b.mucDo]++;
      }
      return {
        'Mã nhận xét': `${abbr}${gradeNumber}${b.mucDo}${counters[b.mucDo]}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.mucDo === 'T' ? '8, 9, 10' : b.mucDo === 'H' ? '5, 6, 7' : '1, 2, 3, 4',
        'Nội dung nhận xét mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => {
    if (window.confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) {
      setRecords([]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">N.Đ.Hùng - Tiểu học Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
              onChange={(e) => setSelectedGrade(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>

            <select 
              value={selectedSubject}
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>

            <button 
              onClick={handleGenerateBank} 
              disabled={isGeneratingBank}
              className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-all shadow-md active:scale-95 text-sm font-bold disabled:opacity-50"
            >
              {isGeneratingBank ? <Loader2 size={18} className="animate-spin" /> : <Database size={18} />}
              Tạo 30 mã NX
            </button>

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold"
            >
              <Upload size={18} />
              Tải file điểm
            </button>

            <button 
              onClick={viewMode === 'table' ? exportTableToExcel : exportBankToExcel} 
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex w-full sm:w-auto">
            <button 
              onClick={() => setViewMode('table')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <TableIcon size={18} /> Bảng nhận xét
            </button>
            <button 
              onClick={() => setViewMode('content')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <FileJson size={18} /> Mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm nhanh..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm"
            />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in duration-300 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto font-bold p-1">&times;</button>
          </div>
        )}

        {viewMode === 'table' && (
          <div className="mb-6 p-6 bg-white rounded-2xl border border-slate-300 shadow-sm text-center">
             <div className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-1">UBND Xã Nấm Dẩn - Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">
               ĐÁNH GIÁ ĐỊNH KỲ MÔN HỌC {selectedSubject.toUpperCase()}
             </h2>
             <div className="text-sm font-bold text-slate-600 mt-1 uppercase">
               LỚP: {selectedGrade.replace('Khối ', '')}B - NĂM HỌC: 2025-2026
             </div>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
