import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên chuyên nghiệp bậc Tiểu học tại Việt Nam, am hiểu sâu sắc Thông tư 27/2020/TT-BGDĐT.
Nhiệm vụ: Viết nhận xét học bạ định kỳ cho môn học.

YÊU CẦU NGHIÊM NGẶT VỀ NỘI DUNG (THEO TT 27):
1. Độ dài: Đúng 2 câu văn, gộp thành một đoạn văn duy nhất.
2. Cấu trúc 2 câu:
   - Câu 1: Đánh giá cụ thể về sự tiến bộ hoặc điểm mạnh trong kiến thức, kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một vấn đề về năng lực/phẩm chất cần rèn luyện thêm và đưa ra biện pháp hỗ trợ cụ thể.
3. QUY ĐỊNH CẤM:
   - KHÔNG sử dụng tên riêng của học sinh.
   - KHÔNG sử dụng từ "em" (viết ẩn chủ ngữ).
   - KHÔNG sử dụng từ "nám".
   - Tuyệt đối không dùng từ ngữ tiêu cực (yếu, kém, lười). 
4. VĂN PHONG: Sát thực tế với mức điểm, khích lệ, mẫu mực sư phạm.
`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Hãy tạo chính xác 30 mẫu nhận xét KHÁC NHAU hoàn toàn cho môn ${subject}, khối ${gradeLevel}. 
  Yêu cầu phân bổ nội dung CỰC KỲ SÁT với từng đầu điểm như sau:

  1. Mức "Hoàn thành tốt" (T) - 10 mẫu:
     - Phân bổ cho các điểm 7, 8, 9, 10. 
     - Nội dung cho điểm 7-8 cần nhấn mạnh sự nỗ lực và tiến bộ rõ rệt.
     - Nội dung cho điểm 9-10 cần nhấn mạnh sự sáng tạo, nắm vững kiến thức chuyên sâu và kỹ năng thành thạo.

  2. Mức "Hoàn thành" (H) - 10 mẫu:
     - Phân bổ cho các điểm 5, 6.
     - Nội dung cần ghi nhận việc hoàn thành các yêu cầu cơ bản, nắm được kiến thức trọng tâm nhưng cần rèn luyện thêm tính cẩn thận hoặc tốc độ làm bài.

  3. Mức "Chưa hoàn thành" (C) - 10 mẫu:
     - Phân bổ cho các điểm 3, 4.
     - Nội dung cần nhẹ nhàng, khích lệ, chỉ ra đúng lỗ hổng kiến thức và đưa ra biện pháp giúp đỡ cụ thể (như tăng cường đọc sách, làm bài tập tương tự, hoặc cần sự hỗ trợ từ gia đình).

  LƯU Ý: Mỗi mẫu đúng 2 câu, không dùng tên học sinh, không dùng từ "em", không dùng từ "nám". 
  Trả về mảng JSON gồm các đối tượng { mucDo: "T"|"H"|"C", noiDung: "chuỗi nhận xét" }.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error) {
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Môn: ${subject}. Khối: ${gradeLevel}. Viết nhận xét 2 câu cho các học sinh có mức độ và điểm số cụ thể: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}. Hãy viết sát với năng lực tương ứng của từng đầu điểm.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
