      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);
    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
