import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên chuyên nghiệp bậc Tiểu học tại Việt Nam, am hiểu sâu sắc Thông tư 27/2020/TT-BGDĐT.
Nhiệm vụ: Viết nhận xét học bạ định kỳ cho môn học.

YÊU CẦU NGHIÊM NGẶT VỀ NỘI DUNG (THEO TT 27):
1. Độ dài: Đúng 2 câu văn, gộp thành một đoạn văn duy nhất.
2. Cấu trúc 2 câu:
   - Câu 1: Đánh giá cụ thể về sự tiến bộ hoặc điểm mạnh trong kiến thức, kỹ năng của môn học đó.
   - Câu 2: Chỉ ra một vấn đề về năng lực/phẩm chất cần rèn luyện thêm và đưa ra biện pháp hỗ trợ cụ thể.
3. QUY ĐỊNH CẤM:
   - KHÔNG sử dụng tên riêng của học sinh.
   - KHÔNG sử dụng từ "em" (viết ẩn chủ ngữ).
   - KHÔNG sử dụng từ "nám".
   - Tuyệt đối không dùng từ ngữ tiêu cực (yếu, kém, lười). 
4. VĂN PHONG: Sát thực tế với mức điểm, khích lệ, mẫu mực sư phạm.
`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  diem: number;
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Hãy tạo ngân hàng nhận xét cho môn ${subject}, khối ${gradeLevel}.
  Yêu cầu tạo 3 mã nhận xét KHÁC NHAU cho mỗi đầu điểm cụ thể như sau:

  1. Mức "Hoàn thành tốt" (T): Các điểm 10, 9, 8, 7 (Tổng 12 mẫu).
  2. Mức "Hoàn thành" (H): Các điểm 6, 5 (Tổng 6 mẫu).
  3. Mức "Chưa hoàn thành" (C): Các điểm 4, 3 (Tổng 6 mẫu).

  Tổng cộng cần 24 mẫu nhận xét (3 mẫu/đầu điểm).

  YÊU CẦU NỘI DUNG:
  - Điểm 10: Nhận xét sự xuất sắc, sáng tạo, tư duy vượt trội.
  - Điểm 9: Nhận xét sự vững vàng, kỹ năng thành thạo.
  - Điểm 7-8: Nhận xét sự nỗ lực, nắm chắc kiến thức cơ bản và có tiến bộ.
  - Điểm 5-6: Nhận xét hoàn thành yêu cầu, nhưng cần rèn luyện thêm tính cẩn thận hoặc trình bày.
  - Điểm 3-4: Nhận xét sự khó khăn trong tiếp thu, cần sự giúp đỡ sát sao và ôn tập kiến thức hổng.

  LƯU Ý: Mỗi mẫu đúng 2 câu, không dùng tên học sinh, không dùng từ "em", không dùng từ "nám".
  Trả về mảng JSON gồm các đối tượng { mucDo: "T"|"H"|"C", diem: number, noiDung: "chuỗi nhận xét" }.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              diem: { type: Type.NUMBER },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "diem", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error) {
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Môn: ${subject}. Khối: ${gradeLevel}. Viết nhận xét 2 câu cho các học sinh có mức độ và điểm số cụ thể: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}. Hãy viết sát với năng lực tương ứng của từng đầu điểm.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Lấy số khối từ chuỗi "Khối X"
  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    // Lưu trữ số thứ tự của mã cho từng tổ hợp (Mức + Điểm)
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = Math.round(record.diem);
      const level = record.mucDo || (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C');

      const counterKey = `${level}_${studentScore}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      // Tạo mã nhận xét theo định dạng mới: [Môn][Khối][Mức][STT]m[Điểm] -> Ví dụ TV2T1m10
      const generatedCode = `${abbr}${gradeNumber}${level}${counters[counterKey]}m${studentScore}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu khớp chính xác đầu điểm
      // Nếu không có khớp điểm chính xác, lấy mẫu bất kỳ trong mức độ đó
      const scoreGroup = commentBank.filter(b => b.diem === studentScore);
      const levelGroup = scoreGroup.length > 0 ? scoreGroup : commentBank.filter(b => b.mucDo === level);

      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng mã nhận xét chi tiết theo từng đầu điểm!' });
      }
    } catch (error) {
      setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
    } finally {
      setIsGeneratingBank(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const abbr = getSubjectAbbr(selectedSubject).toLowerCase();
        const subjectName = selectedSubject.toLowerCase();

        let targetSheetName = wb.SheetNames.find(name => {
          const lowerName = name.toLowerCase();
          return lowerName === subjectName || 
                 lowerName === abbr || 
                 lowerName.includes(subjectName) || 
                 (abbr.length > 1 && lowerName.includes(abbr));
        });

        if (!targetSheetName) {
          targetSheetName = wb.SheetNames[0];
          setNotification({ 
            type: 'error', 
            message: `Không tìm thấy sheet cho môn ${selectedSubject}. Mặc định lấy sheet đầu tiên: "${targetSheetName}"` 
          });
        } else {
          setNotification({ 
            type: 'success', 
            message: `Đã tự động chọn sheet: "${targetSheetName}"` 
          });
        }

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'Sheet được chọn không có dữ liệu học sinh.' });
          return;
        }

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 50); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());

          row.forEach((cell, colIdx) => {
            if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;
            if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên')) nameIdx = colIdx;
            if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;
            if (scoreIdx === -1 && (
              cell === 'điểm' || 
              cell === 'điểm ktđk' || 
              cell.includes('ktđk') || 
              cell.includes('điểm thi') ||
              cell.includes('điểm kiểm tra')
            )) {
              if (!cell.includes('nhận xét')) scoreIdx = colIdx;
            }
            if (levelIdx === -1 && (
              cell === 'mức đạt được' || 
              cell.includes('mức đạt') || 
              cell.includes('xếp loại') || 
              cell.includes('đánh giá')
            )) levelIdx = colIdx;
          });

          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) {
          setNotification({ type: 'error', message: 'Không thể nhận diện tiêu đề cột trong sheet này.' });
          return;
        }

        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            return nameVal !== "" && isNaN(parseFloat(nameVal)) && nameVal.length > 2;
          })
          .map((row, idx) => {
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }
            const hoTen = String(row[nameIdx] || "").trim();
            const ngaySinhVal = row[birthIdx];
            let ngaySinh = "";
            if (ngaySinhVal instanceof Date) {
              ngaySinh = ngaySinhVal.toLocaleDateString('vi-VN');
            } else {
              ngaySinh = String(ngaySinhVal || "").trim();
            }
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  const strScore = String(rawScore).replace(',', '.').trim();
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }
            let mucDoValue = "";
            if (levelIdx !== -1) {
              const rawLevel = String(row[levelIdx] || "").trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT' || rawLevel.includes('HOÀN THÀNH TỐT')) {
                mucDoValue = 'T';
              } else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT' || rawLevel.includes('CHƯA HOÀN THÀNH')) {
                mucDoValue = 'C';
              } else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') {
                mucDoValue = 'H';
              }
            }
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 7 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }
            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ 
            type: 'success', 
            message: `Đã nhập thành công ${newRecords.length} học sinh. Dữ liệu đã được đồng bộ.` 
          });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi khi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Kết quả học tập", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
    const headerRow3 = ["", "", "", "", "", "Mã nhận xét", "Nội dung"];
    const dataRows = calculatedRecords.map(r => [
      r.stt,
      r.hoTen,
      r.ngaySinh,
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);
    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangDiem_NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};
    const data = commentBank.map(b => {
      const key = `${b.mucDo}_${b.diem}`;
      counters[key] = (counters[key] || 0) + 1;
      return {
        'Mã nhận xét': `${abbr}${gradeNumber}${b.mucDo}${counters[key]}m${b.diem}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.diem,
        'Nội dung nhận xét mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => {
