`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  diem: number;
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string,
  signal?: AbortSignal
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Hãy tạo ngân hàng nhận xét cho môn ${subject}, khối ${gradeLevel} dựa trên các mẫu nội dung sau:

  DỮ LIỆU THAM KHẢO (PHẢI DỰA VÀO CÁC Ý NÀY):
  - Mức T (Điểm 7,8,9,10): "Đọc lưu loát, diễn cảm, viết chữ đẹp, đúng chính tả, hiểu bài sâu", "Có kỹ năng đọc hiểu tốt, viết mạch lạc, sáng tạo", "Nắm vững kiến thức, phát biểu rõ ràng, tự tin".
  - Mức H (Điểm 5,6): "Hoàn thành tốt bài tập, đọc hiểu khá, nhưng cần rèn luyện thêm kỹ năng nói tự tin", "Viết đúng, trình bày rõ ràng nhưng cần tích cực phát biểu hơn", "Nắm kiến thức tốt nhưng cần chú ý kiểm tra lỗi chính tả".
  - Mức C (Điểm 3,4): "Đọc chưa trôi chảy, viết còn sai chính tả, cần cố gắng luyện đọc", "Hoàn thành bài tập chưa tốt, cần rèn luyện thêm kỹ năng nghe nói đọc viết", "Đọc chậm, viết bài còn cẩu thả, cần chú ý trình bày sạch sẽ".

  YÊU CẦU CỤ THỂ:
  Tạo đúng 3 mẫu nhận xét khác nhau cho mỗi đầu điểm: 10, 9, 8, 7, 6, 5, 4, 3.
  (Tổng cộng 24 mẫu).

  Mã nhận xét sẽ được gán dựa trên:
  - Điểm 10, 9, 8, 7 -> Mức T.
  - Điểm 6, 5 -> Mức H.
  - Điểm 4, 3 -> Mức C.

  LƯU Ý: Mỗi mẫu đúng 2 câu, không dùng tên học sinh, không dùng từ "em", không dùng từ "nám".
  Trả về mảng JSON gồm các đối tượng { mucDo: "T"|"H"|"C", diem: number, noiDung: "chuỗi nhận xét" }.`;

  try {
    // Fixed: Google GenAI SDK's generateContent expects exactly 1 argument.
    // Removed the second { signal } argument as it's not supported by the SDK signature.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              diem: { type: Type.NUMBER },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "diem", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error: any) {
    if (error.name === 'AbortError') {
      console.log('Generation aborted');
      return [];
    }
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Môn: ${subject}. Khối: ${gradeLevel}. Viết nhận xét 2 câu dựa trên phong cách tài liệu mẫu cho các học sinh: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // Lấy số khối từ chuỗi "Khối X"
  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    // Lưu trữ số thứ tự của mã cho từng tổ hợp (Mức + Điểm)
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = Math.round(record.diem);
      const level = record.mucDo || (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C');

      const counterKey = `${level}_${studentScore}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      // Chuyển đổi ký hiệu mức độ cho mã nhận xét: H -> HT
      const levelCodeForId = level === 'H' ? 'HT' : level;

      // Tạo mã nhận xét theo định dạng mới: [Môn][Khối][Mức_Mới][STT]đ[Điểm] -> Ví dụ TV2HT1đ6
      const generatedCode = `${abbr}${gradeNumber}${levelCodeForId}${counters[counterKey]}đ${studentScore}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu khớp chính xác đầu điểm
      const scoreGroup = commentBank.filter(b => b.diem === studentScore);
      const levelGroup = scoreGroup.length > 0 ? scoreGroup : commentBank.filter(b => b.mucDo === level);

      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);

    // Khởi tạo AbortController mới
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, abortControllerRef.current.signal);

      // Nếu không bị hủy và có dữ liệu
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng mã nhận xét chi tiết theo từng đầu điểm!' });
      } else if (abortControllerRef.current?.signal.aborted) {
        setNotification({ type: 'info', message: 'Đã dừng quá trình tạo ngân hàng mã.' });
      }
    } catch (error: any) {
      if (error.name !== 'AbortError') {
        setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
      }
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const abbr = getSubjectAbbr(selectedSubject).toLowerCase();
        const subjectName = selectedSubject.toLowerCase();

        let targetSheetName = wb.SheetNames.find(name => {
          const lowerName = name.toLowerCase();
          return lowerName === subjectName || 
                 lowerName === abbr || 
                 lowerName.includes(subjectName) || 
                 (abbr.length > 1 && lowerName.includes(abbr));
        });

        if (!targetSheetName) {
          targetSheetName = wb.SheetNames[0];
          setNotification({ 
            type: 'error', 
            message: `Không tìm thấy sheet cho môn ${selectedSubject}. Mặc định lấy sheet đầu tiên: "${targetSheetName}"` 
          });
        } else {
          setNotification({ 
            type: 'success', 
            message: `Đã tự động chọn sheet: "${targetSheetName}"` 
          });
        }

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'Sheet được chọn không có dữ liệu học sinh.' });
          return;
        }

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 50); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());

          row.forEach((cell, colIdx) => {
            if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;
            if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên')) nameIdx = colIdx;
            if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;
            if (scoreIdx === -1 && (
              cell === 'điểm' || 
              cell === 'điểm ktđk' || 
              cell.includes('ktđk') || 
              cell.includes('điểm thi') ||
              cell.includes('điểm kiểm tra')
            )) {
              if (!cell.includes('nhận xét')) scoreIdx = colIdx;
            }
            if (levelIdx === -1 && (
              cell === 'mức đạt được' || 
              cell.includes('mức đạt') || 
              cell.includes('xếp loại') || 
              cell.includes('đánh giá')
            )) levelIdx = colIdx;
          });

          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) {
          setNotification({ type: 'error', message: 'Không thể nhận diện tiêu đề cột trong sheet này.' });
          return;
        }

        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            return nameVal !== "" && isNaN(parseFloat(nameVal)) && nameVal.length > 2;
          })
          .map((row, idx) => {
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }
            const hoTen = String(row[nameIdx] || "").trim();
            const ngaySinhVal = row[birthIdx];
            let ngaySinh = "";
            if (ngaySinhVal instanceof Date) {
              ngaySinh = ngaySinhVal.toLocaleDateString('vi-VN');
            } else {
              ngaySinh = String(ngaySinhVal || "").trim();
            }
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  const strScore = String(rawScore).replace(',', '.').trim();
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }
            let mucDoValue = "";
            if (levelIdx !== -1) {
              const rawLevel = String(row[levelIdx] || "").trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT' || rawLevel.includes('HOÀN THÀNH TỐT')) {
                mucDoValue = 'T';
              } else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT' || rawLevel.includes('CHƯA HOÀN THÀNH')) {
                mucDoValue = 'C';
              } else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') {
                mucDoValue = 'H';
              }
            }
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 7 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }
            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ 
            type: 'success', 
            message: `Đã nhập thành công ${newRecords.length} học sinh. Dữ liệu đã được đồng bộ.` 
          });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi khi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Kết quả học tập", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
    const headerRow3 = ["", "", "", "", "", "Mã nhận xét", "Nội dung"];
    const dataRows = calculatedRecords.map(r => [
      r.stt,
      r.hoTen,
      r.ngaySinh,
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);
    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangDiem_NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};
    const data = commentBank.map(b => {
      const key = `${b.mucDo}_${b.diem}`;
      counters[key] = (counters[key] || 0) + 1;
      const levelCodeForId = b.mucDo === 'H' ? 'HT' : b.mucDo;
      // Cập nhật 'm' thành 'đ' trong xuất Excel
      return {
        'Mã nhận xét': `${abbr}${gradeNumber}${levelCodeForId}${counters[key]}đ${b.diem}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.diem,
        'Nội dung nhận xét mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => {
    if (window.confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) {
      setRecords([]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
              onChange={(e) => setSelectedGrade(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>

            <select 
              value={selectedSubject}
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="px-4 py-2 bg-slate-100 border-none rounded-lg text-sm font-bold outline-none cursor-pointer"
            >
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button 
                onClick={handleStopGenerating}
                className="inline-flex items-center gap-2 px-5 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 transition-all shadow-md active:scale-95 text-sm font-bold animate-pulse"
              >
                <Square size={18} fill="currentColor" />
                Dừng tạo
              </button>
            ) : (
              <button 
                onClick={handleGenerateBank} 
                className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-all shadow-md active:scale-95 text-sm font-bold"
              >
                <Database size={18} />
                Tạo ngân hàng mã
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold"
            >
              <Upload size={18} />
              Tải file điểm
            </button>

            <button 
              onClick={viewMode === 'table' ? exportTableToExcel : exportBankToExcel} 
              className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-md text-sm font-bold active:scale-95"
            >
              <Download size={18} />
              Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex w-full sm:w-auto">
            <button 
              onClick={() => setViewMode('table')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <TableIcon size={18} /> Bảng nhận xét
            </button>
            <button 
              onClick={() => setViewMode('content')}
              className={`flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${
                viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              <FileJson size={18} /> Mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm nhanh..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm"
            />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm animate-in fade-in duration-300 ${
            notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 
            notification.type === 'info' ? 'bg-blue-50 text-blue-900 border-blue-200' :
            'bg-rose-50 text-rose-900 border-rose-200'
          }`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : 
             notification.type === 'info' ? <AlertCircle size={20} className="text-blue-600" /> :
             <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
            <button onClick={() => setNotification(null)} className="ml-auto font-bold p-1">&times;</button>
          </div>
        )}

        {viewMode === 'table' && (
          <div className="mb-6 p-6 bg-white rounded-2xl border border-slate-300 shadow-sm text-center">
             <div className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-1">UBND Xã Nấm Dẩn - Trường PTDTBT Tiểu học Nấm Dẩn</div>
             <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">
               ĐÁNH GIÁ ĐỊNH KỲ MÔN HỌC {selectedSubject.toUpperCase()}
             </h2>
             <div className="text-sm font-bold text-slate-600 mt-1 uppercase">
               LỚP: {selectedGrade.replace('Khối ', '')} - NĂM HỌC: 2025-2026
             </div>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 bg-slate-100/50">Kết quả học tập</th>
                    <th rowSpan={3} className="px-4 py-3 w-16">Xóa</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-36">Mức đạt được</th>
                    <th rowSpan={2} className="px-4 py-2 w-24">Điểm KTĐK</th>
