                      <td className="px-4 py-4 text-center font-bold text-slate-600">
                        {record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))}
                          placeholder="Chưa có nội dung..."
                          className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] leading-relaxed outline-none focus:ring-1 focus:ring-indigo-100 rounded"
