                        >
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={8} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                        <Upload size={48} strokeWidth={1.5} />
                        <p className="text-sm font-bold uppercase tracking-widest">Hãy tải file điểm để bắt đầu</p>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex flex-col">
              <div className="overflow-x-auto">
                <table className="table-bordered w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
                    <tr>
                      <th className="px-6 py-5 w-32 text-center">Mã nhận xét</th>
                      <th className="px-6 py-5 w-40 text-center">Mức đạt</th>
                      <th className="px-6 py-5 w-24 text-center">Điểm</th>
                      <th className="px-6 py-5">Nội dung nhận xét</th>
                      <th className="px-4 py-5 w-12">Xóa</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-300">
                    {commentBank.map((item, index) => {
                      const abbr = getSubjectAbbr(selectedSubject);
                      const sameKeyCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo && b.diem === item.diem).length;

                      // Hiển thị mã nhận xét đồng bộ với bảng chính: H -> HT
                      const levelCodeForId = item.mucDo === 'H' ? 'HT' : item.mucDo;
                      // Cập nhật 'm' thành 'đ' trong giao diện ngân hàng mã
                      const displayCode = `${abbr}${gradeNumber}${levelCodeForId}${sameKeyCount}đ${item.diem}`;

                      return (
                        <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                          <td className="px-6 py-6 text-center align-top">
                            <span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg shadow-sm">
                              {displayCode}
                            </span>
                          </td>
                          <td className="px-6 py-6 text-center align-top">
                            <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${
                              item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                              item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'
                            }`}>
                              {item.mucDo === 'T' ? 'Hoàn thành tốt' : item.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành'}
                            </span>
                          </td>
                          <td className="px-6 py-6 text-center align-top font-black text-slate-700">
                             {item.diem}
                          </td>
                          <td className="px-6 py-6">
                            <textarea 
                              value={item.noiDung}
                              onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))}
                              className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] outline-none transition-all resize-none shadow-sm"
                            />
                          </td>
                          <td className="px-4 py-6 text-center align-top">
                             <button 
                               onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))}
                               className="p-2 text-slate-300 hover:text-rose-500"
                             >
                               <Trash2 size={16} />
                             </button>
                          </td>
                        </tr>
                      );
                    })}
                    {commentBank.length === 0 && (
                      <tr>
                        <td colSpan={5} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                          <Database size={48} strokeWidth={1.5} />
                          <p className="text-sm font-bold uppercase tracking-widest">Ngân hàng mã trống. Hãy nhấn "Tạo ngân hàng mã"</p>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
              {commentBank.length > 0 && (
                <div className="p-8 flex justify-center bg-slate-50/50 border-t border-slate-300">
                  <button onClick={exportBankToExcel} className="inline-flex items-center gap-3 px-8 py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-all shadow-lg active:scale-95 font-black uppercase text-sm tracking-wider">
                    <FileSpreadsheet size={20} /> Tải ngân hàng mã nhận xét (.xlsx)
                  </button>
                </div>
              )}
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-300">
            <button 
              onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 10, mucDo: 'T', maNhanXet: '', noiDung: '', isProcessing: false }])}
              className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
            >
              <Plus size={16} /> Thêm học sinh
            </button>
            {records.length > 0 && (
              <button 
                onClick={handleClearData}
                className="px-4 py-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
              >
                <Trash2 size={16} /> Xóa danh sách
              </button>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        Trường PTDTBT Tiểu học Nấm Dẩn
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // Lấy số khối từ chuỗi "Khối X"
  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tự động điền nhận xét dựa trên mã ngân hàng và mức độ học sinh
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    // Lưu trữ số thứ tự của mã cho từng tổ hợp (Mức + Điểm)
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = Math.round(record.diem);
      const level = record.mucDo || (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C');

      const counterKey = `${level}_${studentScore}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      // Chuyển đổi ký hiệu mức độ cho mã nhận xét: H -> HT
      const levelCodeForId = level === 'H' ? 'HT' : level;

      // Tạo mã nhận xét theo định dạng mới: [Môn][Khối][Mức_Mới][STT]d[Điểm] -> Ví dụ TV2HT1d6
      const generatedCode = `${abbr}${gradeNumber}${levelCodeForId}${counters[counterKey]}d${studentScore}`;
      const code = record.maNhanXet || generatedCode;

      // Lấy nội dung từ ngân hàng mẫu khớp chính xác đầu điểm
      const scoreGroup = commentBank.filter(b => b.diem === studentScore);
      const levelGroup = scoreGroup.length > 0 ? scoreGroup : commentBank.filter(b => b.mucDo === level);

      let autoContent = record.noiDung;

      if (levelGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % levelGroup.length;
        autoContent = levelGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);

    // Khởi tạo AbortController mới
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, abortControllerRef.current.signal);

      // Nếu không bị hủy và có dữ liệu
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo thành công ngân hàng mã nhận xét chi tiết theo từng đầu điểm!' });
      } else if (abortControllerRef.current?.signal.aborted) {
        setNotification({ type: 'info', message: 'Đã dừng quá trình tạo ngân hàng mã.' });
      }
    } catch (error: any) {
      if (error.name !== 'AbortError') {
        setNotification({ type: 'error', message: 'Lỗi khi tạo ngân hàng mã từ AI.' });
      }
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const abbr = getSubjectAbbr(selectedSubject).toLowerCase();
        const subjectName = selectedSubject.toLowerCase();

        let targetSheetName = wb.SheetNames.find(name => {
          const lowerName = name.toLowerCase();
          return lowerName === subjectName || 
                 lowerName === abbr || 
                 lowerName.includes(subjectName) || 
                 (abbr.length > 1 && lowerName.includes(abbr));
        });

        if (!targetSheetName) {
          targetSheetName = wb.SheetNames[0];
          setNotification({ 
            type: 'error', 
            message: `Không tìm thấy sheet cho môn ${selectedSubject}. Mặc định lấy sheet đầu tiên: "${targetSheetName}"` 
          });
        } else {
          setNotification({ 
            type: 'success', 
            message: `Đã tự động chọn sheet: "${targetSheetName}"` 
          });
        }

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        if (data.length < 2) {
          setNotification({ type: 'error', message: 'Sheet được chọn không có dữ liệu học sinh.' });
          return;
        }

        let sttIdx = -1, nameIdx = -1, birthIdx = -1, scoreIdx = -1, levelIdx = -1;
        let headerRowIdx = -1;

        for (let i = 0; i < Math.min(data.length, 50); i++) {
          const row = data[i].map(c => String(c || "").toLowerCase().trim());

          row.forEach((cell, colIdx) => {
            if (sttIdx === -1 && (cell === 'stt' || cell.includes('số tt') || cell.includes('thứ tự'))) sttIdx = colIdx;
            if (nameIdx === -1 && (cell.includes('họ và tên') || cell.includes('họ tên') || cell === 'học sinh' || cell === 'tên')) nameIdx = colIdx;
            if (birthIdx === -1 && (cell.includes('ngày sinh') || cell.includes('năm sinh'))) birthIdx = colIdx;
            if (scoreIdx === -1 && (
              cell === 'điểm' || 
              cell === 'điểm ktđk' || 
              cell.includes('ktđk') || 
              cell.includes('điểm thi') ||
              cell.includes('điểm kiểm tra')
            )) {
              if (!cell.includes('nhận xét')) scoreIdx = colIdx;
            }
            if (levelIdx === -1 && (
              cell === 'mức đạt được' || 
              cell.includes('mức đạt') || 
              cell.includes('xếp loại') || 
              cell.includes('đánh giá')
            )) levelIdx = colIdx;
          });

          if (nameIdx !== -1 && (scoreIdx !== -1 || levelIdx !== -1)) {
            headerRowIdx = i;
            break;
          }
        }

        if (headerRowIdx === -1) {
          setNotification({ type: 'error', message: 'Không thể nhận diện tiêu đề cột trong sheet này.' });
          return;
        }

        const newRecords = data.slice(headerRowIdx + 1)
          .filter(row => {
            const nameVal = String(row[nameIdx] || "").trim();
            return nameVal !== "" && isNaN(parseFloat(nameVal)) && nameVal.length > 2;
          })
          .map((row, idx) => {
            let sttValue = (idx + 1);
            if (sttIdx !== -1) {
              const p = parseInt(String(row[sttIdx]));
              if (!isNaN(p)) sttValue = p;
            }
            const hoTen = String(row[nameIdx] || "").trim();
            const ngaySinhVal = row[birthIdx];
            let ngaySinh = "";
            if (ngaySinhVal instanceof Date) {
              ngaySinh = ngaySinhVal.toLocaleDateString('vi-VN');
            } else {
              ngaySinh = String(ngaySinhVal || "").trim();
            }
            let diemValue = 0;
            if (scoreIdx !== -1) {
              const rawScore = row[scoreIdx];
              if (rawScore !== "" && rawScore !== undefined) {
                if (typeof rawScore === 'number') {
                  diemValue = rawScore;
                } else {
                  const strScore = String(rawScore).replace(',', '.').trim();
                  const parsed = parseFloat(strScore);
                  diemValue = isNaN(parsed) ? 0 : parsed;
                }
              }
            }
            let mucDoValue = "";
            if (levelIdx !== -1) {
              const rawLevel = String(row[levelIdx] || "").trim().toUpperCase();
              if (rawLevel.includes('TỐT') || rawLevel === 'T' || rawLevel === 'HTT' || rawLevel.includes('HOÀN THÀNH TỐT')) {
                mucDoValue = 'T';
              } else if (rawLevel.includes('CHƯA') || rawLevel === 'C' || rawLevel === 'CHT' || rawLevel.includes('CHƯA HOÀN THÀNH')) {
                mucDoValue = 'C';
              } else if (rawLevel.includes('HOÀN THÀNH') || rawLevel === 'H' || rawLevel === 'HT') {
                mucDoValue = 'H';
              }
            }
            if (!mucDoValue && scoreIdx !== -1) {
              mucDoValue = diemValue >= 7 ? 'T' : diemValue >= 5 ? 'H' : 'C';
            }
            return {
              stt: sttValue,
              hoTen,
              ngaySinh,
              diem: diemValue,
              mucDo: mucDoValue,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false,
            } as StudentRecord;
          });

        if (newRecords.length > 0) {
          setRecords(newRecords);
          setNotification({ 
            type: 'success', 
            message: `Đã nhập thành công ${newRecords.length} học sinh. Dữ liệu đã được đồng bộ.` 
          });
        } else {
          setNotification({ type: 'error', message: 'Không tìm thấy dữ liệu học sinh hợp lệ.' });
        }
      } catch (err) {
        console.error(err);
        setNotification({ type: 'error', message: 'Lỗi khi xử lý file Excel.' });
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const headerRow1 = ["", "", "", "Kết quả học tập", "", "", ""];
    const headerRow2 = ["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Nhận xét điểm mạnh và các mặt cần rèn luyện", ""];
    const headerRow3 = ["", "", "", "", "", "Mã nhận xét", "Nội dung"];
    const dataRows = calculatedRecords.map(r => [
      r.stt,
      r.hoTen,
      r.ngaySinh,
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem,
      r.maNhanXet,
      r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([headerRow1, headerRow2, headerRow3, ...dataRows]);
    ws['!merges'] = [
      { s: { r: 0, c: 3 }, e: { r: 0, c: 6 } },
      { s: { r: 1, c: 0 }, e: { r: 2, c: 0 } },
      { s: { r: 1, c: 1 }, e: { r: 2, c: 1 } },
      { s: { r: 1, c: 2 }, e: { r: 2, c: 2 } },
      { s: { r: 1, c: 3 }, e: { r: 2, c: 3 } },
      { s: { r: 1, c: 4 }, e: { r: 2, c: 4 } },
      { s: { r: 1, c: 5 }, e: { r: 1, c: 6 } },
    ];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `BangDiem_NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};
    const data = commentBank.map(b => {
      const key = `${b.mucDo}_${b.diem}`;
      counters[key] = (counters[key] || 0) + 1;
      const levelCodeForId = b.mucDo === 'H' ? 'HT' : b.mucDo;
      // Sử dụng 'd' thay vì 'đ' trong xuất Excel
      return {
        'Mã nhận xét': `${abbr}${gradeNumber}${levelCodeForId}${counters[key]}d${b.diem}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.diem,
        'Nội dung nhận xét mẫu': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => {
    if (window.confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) {
      setRecords([]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select 
              value={selectedGrade}
