                    {commentBank.map((item, index) => {
                      const abbr = getSubjectAbbr(selectedSubject);
                      const sameKeyCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo && b.diem === item.diem).length;

                      // Hiển thị mã nhận xét đồng bộ với bảng chính: H -> HT
                      const levelCodeForId = item.mucDo === 'H' ? 'HT' : item.mucDo;
                      // Sử dụng 'd' thay vì 'đ' trong giao diện ngân hàng mã
                      const displayCode = `${abbr}${gradeNumber}${levelCodeForId}${sameKeyCount}d${item.diem}`;

                      return (
