                      );
                    })}
                    {commentBank.length === 0 && (
                      <tr>
                        <td colSpan={5} className="px-6 py-24 text-center flex flex-col items-center gap-4 text-slate-300">
                          <Database size={48} strokeWidth={1.5} />
