          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-300">
            <button 
              onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 10, mucDo: 'T', maNhanXet: '', noiDung: '', isProcessing: false }])}
              className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2 transition-all"
            >
