      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500'}`}>
              <TableIcon size={18} className="inline mr-2" /> Bảng nhận xét
            </button>
            <button onClick={() => setViewMode('content')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500'}`}>
