        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 bg-slate-100/50">Kết quả học tập</th>
                    <th rowSpan={3} className="px-4 py-3 w-16">Xóa</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-36">Mức đạt</th>
                    <th rowSpan={2} className="px-4 py-2 w-24">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nhận xét</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-32 border-t border-slate-300">Mã NX</th>
                    <th className="px-6 py-2 border-t border-slate-300 text-left">Nội dung</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-500">{record.stt}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-900">{record.hoTen}</td>
                      <td className="px-4 py-4 text-sm text-slate-500 text-center">{record.ngaySinh}</td>
                      <td className="px-4 py-4 text-center">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border uppercase ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-bold text-slate-600">
                        {record.diem > 0 ? (record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)) : "-"}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea 
                          value={record.noiDung}
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))}
                          className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] outline-none"
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button onClick={() => setRecords(records.filter(r => r.stt !== record.stt))} className="p-1.5 text-slate-400 hover:text-rose-500"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex flex-col">
              <div className="overflow-x-auto">
                <table className="table-bordered w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
                    <tr>
                      <th className="px-6 py-5 w-32 text-center">Mã nhận xét</th>
                      <th className="px-6 py-5 w-40 text-center">Mức đạt</th>
                      <th className="px-6 py-5 w-24 text-center">Điểm</th>
                      <th className="px-6 py-5">Nội dung mẫu</th>
                      <th className="px-4 py-5 w-12">Xóa</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-300">
                    {commentBank.map((item, index) => {
                      const abbr = getSubjectAbbr(selectedSubject);
                      const sameKeyCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo && b.diem === item.diem).length;
                      const levelCode = item.mucDo === 'H' ? 'HT' : item.mucDo;
                      const displayCode = `${abbr}${gradeNumber}${levelCode}${sameKeyCount}d${item.diem}`;
                      return (
                        <tr key={item.id}>
                          <td className="px-6 py-6 text-center">
                            <span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg">{displayCode}</span>
                          </td>
                          <td className="px-6 py-6 text-center">
                            <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                              {item.mucDo === 'T' ? 'Hoàn thành tốt' : item.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành'}
                            </span>
                          </td>
                          <td className="px-6 py-6 text-center font-black text-slate-700">{item.diem}</td>
                          <td className="px-6 py-6">
                            <textarea value={item.noiDung} onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))} className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium resize-none shadow-sm" />
                          </td>
                          <td className="px-4 py-6 text-center"><button onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))} className="text-slate-300 hover:text-rose-500"><Trash2 size={16} /></button></td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-300">
            <button onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 0, mucDo: 'H', maNhanXet: '', noiDung: '', isProcessing: false }])} className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Plus size={16} /> Thêm học sinh</button>
            {records.length > 0 && <button onClick={() => setRecords([])} className="px-4 py-2 text-rose-400 hover:text-rose-600 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Trash2 size={16} /> Xóa danh sách</button>}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">Trường PTDTBT Tiểu học Nấm Dẩn</footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      const hasScore = studentScore > 0;
      const level = record.mucDo || (hasScore ? (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C') : 'H');

      // Tạo key đếm STT: Phân biệt count theo mức_điểm và count theo mức_khôngđiểm
      const counterKey = hasScore ? `${level}_score_${studentScore}` : `${level}_noscore`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      const levelCodeForId = level === 'H' ? 'HT' : level;
      const baseCode = `${abbr}${gradeNumber}${levelCodeForId}${counters[counterKey]}`;
      const generatedCode = hasScore ? `${baseCode}d${studentScore}` : baseCode;

      const code = record.maNhanXet || generatedCode;

      // Chọn nội dung nhận xét
      let targetGroup: BankComment[] = [];
      if (hasScore) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo ngân hàng mã nhận xét mới.' });
      } else if (abortControllerRef.current?.signal.aborted) {
        setNotification({ type: 'info', message: 'Đã dừng tạo.' });
      }
    } catch (error: any) {
      if (error.name !== 'AbortError') setNotification({ type: 'error', message: 'Lỗi AI.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const abbr = getSubjectAbbr(selectedSubject).toLowerCase();
        let targetSheetName = wb.SheetNames.find(n => n.toLowerCase().includes(abbr)) || wb.SheetNames[0];
        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        let nameIdx = -1, scoreIdx = -1, levelIdx = -1, birthIdx = -1;
        for (let i = 0; i < 20; i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase());
          if (nameIdx === -1) nameIdx = row.findIndex(c => c.includes('họ tên') || c.includes('học sinh'));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => c === 'điểm' || c.includes('ktđk'));
          if (levelIdx === -1) levelIdx = row.findIndex(c => c.includes('mức đạt') || c.includes('xếp loại'));
          if (birthIdx === -1) birthIdx = row.findIndex(c => c.includes('ngày sinh'));
          if (nameIdx !== -1) break;
        }

        const newRecords = data.slice(1).filter(r => String(r[nameIdx]).trim().length > 2).map((r, i) => {
          const rawScore = parseFloat(String(r[scoreIdx]).replace(',', '.'));
          const diem = isNaN(rawScore) ? 0 : rawScore;
          let mucDo = "";
          const rawL = String(r[levelIdx]).toUpperCase();
          if (rawL.includes('TỐT') || rawL === 'T') mucDo = 'T';
          else if (rawL.includes('CHƯA') || rawL === 'C') mucDo = 'C';
          else if (rawL.includes('HOÀN THÀNH') || rawL === 'H') mucDo = 'H';

          return {
            stt: i + 1,
            hoTen: String(r[nameIdx]).trim(),
            ngaySinh: r[birthIdx] instanceof Date ? r[birthIdx].toLocaleDateString('vi-VN') : String(r[birthIdx]),
            diem,
            mucDo,
            maNhanXet: "",
            noiDung: "",
            isProcessing: false
          } as StudentRecord;
        });
        setRecords(newRecords);
      } catch (err) { setNotification({ type: 'error', message: 'Lỗi file.' }); }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [
      r.stt, r.hoTen, r.ngaySinh, 
      r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : 'CHT',
      r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ tên", "Ngày sinh", "Mức đạt", "Điểm", "Mã NX", "Nội dung"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => { if (confirm("Xóa danh sách?")) setRecords([]); };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-4 py-2 bg-slate-100 rounded-lg text-sm font-bold outline-none cursor-pointer">
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>
            <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-4 py-2 bg-slate-100 rounded-lg text-sm font-bold outline-none cursor-pointer">
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-5 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 shadow-md text-sm font-bold animate-pulse">
                <Square size={18} fill="currentColor" /> Dừng tạo
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 shadow-md text-sm font-bold">
                <Database size={18} /> Tạo ngân hàng mã
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-bold">
              <Upload size={18} /> Tải file
            </button>

            <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg shadow-md text-sm font-bold">
              <Download size={18} /> Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Bảng nhận xét
            </button>
            <button onClick={() => setViewMode('content')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm nhanh..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 bg-slate-100/50">Kết quả học tập</th>
                    <th rowSpan={3} className="px-4 py-3 w-16">Xóa</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-36">Mức đạt</th>
                    <th rowSpan={2} className="px-4 py-2 w-24">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nhận xét</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-32 border-t border-slate-300">Mã NX</th>
                    <th className="px-6 py-2 border-t border-slate-300 text-left">Nội dung</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-500">{record.stt}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-900">{record.hoTen}</td>
                      <td className="px-4 py-4 text-sm text-slate-500 text-center">{record.ngaySinh}</td>
                      <td className="px-4 py-4 text-center">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border uppercase ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-bold text-slate-600">
                        {record.diem > 0 ? (record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)) : "-"}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea value={record.noiDung} onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))} className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] outline-none leading-relaxed" />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button onClick={() => setRecords(records.filter(r => r.stt !== record.stt))} className="p-1.5 text-slate-400 hover:text-rose-500"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr><td colSpan={8} className="py-24 text-center text-slate-300 font-bold uppercase tracking-widest"><Upload className="inline mb-2" /><br/>Tải file điểm để bắt đầu</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="table-bordered w-full text-left">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
                  <tr>
                    <th className="px-6 py-5 w-40 text-center">Mã nhận xét mẫu</th>
                    <th className="px-6 py-5 w-40 text-center">Mức đạt</th>
                    <th className="px-6 py-5 w-24 text-center">Điểm</th>
                    <th className="px-6 py-5">Nội dung mẫu</th>
                    <th className="px-4 py-5 w-12">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {commentBank.map((item, index) => {
                    const abbr = getSubjectAbbr(selectedSubject);
                    const sameKeyCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo && b.diem === item.diem).length;
                    const levelCode = item.mucDo === 'H' ? 'HT' : item.mucDo;
                    const displayCode = `${abbr}${gradeNumber}${levelCode}${sameKeyCount}${item.diem > 0 ? `d${item.diem}` : ''}`;
                    return (
                      <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                        <td className="px-6 py-6 text-center"><span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg">{displayCode}</span></td>
                        <td className="px-6 py-6 text-center">
                          <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                            {item.mucDo === 'T' ? 'Hoàn thành tốt' : item.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành'}
                          </span>
                        </td>
                        <td className="px-6 py-6 text-center font-black text-slate-700">{item.diem > 0 ? item.diem : "-"}</td>
                        <td className="px-6 py-6"><textarea value={item.noiDung} onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))} className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] outline-none shadow-sm resize-none" /></td>
                        <td className="px-4 py-6 text-center"><button onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))} className="p-2 text-slate-300 hover:text-rose-500"><Trash2 size={16} /></button></td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-300">
            <button onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 0, mucDo: 'H', maNhanXet: '', noiDung: '', isProcessing: false }])} className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Plus size={16} /> Thêm học sinh</button>
            {records.length > 0 && <button onClick={handleClearData} className="px-4 py-2 text-rose-400 hover:text-rose-600 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Trash2 size={16} /> Xóa danh sách</button>}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">Trường PTDTBT Tiểu học Nấm Dẩn</footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      const hasScore = studentScore > 0;
      const level = record.mucDo || (hasScore ? (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C') : 'H');

      // Tạo key đếm STT: Phân biệt count theo mức_điểm và count theo mức_khôngđiểm
      const counterKey = hasScore ? `${level}_score_${studentScore}` : `${level}_noscore`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      const levelCodeForId = level === 'H' ? 'HT' : level;
      const baseCode = `${abbr}${gradeNumber}${levelCodeForId}${counters[counterKey]}`;
      // Thay đổi 'd' thành 'D'
      const generatedCode = hasScore ? `${baseCode}D${studentScore}` : baseCode;

      const code = record.maNhanXet || generatedCode;

      // Chọn nội dung nhận xét
      let targetGroup: BankComment[] = [];
      if (hasScore) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo ngân hàng mã nhận xét mới.' });
      } else if (abortControllerRef.current?.signal.aborted) {
        setNotification({ type: 'info', message: 'Đã dừng tạo.' });
      }
    } catch (error: any) {
      if (error.name !== 'AbortError') setNotification({ type: 'error', message: 'Lỗi AI.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const abbr = getSubjectAbbr(selectedSubject).toLowerCase();
        let targetSheetName = wb.SheetNames.find(n => n.toLowerCase().includes(abbr)) || wb.SheetNames[0];
        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        let nameIdx = -1, scoreIdx = -1, levelIdx = -1, birthIdx = -1;
        for (let i = 0; i < 20; i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase());
          if (nameIdx === -1) nameIdx = row.findIndex(c => c.includes('họ tên') || c.includes('học sinh'));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => c === 'điểm' || c.includes('ktđk'));
          if (levelIdx === -1) levelIdx = row.findIndex(c => c.includes('mức đạt') || c.includes('xếp loại'));
          if (birthIdx === -1) birthIdx = row.findIndex(c => c.includes('ngày sinh'));
          if (nameIdx !== -1) break;
        }

        const newRecords = data.slice(1).filter(r => String(r[nameIdx]).trim().length > 2).map((r, i) => {
          const rawScore = parseFloat(String(r[scoreIdx]).replace(',', '.'));
          const diem = isNaN(rawScore) ? 0 : rawScore;
          let mucDo = "";
          const rawL = String(r[levelIdx]).toUpperCase();
          if (rawL.includes('TỐT') || rawL === 'T') mucDo = 'T';
          else if (rawL.includes('CHƯA') || rawL === 'C') mucDo = 'C';
          else if (rawL.includes('HOÀN THÀNH') || rawL === 'H') mucDo = 'H';

          return {
            stt: i + 1,
            hoTen: String(r[nameIdx]).trim(),
            ngaySinh: r[birthIdx] instanceof Date ? r[birthIdx].toLocaleDateString('vi-VN') : String(r[birthIdx]),
            diem,
            mucDo,
            maNhanXet: "",
            noiDung: "",
            isProcessing: false
          } as StudentRecord;
        });
        setRecords(newRecords);
      } catch (err) { setNotification({ type: 'error', message: 'Lỗi file.' }); }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [
      r.stt, r.hoTen, r.ngaySinh, 
      r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : 'CHT',
      r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ tên", "Ngày sinh", "Mức đạt", "Điểm", "Mã NX", "Nội dung"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};
    const data = commentBank.map(b => {
      const key = `${b.mucDo}_${b.diem}`;
      counters[key] = (counters[key] || 0) + 1;
      const levelCode = b.mucDo === 'H' ? 'HT' : b.mucDo;
      // Thay đổi 'd' thành 'D' trong xuất ngân hàng mã
      return {
        'Mã nhận xét': `${abbr}${gradeNumber}${levelCode}${counters[key]}${b.diem > 0 ? `D${b.diem}` : ''}`,
        'Mức đạt': b.mucDo === 'T' ? 'Hoàn thành tốt' : b.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        'Điểm tương ứng': b.diem > 0 ? b.diem : "-",
        'Nội dung': b.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMaNX_${selectedSubject}.xlsx`);
  };

  const handleClearData = () => { if (confirm("Xóa danh sách?")) setRecords([]); };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-4 py-2 bg-slate-100 rounded-lg text-sm font-bold outline-none cursor-pointer">
              {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
            </select>
            <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-4 py-2 bg-slate-100 rounded-lg text-sm font-bold outline-none cursor-pointer">
              {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
            </select>

            <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-5 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 shadow-md text-sm font-bold animate-pulse">
                <Square size={18} fill="currentColor" /> Dừng tạo
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-5 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 shadow-md text-sm font-bold">
                <Database size={18} /> Tạo ngân hàng mã
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-5 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-bold">
              <Upload size={18} /> Tải file
            </button>

            <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-5 py-2 bg-emerald-600 text-white rounded-lg shadow-md text-sm font-bold">
              <Download size={18} /> Xuất Excel
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Bảng nhận xét
            </button>
            <button onClick={() => setViewMode('content')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm nhanh..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-3 border shadow-sm ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
            <span className="font-bold text-sm">{notification.message}</span>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 bg-slate-100/50">Kết quả học tập</th>
                    <th rowSpan={3} className="px-4 py-3 w-16">Xóa</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-36">Mức đạt</th>
                    <th rowSpan={2} className="px-4 py-2 w-24">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nhận xét</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-32 border-t border-slate-300">Mã NX</th>
                    <th className="px-6 py-2 border-t border-slate-300 text-left">Nội dung</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-500">{record.stt}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-900">{record.hoTen}</td>
                      <td className="px-4 py-4 text-sm text-slate-500 text-center">{record.ngaySinh}</td>
                      <td className="px-4 py-4 text-center">
                        <span className={`px-2 py-1 rounded-md text-[9px] font-black border uppercase ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : record.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-bold text-slate-600">
                        {record.diem > 0 ? (record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)) : "-"}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-1 rounded text-slate-600 border border-slate-200">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea value={record.noiDung} onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))} className="w-full bg-transparent border-none text-xs font-medium resize-none min-h-[44px] outline-none leading-relaxed" />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button onClick={() => setRecords(records.filter(r => r.stt !== record.stt))} className="p-1.5 text-slate-400 hover:text-rose-500"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr><td colSpan={8} className="py-24 text-center text-slate-300 font-bold uppercase tracking-widest"><Upload className="inline mb-2" /><br/>Tải file điểm để bắt đầu</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="table-bordered w-full text-left">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
                  <tr>
                    <th className="px-6 py-5 w-40 text-center">Mã nhận xét mẫu</th>
                    <th className="px-6 py-5 w-40 text-center">Mức đạt</th>
                    <th className="px-6 py-5 w-24 text-center">Điểm</th>
                    <th className="px-6 py-5">Nội dung mẫu</th>
                    <th className="px-4 py-5 w-12">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {commentBank.map((item, index) => {
                    const abbr = getSubjectAbbr(selectedSubject);
                    const sameKeyCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo && b.diem === item.diem).length;
                    const levelCode = item.mucDo === 'H' ? 'HT' : item.mucDo;
                    // Thay đổi 'd' thành 'D' trong giao diện mã
                    const displayCode = `${abbr}${gradeNumber}${levelCode}${sameKeyCount}${item.diem > 0 ? `D${item.diem}` : ''}`;
                    return (
                      <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                        <td className="px-6 py-6 text-center"><span className="text-xs font-black font-mono px-3 py-1.5 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-lg">{displayCode}</span></td>
                        <td className="px-6 py-6 text-center">
                          <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase inline-block min-w-[120px] ${item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-100' : item.mucDo === 'H' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                            {item.mucDo === 'T' ? 'Hoàn thành tốt' : item.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành'}
                          </span>
                        </td>
                        <td className="px-6 py-6 text-center font-black text-slate-700">{item.diem > 0 ? item.diem : "-"}</td>
                        <td className="px-6 py-6"><textarea value={item.noiDung} onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))} className="w-full bg-white border border-slate-200 rounded-xl p-4 text-sm font-medium leading-relaxed min-h-[80px] outline-none shadow-sm resize-none" /></td>
                        <td className="px-4 py-6 text-center"><button onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))} className="p-2 text-slate-300 hover:text-rose-500"><Trash2 size={16} /></button></td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
          <div className="p-4 bg-slate-50 flex justify-between items-center border-t border-slate-300">
            <button onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 0, mucDo: 'H', maNhanXet: '', noiDung: '', isProcessing: false }])} className="px-4 py-2 text-indigo-600 hover:bg-indigo-50 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Plus size={16} /> Thêm học sinh</button>
            {records.length > 0 && <button onClick={handleClearData} className="px-4 py-2 text-rose-400 hover:text-rose-600 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Trash2 size={16} /> Xóa danh sách</button>}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">Trường PTDTBT Tiểu học Nấm Dẩn</footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square,
  FileUp
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tính toán mã và nội dung tự động
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      const hasScore = studentScore > 0;
      // Mức độ mặc định là H nếu không có dữ liệu
      const level = record.mucDo || (hasScore ? (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C') : 'H');

      const counterKey = hasScore ? `${level}_score_${studentScore}` : `${level}_noscore`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      const levelCodeForId = level === 'H' ? 'HT' : level;
      const baseCode = `${abbr}${gradeNumber}${levelCodeForId}${counters[counterKey]}`;
      const generatedCode = hasScore ? `${baseCode}D${studentScore}` : baseCode;

      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (hasScore) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo ngân hàng mã nhận xét mới.' });
      } else if (abortControllerRef.current?.signal.aborted) {
        setNotification({ type: 'info', message: 'Đã dừng tạo.' });
      }
    } catch (error: any) {
      if (error.name !== 'AbortError') setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const subjectName = selectedSubject.toLowerCase();
        const subjectAbbr = getSubjectAbbr(selectedSubject).toLowerCase();

        // Tìm sheet phù hợp nhất
        let targetSheetName = wb.SheetNames.find(n => {
          const ln = n.toLowerCase();
          return ln === subjectName || ln === subjectAbbr || ln.includes(subjectName) || ln.includes(subjectAbbr);
        }) || wb.SheetNames[0];

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        // Tìm vị trí các cột dựa trên từ khóa
        let nameIdx = -1, scoreIdx = -1, levelIdx = -1, birthIdx = -1, sttIdx = -1;

        // Duyệt 20 dòng đầu để tìm header
        for (let i = 0; i < Math.min(data.length, 20); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());

          if (sttIdx === -1) sttIdx = row.findIndex(c => c === 'stt' || c.includes('số tt'));
          if (nameIdx === -1) nameIdx = row.findIndex(c => c.includes('họ tên') || c.includes('họ và tên') || c.includes('học sinh'));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => c === 'điểm' || c.includes('ktđk') || c.includes('điểm số'));
          if (levelIdx === -1) levelIdx = row.findIndex(c => c.includes('mức đạt') || c.includes('xếp loại đánh giá') || c.includes('đánh giá'));
          if (birthIdx === -1) birthIdx = row.findIndex(c => c.includes('ngày sinh'));

          if (nameIdx !== -1) {
            const headerRow = i;
            const newRecords = data.slice(headerRow + 1)
              .filter(r => String(r[nameIdx] || "").trim().length > 2)
              .map((r, idx) => {
                // Xử lý điểm số
                let diem = 0;
                if (scoreIdx !== -1) {
                  const val = String(r[scoreIdx] || "").replace(',', '.');
                  const parsed = parseFloat(val);
                  diem = isNaN(parsed) ? 0 : parsed;
                }

                // Xử lý mức đạt được
                let mucDo = "H"; // Mặc định Hoàn thành
                if (levelIdx !== -1) {
                  const rawL = String(r[levelIdx] || "").toUpperCase();
                  if (rawL.includes('TỐT') || rawL === 'T' || rawL.includes('HTT')) mucDo = 'T';
                  else if (rawL.includes('CHƯA') || rawL === 'C' || rawL.includes('CHT')) mucDo = 'C';
                  else if (rawL.includes('HOÀN THÀNH') || rawL === 'H' || rawL.includes('HT')) mucDo = 'H';
                } else if (diem > 0) {
                  // Nếu không có cột mức đạt, tự tính từ điểm
                  mucDo = diem >= 7 ? 'T' : diem >= 5 ? 'H' : 'C';
                }

                return {
                  stt: idx + 1,
                  hoTen: String(r[nameIdx]).trim(),
                  ngaySinh: r[birthIdx] instanceof Date 
                    ? r[birthIdx].toLocaleDateString('vi-VN') 
                    : String(r[birthIdx] || ""),
                  diem,
                  mucDo,
                  maNhanXet: "",
                  noiDung: "",
                  isProcessing: false
                } as StudentRecord;
              });

            setRecords(newRecords);
            setNotification({ type: 'success', message: `Đã nhập dữ liệu từ sheet "${targetSheetName}" thành công.` });
            return;
          }
        }
        setNotification({ type: 'error', message: 'Không tìm thấy cột Họ tên trong sheet. Vui lòng kiểm tra lại file.' });
      } catch (err) { 
        setNotification({ type: 'error', message: 'Lỗi khi đọc file Excel.' }); 
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [
      r.stt, r.hoTen, r.ngaySinh, 
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Mã nhận xét", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedSubject}_Lop${gradeNumber}.xlsx`);
  };

  const handleClearData = () => { if (confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) setRecords([]); };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng | Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex bg-slate-100 p-1 rounded-xl">
              <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer border-r border-slate-200">
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer">
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>

            <div className="h-8 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 shadow-md text-sm font-bold transition-all active:scale-95">
                <Square size={16} fill="currentColor" /> Dừng tạo
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-4 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 shadow-md text-sm font-bold transition-all active:scale-95">
                <Database size={16} /> Tạo ngân hàng
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-bold hover:bg-slate-50 transition-all shadow-sm">
              <FileUp size={16} /> Nhập Excel
            </button>

            <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg shadow-md text-sm font-bold hover:bg-emerald-700 transition-all active:scale-95">
              <Download size={16} /> Xuất file
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Bảng chính
            </button>
            <button onClick={() => setViewMode('content')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Ngân hàng mã
            </button>
          </div>

          <div className="relative w-full sm:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm tên học sinh, mã nhận xét..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm focus:ring-2 focus:ring-indigo-500 transition-all" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center justify-between border shadow-sm ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            <div className="flex items-center gap-3">
              {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
              <span className="font-bold text-sm">{notification.message}</span>
            </div>
            <button onClick={() => setNotification(null)} className="text-xs opacity-50 hover:opacity-100">Đóng</button>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 bg-slate-100/50">Kết quả học tập (Thông tư 27)</th>
                    <th rowSpan={3} className="px-4 py-3 w-16">Xóa</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-40">Mức đạt được</th>
                    <th rowSpan={2} className="px-4 py-2 w-28">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nội dung nhận xét định kỳ</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-36 border-t border-slate-300">Mã NX</th>
                    <th className="px-6 py-2 border-t border-slate-300 text-left">Nội dung cụ thể</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="hover:bg-indigo-50/30 transition-colors">
                      <td className="px-4 py-4 text-center text-xs font-bold text-slate-500">{record.stt}</td>
                      <td className="px-6 py-4 text-sm font-bold text-slate-900">{record.hoTen}</td>
                      <td className="px-4 py-4 text-sm text-slate-500 text-center">{record.ngaySinh}</td>
                      <td className="px-4 py-4 text-center">
                        <span className={`px-2.5 py-1 rounded-md text-[9px] font-black border uppercase shadow-sm ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : record.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-center font-black text-slate-700 text-base">
                        {record.diem > 0 ? (record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)) : "-"}
                      </td>
                      <td className="px-4 py-4 text-center">
                        <span className="text-[11px] font-mono font-black bg-slate-100 px-2 py-1.5 rounded-lg text-slate-600 border border-slate-300">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-4">
                        <textarea 
                          value={record.noiDung} 
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))} 
                          className="w-full bg-transparent border-none text-sm font-medium resize-none min-h-[50px] outline-none leading-relaxed focus:bg-white focus:p-2 focus:rounded-lg focus:shadow-inner transition-all" 
                        />
                      </td>
                      <td className="px-4 py-4 text-center">
                        <button onClick={() => setRecords(records.filter(r => r.stt !== record.stt))} className="p-2 text-slate-300 hover:text-rose-500 transition-colors"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={8} className="py-32 text-center text-slate-300 font-bold uppercase tracking-widest bg-slate-50/50">
                        <FileSpreadsheet className="inline mb-4 opacity-20" size={48} />
                        <br/>Vui lòng chọn môn học và tải file điểm lên
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="table-bordered w-full text-left">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
                  <tr>
                    <th className="px-6 py-5 w-48 text-center">Mã nhận xét mẫu</th>
                    <th className="px-6 py-5 w-40 text-center">Mức đạt</th>
                    <th className="px-6 py-5 w-24 text-center">Điểm</th>
                    <th className="px-6 py-5">Nội dung đề xuất</th>
                    <th className="px-4 py-5 w-16 text-center">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-300">
                  {commentBank.map((item, index) => {
                    const abbr = getSubjectAbbr(selectedSubject);
                    const sameKeyCount = commentBank.slice(0, index + 1).filter(b => b.mucDo === item.mucDo && b.diem === item.diem).length;
                    const levelCode = item.mucDo === 'H' ? 'HT' : item.mucDo;
                    const displayCode = `${abbr}${gradeNumber}${levelCode}${sameKeyCount}${item.diem > 0 ? `D${item.diem}` : ''}`;
                    return (
                      <tr key={item.id} className="hover:bg-indigo-50/10 transition-colors">
                        <td className="px-6 py-6 text-center">
                          <span className="text-xs font-black font-mono px-4 py-2 bg-indigo-50 text-indigo-700 border border-indigo-200 rounded-xl shadow-sm">{displayCode}</span>
                        </td>
                        <td className="px-6 py-6 text-center">
                          <span className={`px-4 py-2 rounded-xl text-[10px] font-black border uppercase inline-block min-w-[140px] shadow-sm ${item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : item.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>
                            {item.mucDo === 'T' ? 'Hoàn thành tốt' : item.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành'}
                          </span>
                        </td>
                        <td className="px-6 py-6 text-center font-black text-slate-700 text-lg">{item.diem > 0 ? item.diem : "-"}</td>
                        <td className="px-6 py-6">
                          <textarea 
                            value={item.noiDung} 
                            onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))} 
                            className="w-full bg-white border border-slate-200 rounded-xl p-5 text-sm font-medium leading-relaxed min-h-[90px] outline-none shadow-sm focus:ring-2 focus:ring-indigo-200 transition-all resize-none" 
                          />
                        </td>
                        <td className="px-4 py-6 text-center">
                          <button onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))} className="p-2.5 text-slate-300 hover:text-rose-500 transition-colors">
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
          <div className="p-5 bg-slate-50 flex justify-between items-center border-t border-slate-300">
            <button onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 0, mucDo: 'H', maNhanXet: '', noiDung: '', isProcessing: false }])} className="px-5 py-2.5 text-indigo-600 hover:bg-indigo-100 rounded-xl text-xs font-black uppercase flex items-center gap-2 transition-all"><Plus size={18} /> Thêm thủ công</button>
            {records.length > 0 && <button onClick={handleClearData} className="px-5 py-2.5 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl text-xs font-black uppercase flex items-center gap-2 transition-all"><Trash2 size={18} /> Xóa danh sách</button>}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-12 text-center text-[11px] text-slate-400 font-bold uppercase tracking-widest">
        Ứng dụng hỗ trợ Giáo viên Tiểu học | Cập nhật TT 27/2020-BGDĐT
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square,
  FileUp
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tính toán mã và nội dung tự động dựa trên mức độ và điểm số
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      const hasScore = studentScore > 0;
      // Mức độ mặc định là H nếu không có dữ liệu
      const level = record.mucDo || (hasScore ? (studentScore >= 7 ? 'T' : studentScore >= 5 ? 'H' : 'C') : 'H');

      const counterKey = hasScore ? `${level}_score_${studentScore}` : `${level}_noscore`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      const levelCodeForId = level === 'H' ? 'HT' : level;
      const baseCode = `${abbr}${gradeNumber}${levelCodeForId}${counters[counterKey]}`;
      // Sử dụng 'D' viết hoa cho mã có điểm
      const generatedCode = hasScore ? `${baseCode}D${studentScore}` : baseCode;

      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (hasScore) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank, gradeNumber]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: 'Đã tạo ngân hàng mã nhận xét mới.' });
      } else if (abortControllerRef.current?.signal.aborted) {
        setNotification({ type: 'info', message: 'Đã dừng tạo.' });
      }
    } catch (error: any) {
      if (error.name !== 'AbortError') setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const subjectName = selectedSubject.toLowerCase();
        const subjectAbbr = getSubjectAbbr(selectedSubject).toLowerCase();

        // Tìm sheet phù hợp nhất với môn học đang chọn
        let targetSheetName = wb.SheetNames.find(n => {
          const ln = n.toLowerCase();
          return ln === subjectName || ln === subjectAbbr || ln.includes(subjectName) || ln.includes(subjectAbbr);
        }) || wb.SheetNames[0];

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        // Từ khóa mở rộng để tìm cột thông minh
        const nameKeywords = ['họ tên', 'họ và tên', 'họ & tên', 'tên học sinh', 'họ tên học sinh', 'full name', 'name'];
        const birthKeywords = ['ngày sinh', 'ngaysinh', 'dob', 'date of birth', 'năm sinh'];
        const scoreKeywords = ['điểm', 'ktđk', 'điểm số', 'score', 'điểm thi', 'thi'];
        const levelKeywords = ['mức đạt', 'mức đạt được', 'xếp loại', 'đánh giá', 'muc do', 'xl', 'level'];
        const sttKeywords = ['stt', 'số tt', 'số thứ tự', 'index', 'no'];

        let nameIdx = -1, scoreIdx = -1, levelIdx = -1, birthIdx = -1, sttIdx = -1;

        // Duyệt qua 20 dòng đầu tiên để xác định dòng tiêu đề (header)
        for (let i = 0; i < Math.min(data.length, 20); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());

          if (sttIdx === -1) sttIdx = row.findIndex(c => sttKeywords.some(k => c === k || c.includes(k)));
          if (nameIdx === -1) nameIdx = row.findIndex(c => nameKeywords.some(k => c === k || c.includes(k)));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => scoreKeywords.some(k => c === k || c.includes(k)));
          if (levelIdx === -1) levelIdx = row.findIndex(c => levelKeywords.some(k => c === k || c.includes(k)));
          if (birthIdx === -1) birthIdx = row.findIndex(c => birthKeywords.some(k => c === k || c.includes(k)));

          // Nếu đã tìm thấy cột Họ tên, coi đây là dòng header và bắt đầu lấy dữ liệu từ dòng kế tiếp
          if (nameIdx !== -1) {
            const headerRow = i;
            const newRecords = data.slice(headerRow + 1)
              .filter(r => String(r[nameIdx] || "").trim().length > 1) // Lọc bỏ dòng trống
              .map((r, idx) => {
                // 1. Xử lý Họ và tên
                const hoTen = String(r[nameIdx] || "").trim();

                // 2. Xử lý Ngày sinh
                let ngaySinh = "";
                if (birthIdx !== -1) {
                  const rawBirth = r[birthIdx];
                  if (rawBirth instanceof Date) {
                    ngaySinh = rawBirth.toLocaleDateString('vi-VN');
                  } else {
                    ngaySinh = String(rawBirth || "").trim();
                  }
                }

                // 3. Xử lý Điểm KTĐK
                let diem = 0;
                if (scoreIdx !== -1) {
                  const val = String(r[scoreIdx] || "").replace(',', '.');
                  const parsed = parseFloat(val);
                  diem = isNaN(parsed) ? 0 : parsed;
                }

                // 4. Xử lý Mức đạt được
                let mucDo = "";
                if (levelIdx !== -1) {
                  const rawL = String(r[levelIdx] || "").toUpperCase();
                  if (rawL.includes('TỐT') || rawL === 'T' || rawL.includes('HTT')) mucDo = 'T';
                  else if (rawL.includes('CHƯA') || rawL === 'C' || rawL.includes('CHT')) mucDo = 'C';
                  else if (rawL.includes('HOÀN THÀNH') || rawL === 'H' || rawL.includes('HT')) mucDo = 'H';
                }

                // Tự động gán mức độ nếu cột mức đạt trống nhưng có điểm
                if (!mucDo && diem > 0) {
                  mucDo = diem >= 7 ? 'T' : diem >= 5 ? 'H' : 'C';
                } else if (!mucDo) {
                  mucDo = 'H'; // Mặc định là Hoàn thành cho môn không điểm
                }

                return {
                  stt: idx + 1,
                  hoTen,
                  ngaySinh,
                  diem,
                  mucDo,
                  maNhanXet: "",
                  noiDung: "",
                  isProcessing: false
                } as StudentRecord;
              });

            setRecords(newRecords);
            setNotification({ type: 'success', message: `Đã nhập ${newRecords.length} học sinh từ sheet "${targetSheetName}".` });
            return;
          }
        }
        setNotification({ type: 'error', message: 'Không nhận diện được các cột dữ liệu cần thiết. Hãy đảm bảo file có cột "Họ tên".' });
      } catch (err) { 
        setNotification({ type: 'error', message: 'Lỗi khi xử lý file Excel. Vui lòng thử lại.' }); 
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [
      r.stt, r.hoTen, r.ngaySinh, 
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Mã nhận xét", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedSubject}_Lop${gradeNumber}.xlsx`);
  };

  const handleClearData = () => { if (confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách hiện tại?")) setRecords([]); };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg">
              <BookOpen size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Nhận Xét TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng | Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex bg-slate-100 p-1 rounded-xl">
              <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer border-r border-slate-200">
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer">
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>

            <div className="h-8 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 shadow-md text-sm font-bold transition-all active:scale-95">
                <Square size={16} fill="currentColor" /> Dừng tạo
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-4 py-2 bg-amber-500 text-white rounded-lg hover:bg-amber-600 shadow-md text-sm font-bold transition-all active:scale-95">
                <Database size={16} /> Tạo ngân hàng
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-bold hover:bg-slate-50 transition-all shadow-sm">
              <FileUp size={16} /> Nhập Excel
            </button>

            <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg shadow-md text-sm font-bold hover:bg-emerald-700 transition-all active:scale-95">
              <Download size={16} /> Xuất file
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1 rounded-xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Bảng chính
            </button>
            <button onClick={() => setViewMode('content')} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Ngân hàng mã
            </button>
          </div>

          <div className="relative w-full sm:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm tên học sinh, mã nhận xét..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none shadow-sm focus:ring-2 focus:ring-indigo-500 transition-all" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-xl flex items-center justify-between border shadow-sm ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            <div className="flex items-center gap-3">
              {notification.type === 'success' ? <CheckCircle2 size={20} className="text-emerald-600" /> : <AlertCircle size={20} className="text-rose-600" />}
              <span className="font-bold text-sm">{notification.message}</span>
            </div>
            <button onClick={() => setNotification(null)} className="text-xs opacity-50 hover:opacity-100">Đóng</button>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-xl border border-slate-300 overflow-hidden">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center">
                  <tr>
                    <th rowSpan={3} className="px-4 py-3 w-12">STT</th>
                    <th rowSpan={3} className="px-6 py-3 w-64">Họ và tên</th>
                    <th rowSpan={3} className="px-4 py-3 w-32">Ngày sinh</th>
                    <th colSpan={4} className="px-4 py-2 bg-slate-100/50">Kết quả học tập (Thông tư 27)</th>
                    <th rowSpan={3} className="px-4 py-3 w-16">Xóa</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-40">Mức đạt được</th>
                    <th rowSpan={2} className="px-4 py-2 w-28">Điểm KTĐK</th>
                    <th colSpan={2} className="px-4 py-2">Nội dung nhận xét định kỳ</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-36 border-t border-slate-300">Mã NX</th>
