export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  diem: number;
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string,
  semester: string,
  signal?: AbortSignal
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const semesterContext = semester === "Học kỳ 1" 
    ? "Cuối Học kỳ 1: Tập trung vào sự thích nghi với nền nếp, nỗ lực chuyên cần đi học đều dù thời tiết khó khăn và bước đầu nắm vững kiến thức trọng tâm."
    : "Cuối Học kỳ 2 (Tổng kết năm): Đánh giá sự tiến bộ rõ rệt sau một năm học, sự tự tin trong giao tiếp và kiến thức nền tảng để sẵn sàng lên lớp trên.";

  const prompt = `Hãy tạo ngân hàng nhận xét cho học sinh VÙNG CAO môn ${subject}, khối ${gradeLevel}, ${semester}.
  Bối cảnh địa phương: ${semesterContext}

  SỐ LƯỢNG MẪU CẦN TẠO THEO QUY ĐỊNH:
  - Điểm 10: Tạo 3 mẫu (Mức T)
  - Điểm 9: Tạo 3 mẫu (Mức T)
  - Điểm 8: Tạo 4 mẫu (Mức T)
  - Điểm 7: Tạo 6 mẫu (Mức H)
  - Điểm 6: Tạo 6 mẫu (Mức H)
  - Điểm 5: Tạo 6 mẫu (Mức H)
  - Điểm 4: Tạo 2 mẫu (Mức C)
  - Điểm 3: Tạo 2 mẫu (Mức C)

  TỔNG CỘNG: 32 mẫu nhận xét.

  Gợi ý nội dung vùng cao: 
  - Khen ngợi việc đi học chuyên cần dù đường xa.
  - Khen ngợi sự tiến bộ trong phát âm, diễn đạt tiếng Việt.
  - Góp ý về sự tự tin, mạnh dạn tham gia hoạt động tập thể.

  Trả về mảng JSON gồm các đối tượng { mucDo: "T"|"H"|"C", diem: number, noiDung: "chuỗi nhận xét" }.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              diem: { type: Type.NUMBER },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "diem", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error: any) {
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string,
  semester: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Viết nhận xét học sinh VÙNG CAO. Môn: ${subject}. Khối: ${gradeLevel}. ${semester}. Danh sách: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square,
  FileUp,
  FileDown,
  CalendarDays,
  Mountain
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';
const HOC_KY = ["Học kỳ 1", "Học kỳ 2"];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [selectedSemester, setSelectedSemester] = useState(HOC_KY[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  // Logic tính toán mã và nội dung tự động dựa trên mức độ và điểm số
  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;

      let level = record.mucDo;
      if (!level && studentScore > 0) {
        if (studentScore >= 8) level = 'T';
        else if (studentScore >= 5) level = 'H';
        else level = 'C';
      }
      level = level || 'H';

      const counterKey = `${studentScore}_${level}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;

      const scoreStr = studentScore > 0 ? studentScore.toString() : "";
      const generatedCode = `${abbr}${scoreStr}${level}${counters[counterKey]}`;

      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (studentScore > 0) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, selectedSemester, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: `Đã tạo ngân hàng mẫu nhận xét đặc thù học sinh vùng cao cho ${selectedSemester}.` });
      }
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const subjectName = selectedSubject.toLowerCase();
        const subjectAbbr = getSubjectAbbr(selectedSubject).toLowerCase();

        let targetSheetName = wb.SheetNames.find(n => {
          const ln = n.toLowerCase();
          return ln === subjectName || ln === subjectAbbr || ln.includes(subjectName) || ln.includes(subjectAbbr);
        }) || wb.SheetNames[0];

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        const nameKeywords = ['họ tên', 'họ và tên', 'họ & tên', 'tên học sinh', 'họ tên học sinh', 'full name', 'name'];
        const scoreKeywords = ['điểm', 'ktđk', 'điểm số', 'score', 'điểm thi', 'thi'];

        let nameIdx = -1, scoreIdx = -1;

        for (let i = 0; i < Math.min(data.length, 20); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());
          if (nameIdx === -1) nameIdx = row.findIndex(c => nameKeywords.some(k => c === k || c.includes(k)));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => scoreKeywords.some(k => c === k || c.includes(k)));

          if (nameIdx !== -1) {
            const headerRow = i;
            const newRecords = data.slice(headerRow + 1)
              .filter(r => String(r[nameIdx] || "").trim().length > 1)
              .map((r, idx) => {
                const hoTen = String(r[nameIdx] || "").trim();
                let diem = 0;
                if (scoreIdx !== -1) {
                  const val = String(r[scoreIdx] || "").replace(',', '.');
                  const parsed = parseFloat(val);
                  diem = isNaN(parsed) ? 0 : parsed;
                }
                return { stt: idx + 1, hoTen, ngaySinh: "", diem, mucDo: "", maNhanXet: "", noiDung: "", isProcessing: false } as StudentRecord;
              });

            setRecords(newRecords);
            setNotification({ type: 'success', message: `Đã nhập ${newRecords.length} học sinh.` });
            return;
          }
        }
      } catch (err) { 
        setNotification({ type: 'error', message: 'Lỗi khi xử lý file Excel.' }); 
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [
      r.stt, r.hoTen, r.ngaySinh, 
      r.mucDo === 'T' ? 'Hoàn thành tốt' : r.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
      r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung
    ]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ và tên", "Ngày sinh", "Mức đạt được", "Điểm KTĐK", "Mã nhận xét", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    const kyHieuKy = selectedSemester === "Học kỳ 1" ? "HK1" : "HK2";
    XLSX.writeFile(wb, `NhanXet_VungCao_${selectedSubject}_Lop${gradeNumber}_${kyHieuKy}.xlsx`);
  };

  const exportBankToExcel = () => {
    if (commentBank.length === 0) return;
    const abbr = getSubjectAbbr(selectedSubject);
    const data = commentBank.map((item, index) => {
      const sameScoreGroup = commentBank.slice(0, index + 1).filter(b => b.diem === item.diem);
      const counter = sameScoreGroup.length;
      const scoreStr = item.diem > 0 ? item.diem.toString() : "";
      const displayCode = `${abbr}${scoreStr}${item.mucDo}${counter}`;

      return {
        "STT": index + 1,
        "Mã nhận xét": displayCode,
        "Mức đạt được": item.mucDo === 'T' ? 'Hoàn thành tốt' : item.mucDo === 'H' ? 'Hoàn thành' : 'Chưa hoàn thành',
        "Điểm số": item.diem,
        "Học kỳ": selectedSemester,
        "Nội dung nhận xét": item.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMaNX");
    XLSX.writeFile(wb, `NganHangMaNX_VungCao_${selectedSubject}_HK${selectedSemester === "Học kỳ 1" ? "1" : "2"}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg relative overflow-hidden">
              <BookOpen size={24} className="relative z-10" />
              <Mountain size={16} className="absolute -bottom-1 -right-1 opacity-40 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Vùng Cao TT 27</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng | Nấm Dẩn</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex bg-slate-100 p-1 rounded-xl items-center shadow-inner border border-slate-200">
              <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer border-r border-slate-200 hover:text-indigo-600 transition-colors">
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer border-r border-slate-200 hover:text-indigo-600 transition-colors">
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <div className="px-3 flex items-center gap-1.5 group cursor-pointer">
                <CalendarDays size={14} className="text-slate-400 group-hover:text-indigo-500 transition-colors" />
                <select value={selectedSemester} onChange={(e) => setSelectedSemester(e.target.value)} className="bg-transparent text-sm font-bold outline-none cursor-pointer text-indigo-600 hover:text-indigo-800 transition-colors">
                  {HOC_KY.map(h => <option key={h} value={h}>{h}</option>)}
                </select>
              </div>
            </div>

            <div className="h-8 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-5 py-2.5 bg-rose-600 text-white rounded-xl hover:bg-rose-700 shadow-md text-sm font-bold transition-all active:scale-95 animate-pulse">
                <Square size={16} fill="currentColor" /> Dừng tạo
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-5 py-2.5 bg-amber-500 text-white rounded-xl hover:bg-amber-600 shadow-md text-sm font-bold transition-all active:scale-95 group">
                <Database size={16} className="group-hover:rotate-12 transition-transform" /> Tạo ngân hàng Vùng Cao
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl text-sm font-bold hover:bg-slate-50 transition-all shadow-sm">
              <FileUp size={16} /> Nhập Excel
            </button>

            {viewMode === 'table' ? (
              <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl shadow-md text-sm font-bold hover:bg-emerald-700 transition-all active:scale-95">
                <Download size={16} /> Xuất nhận xét
              </button>
            ) : (
              <button onClick={exportBankToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl shadow-md text-sm font-bold hover:bg-indigo-700 transition-all active:scale-95">
                <FileDown size={16} /> Xuất ngân hàng (.xlsx)
              </button>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Bảng nhận xét học sinh
            </button>
            <button onClick={() => setViewMode('content')} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Ngân hàng mã nhận xét
            </button>
          </div>

          <div className="relative w-full sm:w-96">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm tên, mã nhận xét..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm outline-none shadow-sm focus:ring-4 focus:ring-indigo-100 transition-all border-slate-300" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-5 rounded-2xl flex items-center justify-between border shadow-lg animate-in slide-in-from-top duration-300 ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            <div className="flex items-center gap-4">
              {notification.type === 'success' ? <CheckCircle2 size={24} className="text-emerald-600" /> : <AlertCircle size={24} className="text-rose-600" />}
              <div className="font-bold text-sm tracking-tight">{notification.message}</div>
            </div>
            <button onClick={() => setNotification(null)} className="p-1 hover:bg-black/5 rounded-full transition-colors opacity-50 hover:opacity-100">X</button>
          </div>
        )}

        <div className="bg-white rounded-[2rem] shadow-2xl border border-slate-200 overflow-hidden mb-12">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1200px] border-none">
                <thead className="bg-slate-50/80 text-slate-600 font-bold text-center border-b-2 border-slate-200">
                  <tr>
                    <th rowSpan={3} className="px-4 py-4 w-12 text-center text-xs text-slate-400">#</th>
                    <th rowSpan={3} className="px-6 py-4 w-64 text-left">Học sinh (Vùng cao)</th>
                    <th colSpan={4} className="px-4 py-3 bg-slate-100/50 text-[10px] tracking-[0.2em] uppercase text-indigo-500">Kết quả đánh giá theo TT 27 - {selectedSemester}</th>
                    <th rowSpan={3} className="px-4 py-4 w-16">Tác vụ</th>
                  </tr>
                  <tr>
                    <th rowSpan={2} className="px-4 py-2 w-40">Mức đạt được</th>
                    <th rowSpan={2} className="px-4 py-2 w-28">Điểm số</th>
                    <th colSpan={2} className="px-4 py-2">Nhận xét chi tiết</th>
                  </tr>
                  <tr>
                    <th className="px-4 py-2 w-36 border-t border-slate-200 text-xs text-slate-400 uppercase tracking-tighter">Mã mẫu</th>
                    <th className="px-6 py-2 border-t border-slate-200 text-left">Nội dung đã chọn</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredRecords.map((record) => (
                    <tr key={record.stt} className="group hover:bg-indigo-50/40 transition-all">
                      <td className="px-4 py-5 text-center text-xs font-bold text-slate-300">{record.stt}</td>
                      <td className="px-6 py-5">
                        <div className="flex flex-col">
                          <span className="text-sm font-bold text-slate-900 group-hover:text-indigo-600 transition-colors">{record.hoTen}</span>
                          <span className="text-[10px] text-slate-400 font-medium">Lớp {gradeNumber} - {selectedSubject}</span>
                        </div>
                      </td>
                      <td className="px-4 py-5 text-center">
                        <span className={`px-3 py-1.5 rounded-lg text-[9px] font-black border uppercase shadow-sm ${record.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : record.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>
                          {record.mucDo === 'T' ? 'HTT' : record.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-4 py-5 text-center font-black text-slate-700 text-lg">
                        {record.diem > 0 ? (record.diem % 1 === 0 ? record.diem : record.diem.toFixed(1)) : "-"}
                      </td>
                      <td className="px-4 py-5 text-center">
                        <span className="text-[10px] font-mono font-black bg-white px-2.5 py-2 rounded-xl text-slate-500 border border-slate-200 shadow-sm">{record.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-5">
                        <textarea 
                          value={record.noiDung} 
                          onChange={(e) => setRecords(records.map(r => r.stt === record.stt ? { ...r, noiDung: e.target.value } : r))} 
                          className="w-full bg-transparent border-none text-sm font-medium resize-none min-h-[60px] outline-none leading-relaxed focus:bg-white focus:ring-1 focus:ring-slate-100 focus:p-3 focus:rounded-2xl focus:shadow-xl transition-all scrollbar-hide" 
                          placeholder="Chọn hoặc nhập nhận xét..."
                        />
                      </td>
                      <td className="px-4 py-5 text-center">
                        <button onClick={() => setRecords(records.filter(r => r.stt !== record.stt))} className="p-2.5 text-slate-200 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
