          <Mountain size={16} />
          <span className="text-[10px] font-black uppercase tracking-[0.3em]">Hỗ trợ giáo dục vùng cao</span>
        </div>
        <div className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">
          Phần mềm Trợ lý Giáo viên | PTDTBT TH Nấm Dẩn | Phiên bản 2.5
        </div>
      </footer>
    </div>
  );
};

