import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên tại vùng cao, dạy học sinh dân tộc thiểu số.
Nhiệm vụ: Viết nhận xét học bạ theo Thông tư 27.

YÊU CẦU VỀ NỘI DUNG:
1. ĐỘ DÀI: Khoảng 150 ký tự (không quá ngắn cũng không quá dài).
2. CẤU TRÚC: Gồm 2 câu văn hoàn chỉnh.
   - Câu 1: Khen ngợi sự tiến bộ về kiến thức hoặc tính chuyên cần (ví dụ: đi học đều, viết chữ rõ ràng, tính toán nhanh).
   - Câu 2: Góp ý nhẹ nhàng và đưa ra lời khuyên thực tế (ví dụ: cần tập nói tiếng phổ thông nhiều hơn, chăm đọc sách tại lớp).
3. ĐỐI TƯỢNG: Sử dụng từ ngữ phổ thông giản dị, dễ hiểu với bà con vùng cao.
4. QUY ĐỊNH CẤM: 
   - Không dùng tên riêng học sinh. 
   - Không dùng "em", không dùng "nám".
   - Không dùng từ ngữ chuyên môn trừu tượng.
5. VĂN PHONG: Gần gũi, khích lệ nỗ lực vượt khó của học sinh miền núi.

PHÂN LOẠI MỨC ĐỘ:
- T (8-10 điểm): Hoàn thành tốt.
- H (5-7 điểm): Hoàn thành.
- C (dưới 5 điểm): Chưa hoàn thành.
`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  diem: number;
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string,
  semester: string,
  signal?: AbortSignal
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Tạo ngân hàng nhận xét khoảng 150 ký tự cho học sinh vùng cao. 
  Môn: ${subject}, Khối: ${gradeLevel}, ${semester}.

  SỐ LƯỢNG MẪU CẦN TẠO:
  - Mức T (8-10 điểm): 10 mẫu (Khen ngợi sự gương mẫu, hiểu bài nhanh).
  - Mức H (5-7 điểm): 12 mẫu (Khen sự chuyên cần, nắm được kiến thức cơ bản).
  - Mức C (dưới 5 điểm): 4 mẫu (Động viên đi học đều, rèn luyện thêm chữ viết/phép tính).

  Lưu ý: Nội dung phải sát với thực tế học sinh dân tộc và đặc thù của ${semester}.
  Trả về mảng JSON: [{ "mucDo": "T"|"H"|"C", "diem": number, "noiDung": "chuỗi nhận xét khoảng 150 ký tự" }].`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              diem: { type: Type.NUMBER },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "diem", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error: any) {
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string,
  semester: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Viết nhận xét khoảng 150 ký tự cho học sinh vùng dân tộc. Môn: ${subject}. Khối: ${gradeLevel}. ${semester}. Danh sách: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}. Trả về JSON [{stt, noiDung}].`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square,
  FileUp,
  FileDown,
  CalendarDays,
  Mountain
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';
const HOC_KY = ["Học kỳ 1", "Học kỳ 2"];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [selectedSemester, setSelectedSemester] = useState(HOC_KY[0]);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      let level = record.mucDo;
      if (!level && studentScore > 0) {
        if (studentScore >= 8) level = 'T';
        else if (studentScore >= 5) level = 'H';
        else level = 'C';
      }
      level = level || 'H';

      const counterKey = `${studentScore}_${level}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;
      const scoreStr = studentScore > 0 ? studentScore.toString() : "";
      const generatedCode = `${abbr}${scoreStr}${level}${counters[counterKey]}`;
      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (studentScore > 0) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, selectedSemester, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: `Đã tạo mẫu nhận xét (~150 ký tự) cho học sinh vùng cao.` });
      }
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];
        const nameKeywords = ['họ tên', 'họ và tên', 'tên học sinh'];
        const scoreKeywords = ['điểm', 'ktđk', 'điểm số'];
        let nameIdx = -1, scoreIdx = -1;
        for (let i = 0; i < Math.min(data.length, 10); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());
          if (nameIdx === -1) nameIdx = row.findIndex(c => nameKeywords.some(k => c.includes(k)));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => scoreKeywords.some(k => c.includes(k)));
          if (nameIdx !== -1) {
            const newRecords = data.slice(i + 1)
              .filter(r => String(r[nameIdx] || "").trim().length > 1)
              .map((r, idx) => ({
                stt: idx + 1,
                hoTen: String(r[nameIdx] || "").trim(),
                ngaySinh: "",
                diem: scoreIdx !== -1 ? parseFloat(String(r[scoreIdx]).replace(',', '.')) || 0 : 0,
                mucDo: "", maNhanXet: "", noiDung: "", isProcessing: false
              } as StudentRecord));
            setRecords(newRecords);
            setNotification({ type: 'success', message: `Đã nhập danh sách ${newRecords.length} học sinh.` });
            return;
          }
        }
      } catch (err) { setNotification({ type: 'error', message: 'Lỗi xử lý file Excel.' }); }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [r.stt, r.hoTen, r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : 'CHT', r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ tên", "Mức đạt", "Điểm", "Mã NX", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `NhanXet_VungCao_${selectedSubject}_HK${selectedSemester === "Học kỳ 1" ? "1" : "2"}.xlsx`);
  };

  const exportBankToExcel = () => {
    if (commentBank.length === 0) return;
    const abbr = getSubjectAbbr(selectedSubject);
    const data = commentBank.map((item, index) => {
      const sameGroup = commentBank.slice(0, index + 1).filter(b => b.diem === item.diem);
      const displayCode = `${abbr}${item.diem || ""}${item.mucDo}${sameGroup.length}`;
      return {
        "STT": index + 1,
        "Mã": displayCode,
        "Mức đạt": item.mucDo === 'T' ? 'Tốt' : item.mucDo === 'H' ? 'HT' : 'CHT',
        "Điểm": item.diem,
        "Nội dung nhận xét (Dân tộc thiểu số)": item.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHangMa_VungCao_HK${selectedSemester === "Học kỳ 1" ? "1" : "2"}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg relative">
              <BookOpen size={24} />
              <Mountain size={14} className="absolute -bottom-1 -right-1 text-white opacity-40" />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Vùng Cao (150 ký tự)</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Thầy Nguyễn Đức Hùng | Nấm Dẩn</p>
            </div>
