import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là giáo viên tiểu học tại vùng cao (ví dụ: Hà Giang, Lào Cai). Học sinh là người dân tộc thiểu số (Mông, Dao, Tày...).
Nhiệm vụ: Viết nhận xét học bạ (Thông tư 27) khoảng 150 ký tự.

YÊU CẦU VỀ NỘI DUNG (PHẢI KHỚP VỚI ĐIỂM SỐ VÀ KHỐI LỚP):
1. ĐỐI VỚI ĐIỂM SỐ:
   - Điểm 9, 10 (Tốt): Khen ngợi sự thông minh, hiểu bài rất nhanh, đi học rất chuyên cần. Biết giúp đỡ bạn bè cùng tiến bộ.
   - Điểm 7, 8 (Khá/Tốt): Khen sự chăm chỉ, làm bài đầy đủ, chữ viết rõ ràng. Biết lắng nghe thầy cô giảng bài.
   - Điểm 5, 6 (Hoàn thành): Khen sự nỗ lực, đi học đều. Góp ý cần tập nói tiếng phổ thông nhiều hơn hoặc tập tính toán kỹ hơn.
   - Dưới 5 (Chưa hoàn thành): Động viên con đi học đều hơn. Góp ý tập trung rèn lại các nét chữ hoặc các phép tính cộng trừ đơn giản.

2. ĐỐI VỚI KHỐI LỚP:
   - Khối 1: Tập trung vào: nhận mặt chữ, con số, cách cầm bút, tư thế ngồi, biết chào hỏi.
   - Khối 2-3: Tập trung vào: đọc trôi chảy, viết đúng chính tả, thuộc bảng cửu chương, mạnh dạn phát biểu.
   - Khối 4-5: Tập trung vào: giải toán có lời văn, viết văn sinh động, tự giác học bài, hoàn thành tốt các bài tập khó.

3. PHONG CÁCH NGÔN NGỮ:
   - Đơn giản, mộc mạc, chân thành. Tránh dùng từ chuyên môn khó hiểu.
   - Câu văn ngắn gọn, súc tích (khoảng 2-3 câu).
   - KHÔNG dùng tên riêng, KHÔNG dùng từ "em", KHÔNG dùng "nám".

VÍ DỤ TỐT: "Biết đọc chữ và làm toán rất nhanh. Đi học chuyên cần, hay giơ tay phát biểu xây dựng bài. Cần phát huy sự tự tin này nhiều hơn nữa."
`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  diem: number;
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string,
  semester: string,
  signal?: AbortSignal
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Hãy tạo ngân hàng mẫu nhận xét cho học sinh dân tộc thiểu số vùng cao (~150 ký tự/mẫu).
  Môn: ${subject}. ${gradeLevel}. ${semester}.

  YÊU CẦU SỐ LƯỢNG VÀ NỘI DUNG CHI TIẾT:
  - Điểm 10, 9: Tạo 8 mẫu (Khen hiểu bài sâu, diễn đạt tốt, gương mẫu).
  - Điểm 8, 7: Tạo 10 mẫu (Khen chăm chỉ, chữ viết đẹp, làm toán chắc chắn).
  - Điểm 6, 5: Tạo 10 mẫu (Khen tiến bộ, đi học đều, cần tập trung hơn).
  - Điểm 4, 3: Tạo 4 mẫu (Nhắc nhở đi học đều, rèn thêm kiến thức hổng).

  Lưu ý: Nội dung phải phản ánh đúng đặc thù kiến thức của ${gradeLevel}. Trả về JSON.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              diem: { type: Type.NUMBER },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "diem", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error: any) {
    console.error("Error generating bank:", error);
    return [];
  }
};

