                <Trash2 size={18} /> Xóa danh sách
              </button>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-16 text-center bg-white/50 backdrop-blur-sm">
        <div className="flex items-center justify-center gap-2 text-slate-300 mb-2">
