  FileSpreadsheet,
  Square,
  FileUp,
  FileDown,
  CalendarDays,
  Mountain
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';
const HOC_KY = ["Học kỳ 1", "Học kỳ 2"];

const App: React.FC = () => {
