  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const gradeNumber = useMemo(() => selectedGrade.replace(/\D/g, ''), [selectedGrade]);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      let level = record.mucDo;

      // Nếu chưa có mức đạt nhưng có điểm, tự tính toán
      if (!level && studentScore > 0) {
        if (studentScore >= 8) level = 'T';
        else if (studentScore >= 5) level = 'H';
        else level = 'C';
      }
      level = level || 'H';

      const counterKey = `${studentScore}_${level}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;
      const scoreStr = studentScore > 0 ? studentScore.toString() : "";
      const generatedCode = `${abbr}${scoreStr}${level}${counters[counterKey]}`;
      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (studentScore > 0) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, selectedSemester, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: `Đã tạo mẫu nhận xét dân tộc cho môn ${selectedSubject}.` });
      }
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        // Tự tìm sheet phù hợp với môn học
        const subjectLower = selectedSubject.toLowerCase();
        const subjectAbbr = getSubjectAbbr(selectedSubject).toLowerCase();

        const targetSheetName = wb.SheetNames.find(name => {
          const n = name.toLowerCase();
          return n.includes(subjectLower) || n === subjectAbbr || n.includes(subjectAbbr);
        }) || wb.SheetNames[0];

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        // Từ khóa tìm kiếm cột
        const nameKeywords = ['họ tên', 'họ và tên', 'tên học sinh', 'họ và tên học sinh'];
        const levelKeywords = ['mức đạt được', 'mức đạt', 'xếp loại', 'đánh giá'];
        const scoreKeywords = ['điểm ktđk', 'ktđk', 'điểm số', 'điểm kiểm tra'];

        let nameIdx = -1, levelIdx = -1, scoreIdx = -1;
        let startRow = 0;

        // Tìm hàng tiêu đề
        for (let i = 0; i < Math.min(data.length, 15); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());
          if (nameIdx === -1) nameIdx = row.findIndex(c => nameKeywords.some(k => c.includes(k)));
          if (levelIdx === -1) levelIdx = row.findIndex(c => levelKeywords.some(k => c.includes(k)));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => scoreKeywords.some(k => c.includes(k)));

          if (nameIdx !== -1) {
            startRow = i + 1;
            break;
          }
        }

        if (nameIdx === -1) {
          setNotification({ type: 'error', message: `Không tìm thấy cột Họ Tên trong sheet "${targetSheetName}".` });
          return;
        }

        const newRecords = data.slice(startRow)
          .filter(r => String(r[nameIdx] || "").trim().length > 1)
          .map((r, idx) => {
            // Xử lý chuẩn hóa Mức đạt
            let rawLevel = String(r[levelIdx] || "").trim().toUpperCase();
            let level = "";
            if (rawLevel.includes("TỐT") || rawLevel === "T" || rawLevel.includes("HTT")) level = "T";
            else if (rawLevel.includes("CHƯA") || rawLevel === "C" || rawLevel.includes("CHT")) level = "C";
            else if (rawLevel.includes("HOÀN THÀNH") || rawLevel === "H" || rawLevel === "HT") level = "H";

            // Xử lý điểm số
            let rawScore = r[scoreIdx];
            let diem = 0;
            if (rawScore !== undefined && rawScore !== "") {
              diem = parseFloat(String(rawScore).replace(',', '.')) || 0;
            }

            return {
              stt: idx + 1,
              hoTen: String(r[nameIdx] || "").trim(),
              ngaySinh: "",
              diem: diem,
              mucDo: level,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false
            } as StudentRecord;
          });

        setRecords(newRecords);
        setNotification({ 
          type: 'success', 
          message: `Đã nhập ${newRecords.length} học sinh từ sheet "${targetSheetName}".` 
        });

      } catch (err) { 
        setNotification({ type: 'error', message: 'Lỗi xử lý file Excel. Vui lòng kiểm tra định dạng.' }); 
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [r.stt, r.hoTen, r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : 'CHT', r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ tên", "Mức đạt", "Điểm KTĐK", "Mã NX", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "BangNhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedGrade}_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    if (commentBank.length === 0) return;
    const abbr = getSubjectAbbr(selectedSubject);
    const data = commentBank.map((item, index) => {
      const sameGroup = commentBank.slice(0, index + 1).filter(b => b.diem === item.diem);
      const displayCode = `${abbr}${item.diem || ""}${item.mucDo}${sameGroup.length}`;
      return {
        "STT": index + 1,
        "Mã": displayCode,
        "Mức đạt": item.mucDo === 'T' ? 'Tốt' : item.mucDo === 'H' ? 'HT' : 'CHT',
        "Điểm số": item.diem,
        "Nội dung nhận xét (Vùng cao)": item.noiDung
      };
    });
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NganHangMa");
    XLSX.writeFile(wb, `NganHang_${selectedGrade}_DânTộc.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 text-slate-900 font-medium">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg relative">
              <BookOpen size={24} />
              <Mountain size={14} className="absolute -bottom-1 -right-1 text-white opacity-40" />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">Trợ Lý Vùng Cao ({selectedGrade})</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Môn: {selectedSubject} | Tự tìm sheet thông minh</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex bg-slate-100 p-1 rounded-xl items-center border border-slate-200">
              <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer border-r border-slate-200">
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer border-r border-slate-200">
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <select value={selectedSemester} onChange={(e) => setSelectedSemester(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none cursor-pointer text-indigo-600">
                {HOC_KY.map(h => <option key={h} value={h}>{h}</option>)}
              </select>
            </div>

            <div className="h-8 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-5 py-2.5 bg-rose-600 text-white rounded-xl shadow-md text-sm font-bold animate-pulse">
                <Square size={16} fill="currentColor" /> Dừng
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-5 py-2.5 bg-amber-500 text-white rounded-xl shadow-md text-sm font-bold transition-all active:scale-95 group">
                <Database size={16} className="group-hover:rotate-12 transition-transform" /> Tạo nhận xét AI
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl text-sm font-bold hover:bg-slate-50 transition-colors">
              <FileUp size={16} /> Nhập Excel ({getSubjectAbbr(selectedSubject)})
            </button>

            {viewMode === 'table' ? (
              <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl shadow-md text-sm font-bold active:scale-95">
                <Download size={16} /> Xuất nhận xét
              </button>
            ) : (
              <button onClick={exportBankToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl shadow-md text-sm font-bold active:scale-95">
                <FileDown size={16} /> Xuất ngân hàng (.xlsx)
              </button>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Học sinh {selectedGrade}
            </button>
            <button onClick={() => setViewMode('content')} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Ngân hàng mẫu
            </button>
          </div>
          <div className="relative w-full sm:w-96">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm tên, mã nhận xét..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3 bg-white border border-slate-300 rounded-2xl text-sm outline-none shadow-sm focus:ring-4 focus:ring-indigo-100 transition-all font-medium" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center justify-between border shadow-sm ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            <div className="flex items-center gap-3">
              <CheckCircle2 size={20} className={notification.type === 'success' ? 'text-emerald-600' : 'text-rose-600'} />
              <span className="font-bold text-sm tracking-tight">{notification.message}</span>
            </div>
            <button onClick={() => setNotification(null)} className="opacity-50 hover:opacity-100 transition-opacity">Đóng</button>
          </div>
        )}

        <div className="bg-white rounded-[2rem] shadow-2xl border border-slate-200 overflow-hidden mb-12">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1000px] border-none">
                <thead className="bg-slate-50 text-slate-600 font-bold text-center border-b-2 border-slate-200">
                  <tr>
                    <th className="px-4 py-4 w-12 text-slate-400 font-black">#</th>
                    <th className="px-6 py-4 w-64 text-left">Học sinh ({selectedGrade})</th>
                    <th className="px-4 py-4 w-28">Mức đạt</th>
                    <th className="px-4 py-4 w-24">Điểm KTĐK</th>
                    <th className="px-4 py-4 w-32">Mã NX</th>
                    <th className="px-6 py-4 text-left">Nhận xét mộc mạc (~150 ký tự)</th>
                    <th className="px-4 py-4 w-16 text-slate-400">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredRecords.map((r) => (
                    <tr key={r.stt} className="group hover:bg-indigo-50/40 transition-all">
                      <td className="px-4 py-5 text-center text-xs text-slate-300 font-bold">{r.stt}</td>
                      <td className="px-6 py-5 text-sm font-bold text-slate-900 tracking-tight">{r.hoTen}</td>
                      <td className="px-4 py-5 text-center">
                        <span className={`px-3 py-1 rounded-lg text-[9px] font-black border uppercase shadow-sm ${r.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : r.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>
                          {r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : r.mucDo === 'C' ? 'CHT' : 'CHƯA CÓ'}
                        </span>
                      </td>
                      <td className="px-4 py-5 text-center font-black text-slate-700 text-lg">{r.diem || "-"}</td>
                      <td className="px-4 py-5 text-center">
                        <span className="text-[10px] font-mono font-black bg-white px-2 py-1.5 rounded-lg border border-slate-200 shadow-sm text-slate-500">{r.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-5">
                        <textarea value={r.noiDung} onChange={(e) => setRecords(records.map(rec => rec.stt === r.stt ? { ...rec, noiDung: e.target.value } : rec))} className="w-full bg-transparent border-none text-sm font-medium resize-none min-h-[60px] outline-none leading-relaxed focus:bg-white focus:p-2 focus:rounded-lg focus:shadow-inner transition-all" placeholder="AI sẽ viết dựa trên Mức đạt hoặc Điểm số..." />
                      </td>
                      <td className="px-4 py-5 text-center">
                        <button onClick={() => setRecords(records.filter(rec => rec.stt !== r.stt))} className="text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={7} className="py-40 text-center">
                        <div className="flex flex-col items-center opacity-20">
                          <Mountain size={64} className="mb-4 text-slate-300" />
                          <p className="font-black text-sm uppercase tracking-widest text-slate-400">Vui lòng chọn môn học và Nhập Excel tương ứng</p>
                        </div>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="table-bordered w-full text-left border-none">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-widest border-b border-slate-200">
                  <tr>
                    <th className="px-8 py-6 w-56 text-center">Mã nhận xét</th>
                    <th className="px-8 py-6 w-40 text-center">Mức đạt</th>
                    <th className="px-8 py-6 w-24 text-center">Điểm</th>
                    <th className="px-8 py-6">Mẫu nhận xét giản dị ({selectedGrade})</th>
                    <th className="px-4 py-6 w-16 text-center text-slate-300">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {commentBank.map((item, idx) => {
                    const abbr = getSubjectAbbr(selectedSubject);
                    const sameGroup = commentBank.slice(0, idx + 1).filter(b => b.diem === item.diem);
                    const displayCode = `${abbr}${item.diem || ""}${item.mucDo}${sameGroup.length}`;
                    return (
                      <tr key={item.id} className="hover:bg-indigo-50/20 transition-all">
                        <td className="px-8 py-8 text-center">
                          <span className="text-xs font-black font-mono px-4 py-2 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-xl shadow-sm">{displayCode}</span>
                        </td>
                        <td className="px-8 py-8 text-center">
                          <span className={`px-4 py-2 rounded-xl text-[10px] font-black border uppercase inline-block min-w-[140px] shadow-sm ${item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : item.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>
                            {item.mucDo === 'T' ? 'Tốt' : item.mucDo === 'H' ? 'HT' : 'CHT'}
                          </span>
                        </td>
                        <td className="px-8 py-8 text-center font-black text-slate-700 text-xl">{item.diem || "-"}</td>
                        <td className="px-8 py-8">
                          <textarea value={item.noiDung} onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))} className="w-full bg-white border border-slate-200 rounded-2xl p-6 text-sm font-medium leading-relaxed min-h-[100px] outline-none shadow-sm focus:ring-4 focus:ring-indigo-50 transition-all resize-none border-indigo-50" />
                        </td>
                        <td className="px-4 py-8 text-center">
                          <button onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))} className="text-slate-200 hover:text-rose-500 transition-all"><Trash2 size={18} /></button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
          <div className="p-8 bg-slate-50 flex flex-col sm:flex-row justify-between items-center gap-4 border-t border-slate-100">
            <div className="flex gap-3">
              <button onClick={() => setRecords([...records, { stt: records.length + 1, hoTen: 'Học sinh mới', ngaySinh: '', diem: 0, mucDo: 'H', maNhanXet: '', noiDung: '', isProcessing: false }])} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-xs font-black uppercase flex items-center gap-2 hover:shadow-lg transition-all"><Plus size={18} /> Thêm thủ công</button>
            </div>
            {records.length > 0 && (
              <button onClick={() => { if (confirm("Xóa toàn bộ dữ liệu hiện tại?")) setRecords([]); }} className="px-6 py-3 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-2xl text-xs font-black uppercase flex items-center gap-2 transition-all">
                <Trash2 size={18} /> Xóa danh sách
              </button>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-16 text-center bg-white/50 backdrop-blur-sm">
        <div className="flex items-center justify-center gap-2 text-slate-300 mb-2">
          <Mountain size={16} />
          <span className="text-[10px] font-black uppercase tracking-[0.3em]">Đồng hành cùng trẻ em vùng khó</span>
        </div>
        <div className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">
          PTDTBT TH Nấm Dẩn | Thầy Nguyễn Đức Hùng | Phiên bản Thông Minh 6.0
        </div>
      </footer>
    </div>
  );
};

export default App;

