import { GoogleGenAI, Type } from "@google/genai";
import { StudentRecord } from "../types";

const SYSTEM_INSTRUCTION = `
Bạn là trợ lý viết nhận xét học bạ tiểu học (Thông tư 27). 
Đối tượng: Học sinh vùng dân tộc thiểu số.
Yêu cầu: Viết nhận xét ngắn gọn (khoảng 150 ký tự), dễ hiểu, mộc mạc.

DANH SÁCH TỪ CẤM (TUYỆT ĐỐI KHÔNG DÙNG):
- Không dùng: "con", "em", "bé".
- Không dùng: "thầy giáo", "cô giáo", "thầy", "cô".
- Không dùng: "bản làng", "bản".
- Không dùng: "nám".
- Không dùng tên riêng của học sinh.
- Không dùng thuật ngữ chuyên môn khó hiểu hoặc từ ngữ địa phương.

QUY TẮC NHẬN XÉT:
1. NẾU CÓ ĐIỂM SỐ (Điểm KTĐK):
   - 9-10: Hoàn thành rất tốt các nội dung học tập. Kiến thức vững vàng, tích cực phát biểu.
   - 7-8: Nắm chắc kiến thức cơ bản. Chăm chỉ học tập, hoàn thành bài đầy đủ.
   - 5-6: Có nỗ lực trong học tập. Cần tập trung rèn luyện thêm kỹ năng tính toán và đọc viết.
   - Dưới 5: Cần đi học đều hơn để theo kịp kiến thức. Tập trung rèn các phép tính và nét chữ căn bản.

2. NẾU KHÔNG CÓ ĐIỂM (Chỉ có Mức đạt được):
   - Mức T (Hoàn thành tốt): Tích cực trong giờ học, hoàn thành tốt các nhiệm vụ được giao. Biết giúp đỡ bạn bè.
   - Mức H (Hoàn thành): Đi học chuyên cần, nắm được kiến thức cơ bản của môn học. Biết vâng lời.
   - Mức C (Chưa hoàn thành): Cần cố gắng nhiều hơn. Gia đình nên nhắc nhở đi học đều để không bị hổng kiến thức.

PHONG CÁCH: Trực diện, khách quan, sử dụng tiếng Việt phổ thông đơn giản. 
Ví dụ tốt: "Biết đọc, viết và làm toán nhanh. Chăm chỉ học tập, tích cực phát biểu xây dựng bài. Cần giữ vững tinh thần này."
`;

export interface BankComment {
  id: string;
  mucDo: 'T' | 'H' | 'C';
  diem: number;
  noiDung: string;
}

export const generateCommentBank = async (
  subject: string,
  gradeLevel: string,
  semester: string,
  signal?: AbortSignal
): Promise<BankComment[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Tạo ngân hàng mẫu nhận xét môn ${subject}, ${gradeLevel}. 
  Yêu cầu: Khoảng 150 ký tự/mẫu. Trả về JSON.
  Lưu ý quan trọng: Tuyệt đối không dùng các từ: con, em, thầy, cô, bản, làng. Sử dụng tiếng Việt phổ thông đơn giản.

  Số lượng:
  - Điểm 10, 9: 8 mẫu.
  - Điểm 8, 7: 10 mẫu.
  - Điểm 6, 5: 10 mẫu.
  - Mức T, H (khi không có điểm): 5 mẫu mỗi loại.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              mucDo: { type: Type.STRING, enum: ["T", "H", "C"] },
              diem: { type: Type.NUMBER },
              noiDung: { type: Type.STRING },
            },
            required: ["mucDo", "diem", "noiDung"],
          },
        },
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, index: number) => ({
      id: `${index + 1}`,
      ...r
    }));
  } catch (error: any) {
    console.error("Error generating bank:", error);
    return [];
  }
};

export const generateComments = async (
  records: StudentRecord[], 
  subject: string, 
  gradeLevel: string,
  semester: string
): Promise<Partial<StudentRecord>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Viết nhận xét (~150 ký tự) cho danh sách học sinh. 
  Môn: ${subject}. ${gradeLevel}. 
  Dữ liệu: ${JSON.stringify(records.map(r => ({ stt: r.stt, mucDo: r.mucDo, diem: r.diem })))}.
  Ghi chú: Nếu điểm bằng 0, chỉ dựa vào Mức đạt (T/H/C). Tuyệt đối không dùng từ: con, em, thầy, cô, bản, làng.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              stt: { type: Type.INTEGER },
              noiDung: { type: Type.STRING },
            },
            required: ["stt", "noiDung"],
          },
        },
      },
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square,
  FileUp,
  FileDown,
  CalendarDays,
  Mountain
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';
const HOC_KY = ["Học kỳ 1", "Học kỳ 2"];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [selectedSemester, setSelectedSemester] = useState(HOC_KY[0]);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      let level = record.mucDo;

      // Tự tính mức đạt nếu có điểm mà mức đạt trống
      if (!level && studentScore > 0) {
        if (studentScore >= 8) level = 'T';
        else if (studentScore >= 5) level = 'H';
        else level = 'C';
      }
      level = level || 'H';

      const counterKey = `${studentScore}_${level}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;
      const scoreStr = studentScore > 0 ? studentScore.toString() : "";
      const generatedCode = `${abbr}${scoreStr}${level}${counters[counterKey]}`;
      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (studentScore > 0) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, selectedSemester, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: `Đã tạo xong mẫu nhận xét môn ${selectedSubject}.` });
      }
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const subjectLower = selectedSubject.toLowerCase();
        const subjectAbbr = getSubjectAbbr(selectedSubject).toLowerCase();

        // 1. Tự động tìm sheet tương ứng môn học
        const targetSheetName = wb.SheetNames.find(name => {
          const n = name.toLowerCase();
          return n.includes(subjectLower) || n === subjectAbbr || n.includes(subjectAbbr);
        }) || wb.SheetNames[0];

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        // 2. Định nghĩa các từ khóa tìm cột
        const nameKeywords = ['họ tên', 'họ và tên', 'tên học sinh'];
        const levelKeywords = ['mức đạt được', 'mức đạt', 'xếp loại'];
        const scoreKeywords = ['điểm ktđk', 'ktđk', 'điểm kiểm tra'];

        let nameIdx = -1, levelIdx = -1, scoreIdx = -1;
        let startRow = 0;

        // 3. Tìm hàng tiêu đề và chỉ số cột
        for (let i = 0; i < Math.min(data.length, 15); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());
          if (nameIdx === -1) nameIdx = row.findIndex(c => nameKeywords.some(k => c.includes(k)));
          if (levelIdx === -1) levelIdx = row.findIndex(c => levelKeywords.some(k => c.includes(k)));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => scoreKeywords.some(k => c.includes(k)));

          if (nameIdx !== -1) {
            startRow = i + 1;
            break;
          }
        }

        if (nameIdx === -1) {
          setNotification({ type: 'error', message: `Không tìm thấy cột "Họ Tên" trong sheet "${targetSheetName}".` });
          return;
        }

        // 4. Ánh xạ dữ liệu vào bảng
        const newRecords = data.slice(startRow)
          .filter(r => String(r[nameIdx] || "").trim().length > 1)
          .map((r, idx) => {
            // Chuẩn hóa Mức đạt được (T, H, C)
            let rawLevel = String(r[levelIdx] || "").trim().toUpperCase();
            let level = "";
            if (rawLevel.includes("TỐT") || rawLevel === "T" || rawLevel.includes("HTT")) level = "T";
            else if (rawLevel.includes("CHƯA") || rawLevel === "C" || rawLevel.includes("CHT")) level = "C";
            else if (rawLevel.includes("HOÀN THÀNH") || rawLevel === "H" || rawLevel === "HT") level = "H";

            // Lấy điểm số
            let rawScore = r[scoreIdx];
            let diem = 0;
            if (rawScore !== undefined && rawScore !== "") {
              diem = parseFloat(String(rawScore).replace(',', '.')) || 0;
            }

            return {
              stt: idx + 1,
              hoTen: String(r[nameIdx] || "").trim(),
              ngaySinh: "",
              diem: diem,
              mucDo: level,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false
            } as StudentRecord;
          });

        setRecords(newRecords);
        setNotification({ 
          type: 'success', 
          message: `Đã nhập dữ liệu môn ${selectedSubject} từ sheet "${targetSheetName}".` 
        });

      } catch (err) { 
        setNotification({ type: 'error', message: 'Lỗi định dạng file Excel.' }); 
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [r.stt, r.hoTen, r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : 'CHT', r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ tên", "Mức đạt được", "Điểm KTĐK", "Mã NX", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedGrade}_${selectedSubject}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 text-slate-900">
      <header className="bg-white border-b sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg relative">
              <BookOpen size={24} />
              <Mountain size={14} className="absolute -bottom-1 -right-1 text-white opacity-40" />
            </div>
            <div>
              <h1 className="text-xl font-black uppercase tracking-tight">Hỗ Trợ Giáo Viên ({selectedGrade})</h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-tight">Môn: {selectedSubject} | Dùng tiếng Việt phổ thông</p>
            </div>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex bg-slate-100 p-1 rounded-xl items-center border border-slate-200">
              <select value={selectedGrade} onChange={(e) => setSelectedGrade(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none border-r border-slate-200">
                {KHOI_LOP.map(k => <option key={k} value={k}>{k}</option>)}
              </select>
              <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none border-r border-slate-200">
                {MON_HOC_TIEU_HOC.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <select value={selectedSemester} onChange={(e) => setSelectedSemester(e.target.value)} className="px-3 py-1.5 bg-transparent text-sm font-bold outline-none text-indigo-600">
                {HOC_KY.map(h => <option key={h} value={h}>{h}</option>)}
              </select>
            </div>

            <div className="h-8 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            {isGeneratingBank ? (
              <button onClick={handleStopGenerating} className="inline-flex items-center gap-2 px-5 py-2.5 bg-rose-600 text-white rounded-xl shadow-md text-sm font-bold animate-pulse">
                <Square size={16} fill="currentColor" /> Dừng
              </button>
            ) : (
              <button onClick={handleGenerateBank} className="inline-flex items-center gap-2 px-5 py-2.5 bg-amber-500 text-white rounded-xl shadow-md text-sm font-bold transition-all group">
                <Database size={16} className="group-hover:rotate-12 transition-transform" /> Tạo nhận xét AI
              </button>
            )}

            <input type="file" accept=".xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl text-sm font-bold hover:bg-slate-50">
              <FileUp size={16} /> Nhập Excel
            </button>

            {viewMode === 'table' && (
              <button onClick={exportTableToExcel} className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl shadow-md text-sm font-bold active:scale-95">
                <Download size={16} /> Xuất file
              </button>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
          <div className="bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 flex">
            <button onClick={() => setViewMode('table')} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${viewMode === 'table' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <TableIcon size={18} className="inline mr-2" /> Học sinh
            </button>
            <button onClick={() => setViewMode('content')} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${viewMode === 'content' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FileJson size={18} className="inline mr-2" /> Ngân hàng mẫu
            </button>
          </div>
          <div className="relative w-full sm:w-96">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Tìm tên, mã nhận xét..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3 bg-white border border-slate-300 rounded-2xl text-sm outline-none shadow-sm focus:ring-4 focus:ring-indigo-100 transition-all font-medium" />
          </div>
        </div>

        {notification && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center justify-between border shadow-sm ${notification.type === 'success' ? 'bg-emerald-50 text-emerald-900 border-emerald-200' : 'bg-rose-50 text-rose-900 border-rose-200'}`}>
            <div className="flex items-center gap-3">
              <CheckCircle2 size={20} className={notification.type === 'success' ? 'text-emerald-600' : 'text-rose-600'} />
              <span className="font-bold text-sm tracking-tight">{notification.message}</span>
            </div>
            <button onClick={() => setNotification(null)} className="opacity-50 hover:opacity-100 transition-opacity text-xs uppercase font-black">Đóng</button>
          </div>
        )}

        <div className="bg-white rounded-[2rem] shadow-2xl border border-slate-200 overflow-hidden mb-12">
          {viewMode === 'table' ? (
            <div className="overflow-x-auto">
              <table className="table-bordered min-w-[1000px] border-none text-center">
                <thead className="bg-slate-50 text-slate-600 font-bold border-b-2 border-slate-200">
                  <tr>
                    <th className="px-4 py-4 w-12 text-slate-400">#</th>
                    <th className="px-6 py-4 w-64 text-left">Học sinh</th>
                    <th className="px-4 py-4 w-28">Mức đạt được</th>
                    <th className="px-4 py-4 w-24">Điểm KTĐK</th>
                    <th className="px-4 py-4 w-32">Mã NX</th>
                    <th className="px-6 py-4 text-left">Nội dung nhận xét phổ thông (~150 ký tự)</th>
                    <th className="px-4 py-4 w-16 text-slate-400">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredRecords.map((r) => (
                    <tr key={r.stt} className="group hover:bg-indigo-50/40 transition-all">
                      <td className="px-4 py-5 text-xs text-slate-300 font-bold">{r.stt}</td>
                      <td className="px-6 py-5 text-sm font-bold text-slate-900 text-left">{r.hoTen}</td>
                      <td className="px-4 py-5">
                        <span className={`px-3 py-1 rounded-lg text-[9px] font-black border uppercase shadow-sm ${r.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : r.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : r.mucDo === 'C' ? 'bg-rose-50 text-rose-700 border-rose-200' : 'bg-slate-50'}`}>
                          {r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : r.mucDo === 'C' ? 'CHT' : 'TRỐNG'}
                        </span>
                      </td>
                      <td className="px-4 py-5 font-black text-slate-700 text-lg">{r.diem || "-"}</td>
                      <td className="px-4 py-5">
                        <span className="text-[10px] font-mono font-black bg-white px-2 py-1.5 rounded-lg border border-slate-200 text-slate-500">{r.maNhanXet}</span>
                      </td>
                      <td className="px-6 py-5">
                        <textarea value={r.noiDung} onChange={(e) => setRecords(records.map(rec => rec.stt === r.stt ? { ...rec, noiDung: e.target.value } : rec))} className="w-full bg-transparent border-none text-sm font-medium resize-none min-h-[60px] outline-none leading-relaxed focus:bg-white focus:p-2 focus:rounded-lg transition-all" placeholder="Dữ liệu sẽ hiển thị ở đây sau khi nhập Excel hoặc tạo AI..." />
                      </td>
                      <td className="px-4 py-5">
                        <button onClick={() => setRecords(records.filter(rec => rec.stt !== r.stt))} className="text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
                  {filteredRecords.length === 0 && (
                    <tr>
                      <td colSpan={7} className="py-40 text-center opacity-30">
                        <Mountain size={64} className="mx-auto mb-4" />
                        <p className="font-bold uppercase tracking-widest text-sm">Chưa có dữ liệu học sinh</p>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="table-bordered w-full text-left border-none">
                <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-widest border-b border-slate-200">
                  <tr>
                    <th className="px-8 py-6 w-56 text-center">Mã nhận xét</th>
                    <th className="px-8 py-6 w-40 text-center">Mức đạt</th>
                    <th className="px-8 py-6 w-24 text-center">Điểm</th>
                    <th className="px-8 py-6">Mẫu nhận xét phổ thông ({selectedGrade})</th>
                    <th className="px-4 py-6 w-16 text-center text-slate-300">Xóa</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {commentBank.map((item, idx) => (
                    <tr key={item.id} className="hover:bg-indigo-50/20 transition-all">
                      <td className="px-8 py-8 text-center">
                        <span className="text-xs font-black font-mono px-4 py-2 bg-indigo-50 text-indigo-700 border border-indigo-100 rounded-xl shadow-sm">{getSubjectAbbr(selectedSubject)}{item.diem || ""}{item.mucDo}{idx + 1}</span>
                      </td>
                      <td className="px-8 py-8 text-center">
                        <span className={`px-4 py-2 rounded-xl text-[10px] font-black border uppercase inline-block min-w-[140px] shadow-sm ${item.mucDo === 'T' ? 'bg-amber-50 text-amber-700 border-amber-200' : item.mucDo === 'H' ? 'bg-sky-50 text-sky-700 border-sky-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>
                          {item.mucDo === 'T' ? 'Tốt' : item.mucDo === 'H' ? 'HT' : 'CHT'}
                        </span>
                      </td>
                      <td className="px-8 py-8 text-center font-black text-slate-700 text-xl">{item.diem || "-"}</td>
                      <td className="px-8 py-8">
                        <textarea value={item.noiDung} onChange={(e) => setCommentBank(commentBank.map(b => b.id === item.id ? { ...b, noiDung: e.target.value } : b))} className="w-full bg-white border border-slate-200 rounded-2xl p-6 text-sm font-medium leading-relaxed min-h-[80px] outline-none shadow-sm focus:ring-4 focus:ring-indigo-50 transition-all resize-none" />
                      </td>
                      <td className="px-4 py-8 text-center">
                        <button onClick={() => setCommentBank(commentBank.filter(b => b.id !== item.id))} className="text-slate-200 hover:text-rose-500 transition-all"><Trash2 size={18} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 py-16 text-center bg-white/50">
        <div className="flex items-center justify-center gap-2 text-slate-300 mb-2">
          <Mountain size={16} />
          <span className="text-[10px] font-black uppercase tracking-[0.3em]">Hỗ trợ giáo viên tiểu học</span>
        </div>
        <div className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">
          Phòng Giáo dục và Đào tạo | PTDTBT TH Nấm Dẩn | Phiên bản Phổ Thông 8.0
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { StudentRecord, MON_HOC_TIEU_HOC, KHOI_LOP, getSubjectAbbr } from './types';
import { generateComments, generateCommentBank, BankComment } from './services/geminiService';
import { 
  Plus, 
  Sparkles, 
  Download, 
  Upload,
  BookOpen,
  CheckCircle2, 
  AlertCircle,
  Loader2,
  RefreshCw,
  Table as TableIcon,
  AlignLeft,
  Search,
  FileJson,
  Database,
  Trash2,
  FileSpreadsheet,
  Square,
  FileUp,
  FileDown,
  CalendarDays,
  Mountain
} from 'lucide-react';
import * as XLSX from 'xlsx';

type ViewMode = 'table' | 'content';
const HOC_KY = ["Học kỳ 1", "Học kỳ 2"];

const App: React.FC = () => {
  const [records, setRecords] = useState<StudentRecord[]>([]);
  const [commentBank, setCommentBank] = useState<BankComment[]>([]);
  const [selectedSubject, setSelectedSubject] = useState(MON_HOC_TIEU_HOC[0]);
  const [selectedGrade, setSelectedGrade] = useState(KHOI_LOP[0]);
  const [selectedSemester, setSelectedSemester] = useState(HOC_KY[0]);
  const [isGeneratingBank, setIsGeneratingBank] = useState(false);
  const [viewMode, setViewMode] = useState('table' as ViewMode);
  const [searchTerm, setSearchTerm] = useState('');
  const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info', message: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const calculatedRecords = useMemo(() => {
    const abbr = getSubjectAbbr(selectedSubject);
    const counters: Record<string, number> = {};

    return records.map(record => {
      const studentScore = record.diem > 0 ? Math.round(record.diem) : 0;
      let level = record.mucDo;

      if (!level && studentScore > 0) {
        if (studentScore >= 8) level = 'T';
        else if (studentScore >= 5) level = 'H';
        else level = 'C';
      }
      level = level || 'H';

      const counterKey = `${studentScore}_${level}`;
      counters[counterKey] = (counters[counterKey] || 0) + 1;
      const scoreStr = studentScore > 0 ? studentScore.toString() : "";
      const generatedCode = `${abbr}${scoreStr}${level}${counters[counterKey]}`;
      const code = record.maNhanXet || generatedCode;

      let targetGroup: BankComment[] = [];
      if (studentScore > 0) {
        targetGroup = commentBank.filter(b => b.diem === studentScore);
        if (targetGroup.length === 0) targetGroup = commentBank.filter(b => b.mucDo === level);
      } else {
        targetGroup = commentBank.filter(b => b.mucDo === level);
      }

      let autoContent = record.noiDung;
      if (targetGroup.length > 0 && !record.noiDung) {
        const bankIndex = (counters[counterKey] - 1) % targetGroup.length;
        autoContent = targetGroup[bankIndex].noiDung;
      }

      return { ...record, mucDo: level, maNhanXet: code, noiDung: autoContent };
    });
  }, [records, selectedSubject, commentBank]);

  const filteredRecords = useMemo(() => {
    if (!searchTerm) return calculatedRecords;
    return calculatedRecords.filter(r => 
      r.hoTen.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.maNhanXet.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [calculatedRecords, searchTerm]);

  const handleGenerateBank = async () => {
    setIsGeneratingBank(true);
    setNotification(null);
    abortControllerRef.current = new AbortController();

    try {
      const bank = await generateCommentBank(selectedSubject, selectedGrade, selectedSemester, abortControllerRef.current.signal);
      if (bank.length > 0) {
        setCommentBank(bank);
        setNotification({ type: 'success', message: `Đã tạo xong mẫu nhận xét môn ${selectedSubject}.` });
      }
    } catch (error: any) {
      setNotification({ type: 'error', message: 'Lỗi AI khi tạo nội dung.' });
    } finally {
      setIsGeneratingBank(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGenerating = () => abortControllerRef.current?.abort();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary', cellDates: true });

        const subjectLower = selectedSubject.toLowerCase();
        const subjectAbbr = getSubjectAbbr(selectedSubject).toLowerCase();

        const targetSheetName = wb.SheetNames.find(name => {
          const n = name.toLowerCase();
          return n.includes(subjectLower) || n === subjectAbbr || n.includes(subjectAbbr);
        }) || wb.SheetNames[0];

        const ws = wb.Sheets[targetSheetName];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as any[][];

        const nameKeywords = ['họ tên', 'họ và tên', 'tên học sinh'];
        const levelKeywords = ['mức đạt được', 'mức đạt', 'xếp loại'];
        const scoreKeywords = ['điểm ktđk', 'ktđk', 'điểm kiểm tra'];

        let nameIdx = -1, levelIdx = -1, scoreIdx = -1;
        let startRow = 0;

        for (let i = 0; i < Math.min(data.length, 15); i++) {
          const row = (data[i] || []).map(c => String(c).toLowerCase().trim());
          if (nameIdx === -1) nameIdx = row.findIndex(c => nameKeywords.some(k => c.includes(k)));
          if (levelIdx === -1) levelIdx = row.findIndex(c => levelKeywords.some(k => c.includes(k)));
          if (scoreIdx === -1) scoreIdx = row.findIndex(c => scoreKeywords.some(k => c.includes(k)));

          if (nameIdx !== -1) {
            startRow = i + 1;
            break;
          }
        }

        if (nameIdx === -1) {
          setNotification({ type: 'error', message: `Không tìm thấy cột "Họ Tên" trong sheet "${targetSheetName}".` });
          return;
        }

        const newRecords = data.slice(startRow)
          .filter(r => String(r[nameIdx] || "").trim().length > 1)
          .map((r, idx) => {
            let rawLevel = String(r[levelIdx] || "").trim().toUpperCase();
            let level = "";
            if (rawLevel.includes("TỐT") || rawLevel === "T" || rawLevel.includes("HTT")) level = "T";
            else if (rawLevel.includes("CHƯA") || rawLevel === "C" || rawLevel.includes("CHT")) level = "C";
            else if (rawLevel.includes("HOÀN THÀNH") || rawLevel === "H" || rawLevel === "HT") level = "H";

            let rawScore = r[scoreIdx];
            let diem = 0;
            if (rawScore !== undefined && rawScore !== "") {
              diem = parseFloat(String(rawScore).replace(',', '.')) || 0;
            }

            return {
              stt: idx + 1,
              hoTen: String(r[nameIdx] || "").trim(),
              ngaySinh: "",
              diem: diem,
              mucDo: level,
              maNhanXet: "",
              noiDung: "",
              isProcessing: false
            } as StudentRecord;
          });

        setRecords(newRecords);
        setNotification({ 
          type: 'success', 
          message: `Đã nhập dữ liệu môn ${selectedSubject} từ sheet "${targetSheetName}".` 
        });

      } catch (err) { 
        setNotification({ type: 'error', message: 'Lỗi định dạng file Excel.' }); 
      }
    };
    reader.readAsBinaryString(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const exportTableToExcel = () => {
    const data = filteredRecords.map(r => [r.stt, r.hoTen, r.mucDo === 'T' ? 'HTT' : r.mucDo === 'H' ? 'HT' : 'CHT', r.diem > 0 ? r.diem : "", r.maNhanXet, r.noiDung]);
    const ws = XLSX.utils.aoa_to_sheet([["STT", "Họ tên", "Mức đạt được", "Điểm KTĐK", "Mã NX", "Nội dung nhận xét"], ...data]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "NhanXet");
    XLSX.writeFile(wb, `NhanXet_${selectedGrade}_${selectedSubject}.xlsx`);
  };

  const exportBankToExcel = () => {
    if (commentBank.length === 0) {
      setNotification({ type: 'error', message: 'Chưa có ngân hàng mẫu để xuất file.' });
      return;
    }
    const abbr = getSubjectAbbr(selectedSubject);
    const data = commentBank.map((item, index) => {
      // Logic tạo mã giống như hiển thị trên bảng
      const sameGroup = commentBank.slice(0, index + 1).filter(b => b.diem === item.diem && b.mucDo === item.mucDo);
